-- Poems batch 5
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('08787c29-8c27-4e9a-b66a-b499586d2b82','寄賀蘭銛','杜甫','唐','唐诗','tang','','[]','朝野歡娛後，乾坤震蕩中。',48,'全唐诗/poet.tang.11000.json','["朝野歡娛後，乾坤震蕩中。", "相隨萬里日，總作白頭翁。", "歲晚仍分袂，江邊更轉蓬。", "勿云俱異域，飲啄幾回同。"]'),
('19e1ce0c-fd4d-47e7-83e2-07c1891d5ee4','寄楊五桂州譚','杜甫','唐','唐诗','tang','','[]','五嶺皆炎熱，宜人獨桂林。',48,'全唐诗/poet.tang.11000.json','["五嶺皆炎熱，宜人獨桂林。", "梅花萬里外，雪片一冬深。", "聞此寬相憶，爲邦復好音。", "江邊送孫楚，遠附白頭吟。"]'),
('ddd6af5c-372e-4a0e-98bd-4a2c51c42b00','逢唐興劉主簿弟','杜甫','唐','唐诗','tang','','[]','分手開元末，連年絕尺書。',48,'全唐诗/poet.tang.11000.json','["分手開元末，連年絕尺書。", "江山且相見，戎馬未安居。", "劒外官人冷，關中驛騎疎。", "輕舟下吳會，主簿意何如。"]'),
('e17bc310-4fcc-4a80-a860-5f112a907f54','和裴迪登新津寺寄王侍郎','杜甫','唐','唐诗','tang','','[]','何限倚山木，吟詩秋葉黃。',48,'全唐诗/poet.tang.11000.json','["何限倚山木，吟詩秋葉黃。", "蟬聲集古寺，鳥影度寒塘。", "風物悲遊子，登臨憶侍郎。", "老夫貪佛日，隨意宿僧房。"]'),
('4a32f032-6f9a-4095-bfcc-67d095ce90c7','敬簡王明府','杜甫','唐','唐诗','tang','','[]','葉縣郎官宰，周南太史公。',48,'全唐诗/poet.tang.11000.json','["葉縣郎官宰，周南太史公。", "神仙才有數，流落意無窮。", "驥病思偏秣，鷹愁怕苦籠。", "看君用高義，恥與萬人同。"]'),
('7679ec5f-893f-4d30-8acd-b45c908e49d1','重簡王明府','杜甫','唐','唐诗','tang','','[]','甲子西南異，冬來只薄寒。',48,'全唐诗/poet.tang.11000.json','["甲子西南異，冬來只薄寒。", "江雲何夜盡，蜀雨幾時乾。", "行李須相問，窮愁豈有寬。", "君聽鴻鴈響，恐致稻粱難。"]'),
('ba10246a-c026-41e7-87a9-2e6ce2a27559','建都十二韻','杜甫','唐','唐诗','tang','','[]','蒼生未蘇息，胡馬半乾坤。',144,'全唐诗/poet.tang.11000.json','["蒼生未蘇息，胡馬半乾坤。", "議在雲臺上，誰扶黃屋尊。", "建都分魏闕，下韶闢荆門。", "恐失東人望，其如西極存。", "時危當雪恥，計大豈輕論。", "雖倚三階正，終愁萬國飜。", "牽裾恨不死，漏網荷殊恩。", "永負漢庭哭，遙憐湘水魂。", "窮冬客江劒，隨事有田園。", "風斷青蒲節，霜埋翠竹根。", "衣冠空穰穰，關輔久昏昏。", "願枉長安日，光輝照北原。"]'),
('130ff9df-d0d9-4812-8ae2-cba09ed87050','歲暮','杜甫','唐','唐诗','tang','','["\u7231\u56fd", "\u6218\u4e89"]','歲暮遠爲客，邊隅還用兵。',48,'全唐诗/poet.tang.11000.json','["歲暮遠爲客，邊隅還用兵。", "煙塵犯雪嶺，鼓角動江城。", "天地日流血，朝廷誰請纓。", "濟時敢愛死，寂寞壯心驚。"]'),
('21500334-b2e4-4199-8c2c-cbff940c9b6d','和裴迪登蜀州東亭送客逢早梅相憶見寄','杜甫','唐','唐诗','tang','','["\u6292\u60c5", "\u6885\u82b1"]','東閣官梅動詩興，還如何遜在揚州。',64,'全唐诗/poet.tang.11000.json','["東閣官梅動詩興，還如何遜在揚州。", "此時對雪遙相憶，送客逢春可自由。", "幸不折來傷歲暮，若爲看去亂鄉愁。", "江邊一樹垂垂發，朝夕催人自白頭。"]'),
('6306447f-ad78-4478-aeb0-9bde2807146f','寄贈王十將軍承俊','杜甫','唐','唐诗','tang','','[]','將軍膽氣雄，臂懸兩角弓。',48,'全唐诗/poet.tang.11000.json','["將軍膽氣雄，臂懸兩角弓。", "纏結青驄馬，出入錦城中。", "時危未授鉞，勢屈難爲功。", "賓客滿堂上，何人高義同。"]'),
('248f3d52-a0cf-4224-9dd0-5b9f12786c51','暮登四安寺鐘樓寄裴十','杜甫','唐','唐诗','tang','','[]','暮倚高樓對雪峰，僧來不語自鳴鐘。',64,'全唐诗/poet.tang.11000.json','["暮倚高樓對雪峰，僧來不語自鳴鐘。", "孤城返照紅將歛，近市浮煙翠且重。", "多病獨愁常閴寂，故人相見未從容。", "知君苦思緣詩瘦，大向交遊萬事慵。"]'),
('0a77da0a-1228-424b-8bee-57e78dd1a9e3','散愁二首 一','杜甫','唐','唐诗','tang','','[]','久客宜旋斾，興王未息戈。',48,'全唐诗/poet.tang.11000.json','["久客宜旋斾，興王未息戈。", "蜀星陰見少，江雨夜聞多。", "百萬傳深入，寰區望匪它。", "司徒下燕趙，收取舊山河。"]'),
('1e5828eb-ebeb-4c30-8894-70ebb94adc3e','散愁二首 二','杜甫','唐','唐诗','tang','','[]','聞道幷州鎮，尚書訓士齊。',48,'全唐诗/poet.tang.11000.json','["聞道幷州鎮，尚書訓士齊。", "幾時通薊北，當日報關西。", "戀闕丹心破，霑衣皓首啼。", "老魂招不得，歸路恐長迷。"]'),
('327ec1e1-6d64-4867-9130-51bacc00112c','奉酬李都督表丈早春作','杜甫','唐','唐诗','tang','','["\u60b2\u4f24", "\u6625\u5929", "\u601d\u4e61"]','力疾坐清曉，來時悲早春。',48,'全唐诗/poet.tang.11000.json','["力疾坐清曉，來時悲早春。", "轉添愁伴客，更覺老隨人。", "紅入桃花嫩，青歸柳葉新。", "望鄉應未已，四海尚風塵。"]'),
('9da0cbe5-52d4-4efc-8be2-2f78f1a8f097','客至','杜甫','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u559c\u60a6", "\u5199\u666f", "\u53cb\u60c5", "\u5f85\u5ba2"]','舍南舍北皆春水，但見羣鷗日日來。',64,'全唐诗/poet.tang.11000.json','["舍南舍北皆春水，但見羣鷗日日來。", "花徑不曾緣客掃，蓬門今始爲君開。", "盤餐市遠無兼味，樽酒家貧只舊醅。", "肯與鄰翁相對飲，隔籬呼取盡餘桮。"]'),
('b4fdb8fe-7069-4925-a41b-a9522bb26653','遣意二首 一','杜甫','唐','唐诗','tang','','[]','囀枝黃鳥近，泛渚白鷗輕。',48,'全唐诗/poet.tang.11000.json','["囀枝黃鳥近，泛渚白鷗輕。", "一徑野花落，孤村春水生。", "衰年催釀黍，細雨更移橙。", "漸喜交遊絕，幽居不用名。"]'),
('982aa516-163c-40fd-94ab-3c7c743456c9','遣意二首 二','杜甫','唐','唐诗','tang','','[]','簷影微微落，津流脉脉斜。',48,'全唐诗/poet.tang.11000.json','["簷影微微落，津流脉脉斜。", "野船明細火，宿鴈聚圓沙。", "雲掩初弦月，香傳小樹花。", "鄰人有美酒，稚子夜能賒。"]'),
('d239ab24-c5d9-4163-9cb0-2dd7c0f95998','漫成二首 一','杜甫','唐','唐诗','tang','','[]','野日荒荒白，春流泯泯清。',48,'全唐诗/poet.tang.11000.json','["野日荒荒白，春流泯泯清。", "渚蒲隨地有，村徑逐門成。", "只作披衣慣，常從漉酒生。", "眼前無俗物，多病也身輕。"]'),
('c27559b0-f98d-4b5f-a239-f5ec7cb33f71','漫成二首 二','杜甫','唐','唐诗','tang','','[]','江臯已仲春，花下復清晨。',48,'全唐诗/poet.tang.11000.json','["江臯已仲春，花下復清晨。", "仰面貪看鳥，回頭錯應人。", "讀書難字過，對酒滿壺頻。", "近識峨眉老，知予嬾是真。"]'),
('c6ddd64d-606c-421e-8912-7f37568020b1','春夜喜雨','杜甫','唐','唐诗','tang','','["\u5199\u96e8", "\u6625\u5929", "\u548f\u7269", "\u559c\u60a6", "\u96e8", "\u548f\u7269\u8bd7"]','好雨知時節，當春乃發生。',48,'全唐诗/poet.tang.11000.json','["好雨知時節，當春乃發生。", "隨風潛入夜，潤物細無聲。", "野徑雲俱黑，江船火獨明。", "曉看紅濕處，花重錦官城。"]'),
('be93d219-ff58-4c9e-8068-9a8cbc8db5e5','春水','杜甫','唐','唐诗','tang','','[]','三月桃花浪，江流復舊痕。',48,'全唐诗/poet.tang.11000.json','["三月桃花浪，江流復舊痕。", "朝來沒沙尾，碧色動柴門。", "接縷垂芳餌，連筒灌小園。", "已添無數鳥，爭浴故相喧。"]'),
('f53d6111-259a-4fdf-950c-818b70c38a31','春水生二絕 一','杜甫','唐','唐诗','tang','','[]','二月六夜春水生。',32,'全唐诗/poet.tang.11000.json','["二月六夜春水生。", "門前小灘渾欲平，鸕鶿鸂鶒莫漫喜。", "吾與汝曹俱眼明。"]'),
('be030244-ee5c-409c-bc75-8a80eb18bb4e','春水生二絕 二','杜甫','唐','唐诗','tang','','[]','一夜水高二尺強，數日不可更禁當。',32,'全唐诗/poet.tang.11000.json','["一夜水高二尺強，數日不可更禁當。", "南市津頭有船賣，無錢即買繫籬旁。"]'),
('d59c85f4-1fba-4dd6-8300-76b1793afdb2','江亭','杜甫','唐','唐诗','tang','','["\u7231\u56fd", "\u66ae\u6625"]','坦腹江亭暖，長吟野望時。',48,'全唐诗/poet.tang.11000.json','["坦腹江亭暖，長吟野望時。", "水流心不競，雲在意俱遲。", "寂寂春將晚，欣欣物自私。", "故林歸未得，排悶強裁詩。"]'),
('6d090832-2f35-4f44-a68a-cc5b67e1798d','村夜','杜甫','唐','唐诗','tang','','[]','蕭蕭風色暮，江頭人不行。',48,'全唐诗/poet.tang.11000.json','["蕭蕭風色暮，江頭人不行。", "村舂雨外急，鄰火夜深明。", "胡羯何多難，漁樵寄此生。", "中原有兄弟，萬里正含情。"]'),
('9ea7e12e-dd82-4922-88bc-e97fd3e60cdb','早起','杜甫','唐','唐诗','tang','','[]','春來常早起，幽事頗相關。',48,'全唐诗/poet.tang.11000.json','["春來常早起，幽事頗相關。", "帖石防隤岸，開林出遠山。", "一丘藏曲折，緩步有躋攀。", "童僕來城市，瓶中得酒還。"]'),
('9eb8a798-42bf-42a1-bbd0-b4fe04d71aef','可惜','杜甫','唐','唐诗','tang','','[]','花飛有底急，老去願春遲。',48,'全唐诗/poet.tang.11000.json','["花飛有底急，老去願春遲。", "可惜歡娛地，都非少壯時。", "寬心應是酒，遣興莫過詩。", "此意陶潛解，吾生後汝期。"]'),
('09f26016-922c-4bb4-a70f-a846c5b03661','落日','杜甫','唐','唐诗','tang','','[]','落日在簾鉤，溪邊春事幽。',48,'全唐诗/poet.tang.11000.json','["落日在簾鉤，溪邊春事幽。", "芳菲緣岸圃，樵爨倚灘舟。", "啅雀爭枝墜，飛蟲滿院遊。", "濁醪誰造汝，一酌散千憂。"]'),
('a1e5f620-d20f-4366-8cde-0ce540fcd107','獨酌','杜甫','唐','唐诗','tang','','[]','步屨深林晚，開樽獨酌遲。',48,'全唐诗/poet.tang.11000.json','["步屨深林晚，開樽獨酌遲。", "仰蜂黏落絮，行蟻上枯梨。", "薄劣慚真隱，幽偏得自怡。", "本無軒冕意，不是傲當時。"]'),
('7392d578-301d-4562-98b0-2cb5086b62bf','徐步','杜甫','唐','唐诗','tang','','[]','整履步青蕪，荒庭日欲晡。',48,'全唐诗/poet.tang.11000.json','["整履步青蕪，荒庭日欲晡。", "芹泥隨燕觜，花蘂上蜂鬚。", "把酒從衣濕，吟詩信杖扶。", "敢論才見忌，實有醉如愚。"]'),
('61275a5a-1dce-4a0b-9491-a43c915c06d3','寒食','杜甫','唐','唐诗','tang','','[]','寒食江村路，風花高下飛。',48,'全唐诗/poet.tang.11000.json','["寒食江村路，風花高下飛。", "汀煙輕冉冉，竹日靜暉暉。", "田父要皆去，鄰家鬧不違。", "地偏相識盡，雞犬亦忘歸。"]'),
('731d79e3-1e7c-4ce8-a484-890b7cf39af5','高柟','杜甫','唐','唐诗','tang','','[]','柟樹色冥冥，江邊一蓋青。',48,'全唐诗/poet.tang.11000.json','["柟樹色冥冥，江邊一蓋青。", "近根開藥圃，接葉製茅亭。", "落景陰猶合，微風韻可聽。", "尋常絕醉困，臥此片時醒。"]'),
('8d0e997e-203d-4294-8173-9994f02bacdd','惡樹','杜甫','唐','唐诗','tang','','[]','獨遶虛齋徑，常持小斧柯。',48,'全唐诗/poet.tang.11000.json','["獨遶虛齋徑，常持小斧柯。", "幽陰成頗雜，惡木剪還多。", "枸杞因吾有，雞棲奈汝何。", "方知不材者，生長漫婆娑。"]'),
('c0e92988-2c74-4996-a1fc-8450d79a9ef0','石鏡','杜甫','唐','唐诗','tang','','[]','蜀王將此鏡，送死置空山。',48,'全唐诗/poet.tang.11000.json','["蜀王將此鏡，送死置空山。", "冥寞憐香骨，提攜近玉顏。", "衆妃無復歎，千騎亦虛還。", "獨有傷心石，埋輪月宇間。"]'),
('6c5af966-9b25-4030-80ad-c00e403151d5','琴臺','杜甫','唐','唐诗','tang','','["\u968b\u30fb\u5510\u30fb\u4e94\u4ee3", "\u7231\u60c5", "\u548f\u53f2\u6000\u53e4"]','茂陵多病後，尚愛卓文君。',48,'全唐诗/poet.tang.11000.json','["茂陵多病後，尚愛卓文君。", "酒肆人間世，琴臺日暮雲。", "野花留寶靨，蔓草見羅帬。", "歸鳳求皇意，寥寥不復聞。"]'),
('62c91219-9aa9-4872-a4cc-8751a8f85e3c','聞斛斯六官未歸','杜甫','唐','唐诗','tang','','[]','故人南郡去，去索作碑錢。',48,'全唐诗/poet.tang.11000.json','["故人南郡去，去索作碑錢。", "本賣文爲活，飜令室倒懸。", "荆扉深蔓草，土銼冷疎煙。", "老罷休無賴，歸來省醉眠。"]'),
('6578791b-8f0c-43a9-b7ec-96de41d55d29','遊修覺寺','杜甫','唐','唐诗','tang','','[]','野寺江天豁，山扉花竹幽。',48,'全唐诗/poet.tang.11000.json','["野寺江天豁，山扉花竹幽。", "詩應有神助，吾得及春遊。", "徑石相縈帶，川雲自去留。", "禪枝宿衆鳥，漂轉暮歸愁。"]'),
('2e21cd9e-d90b-4cb5-a624-4ea522457655','後遊','杜甫','唐','唐诗','tang','','["\u6292\u60c5", "\u5199\u666f"]','寺憶新遊處，橋憐再渡時。',48,'全唐诗/poet.tang.11000.json','["寺憶新遊處，橋憐再渡時。", "江山如有待，花柳更無私。", "野潤煙光薄，沙暄日色遲。", "客愁全爲減，捨此復何之。"]'),
('8d17fb7e-d2f3-4f01-bcee-be11864e9155','題新津北橋樓','杜甫','唐','唐诗','tang','','[]','望極春城上，開筵近鳥巢。',48,'全唐诗/poet.tang.11000.json','["望極春城上，開筵近鳥巢。", "白花簷外朵，青柳檻前梢。", "池水觀爲政，廚煙覺遠庖。", "西川供客眼，唯有此江郊。"]'),
('de032aba-5c58-4587-af44-fac5ac8cba2b','江漲','杜甫','唐','唐诗','tang','','[]','江發蠻夷漲，山添雨雪流。',48,'全唐诗/poet.tang.11000.json','["江發蠻夷漲，山添雨雪流。", "大聲吹地轉，高浪蹴天浮。", "魚鱉爲人得，蛟龍不自謀。", "輕帆好去便，吾道付滄洲。"]'),
('759ebea2-b15e-4e34-8596-d81ad6a5e982','晚晴','杜甫','唐','唐诗','tang','','["\u7530\u56ed"]','村晚驚風度，庭幽過雨霑。',48,'全唐诗/poet.tang.11000.json','["村晚驚風度，庭幽過雨霑。", "夕陽薰細草，江色映疎簾。", "書亂誰能帙，桮乾可自添。", "時聞有餘論，未怪老夫潛。"]'),
('d6d2681f-bb88-4a16-b4f3-758588182049','朝雨','杜甫','唐','唐诗','tang','','[]','涼氣晚蕭蕭，江雲亂眼飄。',48,'全唐诗/poet.tang.11000.json','["涼氣晚蕭蕭，江雲亂眼飄。", "風鴛藏近渚，雨燕集深條。", "黃綺終辭漢，巢由不見堯。", "草堂樽酒在，幸得過清朝。"]'),
('a0dc8942-b0f1-4952-af32-511e47fb4dc5','江上值水如海勢聊短述','杜甫','唐','唐诗','tang','','["\u63cf\u5199\u6c34", "\u6292\u6000", "\u5199\u6c34"]','爲人性僻耽佳句，語不驚人死不休。',64,'全唐诗/poet.tang.11000.json','["爲人性僻耽佳句，語不驚人死不休。", "老去詩篇渾漫興，春來花鳥莫深愁。", "新添水檻供垂釣，故著浮槎替入舟。", "焉得思如陶謝手，令渠述作與同遊。"]'),
('6a78cd6d-86f2-4829-8ef1-80ca35415868','送裴五赴東川','杜甫','唐','唐诗','tang','','[]','故人亦流落，高義動乾坤。',48,'全唐诗/poet.tang.11000.json','["故人亦流落，高義動乾坤。", "何日通燕塞，相看老蜀門。", "東行應暫別，北望苦銷魂。", "凜凜悲秋意，非君誰與論。"]'),
('a8a7854a-a95a-4171-8569-56abfb5b1189','赴青城縣出成都寄陶王二少尹','杜甫','唐','唐诗','tang','','[]','老恥妻孥笑，貧嗟出入勞。',48,'全唐诗/poet.tang.11000.json','["老恥妻孥笑，貧嗟出入勞。", "客情投異縣，詩態憶吾曹。", "東郭滄江合，西山白雪高。", "文章差底病，回首興滔滔。"]'),
('f97db092-6895-40e4-a61d-e54cba511c93','因崔五侍御寄高彭州','杜甫','唐','唐诗','tang','','[]','百年已過半，秋至轉饑寒。',24,'全唐诗/poet.tang.11000.json','["百年已過半，秋至轉饑寒。", "為問彭州牧，何時救急難。"]'),
('7dfe38bb-ee39-4126-ac0d-33310dbb03ba','野望因過常少仙','杜甫','唐','唐诗','tang','','[]','野橋齊度馬，秋望轉悠哉。',48,'全唐诗/poet.tang.11000.json','["野橋齊度馬，秋望轉悠哉。", "竹覆青城合，江從灌口來。", "入村樵徑引，嘗果栗皺開。", "落盡高天日，幽人未遣迴。"]'),
('503e8554-22b6-4be6-bd23-be42f5591cbf','寄杜位','杜甫','唐','唐诗','tang','','[]','近聞寬法離新州，想見懷歸尚百憂。',48,'全唐诗/poet.tang.11000.json','["近聞寬法離新州，想見懷歸尚百憂。", "逐客雖皆萬里去，悲君已是十年流。", "干戈況復塵隨眼，鬢髮還應雪滿頭。"]'),
('7d45a81a-7760-4323-95a0-e33be199c67b','奉簡高三十五使君','杜甫','唐','唐诗','tang','','[]','當代論才子，如公復幾人。',48,'全唐诗/poet.tang.11000.json','["當代論才子，如公復幾人。", "驊騮開道路，鷹隼出風塵。", "行色秋將晚，交情老更親。", "天涯喜相見，披豁對吾真。"]'),
('ca2f43ed-1561-4022-b525-b92b76402740','送韓十四江東覲省','杜甫','唐','唐诗','tang','','["\u9001\u522b"]','兵戈不見老萊衣，歎息人間萬事非。',64,'全唐诗/poet.tang.11000.json','["兵戈不見老萊衣，歎息人間萬事非。", "我已無家尋弟妹，君今何處訪庭闈。", "黃牛峽靜灘聲轉，白馬江寒樹影稀。", "此別應須各努力，故鄉猶恐未同歸。"]'),
('41618e63-3f2a-45a9-972c-ba4b9b30b256','酬高使君相贈','杜甫','唐','唐诗','tang','','[]','古寺僧牢落，空房客寓居。',48,'全唐诗/poet.tang.11000.json','["古寺僧牢落，空房客寓居。", "故人供祿米，鄰舍與園蔬。", "雙樹容聽法，三車肯載書。", "草玄吾豈敢，賦或似相如。"]'),
('f12c6cd1-db69-4d70-abde-f8fa28cb597d','草堂即事','杜甫','唐','唐诗','tang','','[]','荒村建子月，獨樹老夫家。',48,'全唐诗/poet.tang.11000.json','["荒村建子月，獨樹老夫家。", "霧裏江船渡，風前徑竹斜。", "寒魚依密藻，宿鷺起圓沙。", "蜀酒禁愁得，無錢何處賒。"]'),
('d9cb4b28-e916-4e05-bb3d-7f4c7cf0ca89','魏十四侍御就弊廬相別','杜甫','唐','唐诗','tang','','[]','有客騎驄馬，江邊問草堂。',48,'全唐诗/poet.tang.11000.json','["有客騎驄馬，江邊問草堂。", "遠尋留藥價，惜別到文場。", "入幕旌旗動，歸軒錦繡香。", "時應念衰疾，書疏及滄浪。"]'),
('00a6e6c6-eba7-48b4-8d9d-f42df46815a6','徐九少尹見過','杜甫','唐','唐诗','tang','','[]','晚景孤村僻，行軍數騎來。',48,'全唐诗/poet.tang.11000.json','["晚景孤村僻，行軍數騎來。", "交新徒有喜，禮厚媿無才。", "賞靜憐雲竹，忘歸步月臺。", "何當看花蘂，欲發照江梅。"]'),
('bd7eff0e-218e-4af8-b731-9f32786581aa','范二員外邈吳十侍御郁特枉駕闕展待聊寄此','杜甫','唐','唐诗','tang','','[]','暫往比鄰去，空聞二妙歸。',48,'全唐诗/poet.tang.11000.json','["暫往比鄰去，空聞二妙歸。", "幽棲誠簡略，衰白已光輝。", "野外貧家遠，村中好客稀。", "論文或不媿，肯重欵柴扉。"]'),
('86034140-52f0-45f7-b895-1a8ccfe59ad4','王十七侍御掄許攜酒至草堂奉寄此詩便請邀高三十五使君同到','杜甫','唐','唐诗','tang','','[]','老夫臥穩朝慵起，白屋寒多暖始開。',64,'全唐诗/poet.tang.11000.json','["老夫臥穩朝慵起，白屋寒多暖始開。", "江鸛巧當幽徑浴，鄰雞還過短牆來。", "繡衣屢許攜家醞，皂蓋能忘折野梅。", "戲假霜威促山簡，須成一醉習池迴。"]'),
('1335ae90-298f-40fa-9b43-c46cdfcb5f3e','王竟攜酒高亦同過共用寒字','杜甫','唐','唐诗','tang','','[]','臥病荒郊遠，通行小徑難。',48,'全唐诗/poet.tang.11000.json','["臥病荒郊遠，通行小徑難。", "故人能領客，攜酒重相看。", "自媿無鮭菜，空煩卸馬鞍。", "移樽勸山簡，頭白恐風寒。"]'),
('995a9440-f8e3-4a9b-843d-27a34ea8b671','陪李七司馬皂江上觀造竹橋即日成往來之人免冬寒入水聊題短作簡李公二首 一','杜甫','唐','唐诗','tang','','[]','伐竹爲橋結構同，褰裳不涉往來通。',64,'全唐诗/poet.tang.11000.json','["伐竹爲橋結構同，褰裳不涉往來通。", "天寒白鶴歸華表，日落青龍見水中。", "顧我老非題柱客，知君才是濟川功。", "合歡却笑千年事，驅石何時到海東。"]'),
('601d90fb-3589-44f1-9a25-9e16af2102c3','陪李七司馬皂江上觀造竹橋即日成往來之人免冬寒入水聊題短作簡李公二首 二','杜甫','唐','唐诗','tang','','[]','把燭成橋夜，迴舟坐客時。',48,'全唐诗/poet.tang.11000.json','["把燭成橋夜，迴舟坐客時。", "天高雲去盡，江迥月來遲。", "衰謝多扶病，招邀屢有期。", "異方乘此興，樂罷不無悲。"]'),
('8ddd5978-71db-43ff-b8e8-119ec0b4fbef','李司馬橋了承高使君自成都回','杜甫','唐','唐诗','tang','','[]','向來江上手紛紛，三日成功事出羣。',32,'全唐诗/poet.tang.11000.json','["向來江上手紛紛，三日成功事出羣。", "已傳童子騎青竹，總擬橋東待使君。"]'),
('cee19f68-28bd-4565-90ef-957426d73e23','少年行二首 一','杜甫','唐','唐诗','tang','','[]','莫笑田家老瓦盆，自從盛酒長兒孫。',32,'全唐诗/poet.tang.11000.json','["莫笑田家老瓦盆，自從盛酒長兒孫。", "傾銀注瓦驚人眼，共醉終同臥竹根。"]'),
('a3aeb9d8-1112-4b40-99fe-11d2db52c001','少年行二首 二','杜甫','唐','唐诗','tang','','[]','巢燕養雛渾去盡，江花結子已無多。',32,'全唐诗/poet.tang.11000.json','["巢燕養雛渾去盡，江花結子已無多。", "黃衫年少來宜數，不見堂前東逝波。"]'),
('079740ca-693f-457c-8ed8-625cf2661088','野人送朱櫻','杜甫','唐','唐诗','tang','','["\u548f\u7269\u8bd7", "\u548f\u7269", "\u8d5e\u7f8e", "\u519c\u6c11"]','西蜀櫻桃也自紅，野人相贈滿筠籠。',64,'全唐诗/poet.tang.11000.json','["西蜀櫻桃也自紅，野人相贈滿筠籠。", "數迴細寫愁仍破，萬顆勻圓訝許同。", "憶昨賜霑門下省，退朝擎出大明宮。", "金盤玉筯無消息，此日嘗新任轉蓬。"]'),
('c6a8ceab-a865-4bb2-9987-13d42349f38a','即事','杜甫','唐','唐诗','tang','','[]','百寶裝腰帶，真珠絡臂韝。',24,'全唐诗/poet.tang.11000.json','["百寶裝腰帶，真珠絡臂韝。", "笑時花近眼，舞罷錦纏頭。"]'),
('846bf783-211a-4122-9587-054fcbdbc6d1','贈花卿','杜甫','唐','唐诗','tang','','[]','錦城絲管日紛紛，半入江風半入雲。',32,'全唐诗/poet.tang.11000.json','["錦城絲管日紛紛，半入江風半入雲。", "此曲秪應天上有，人間能得幾回聞。"]'),
('469e9b83-b9fe-4f2e-89da-bb59dd7b9067','少年行','杜甫','唐','唐诗','tang','','[]','馬上誰家薄媚郎，臨堦下馬坐人牀。',32,'全唐诗/poet.tang.11000.json','["馬上誰家薄媚郎，臨堦下馬坐人牀。", "不通姓字麤豪甚，指點銀瓶索酒嘗。"]'),
('c09c67ab-4080-40bb-85a2-2ed5bc2f32bb','觀李固請司馬弟山水圖三首 一','杜甫','唐','唐诗','tang','','[]','簡易高人意，匡牀竹火爐。',48,'全唐诗/poet.tang.11000.json','["簡易高人意，匡牀竹火爐。", "寒天留遠客，碧海挂新圖。", "雖對連山好，貪看絕島孤。", "羣仙不愁思，冉冉下蓬壺。"]'),
('449addec-d8fe-491c-9ae0-9cc48029574c','觀李固請司馬弟山水圖三首 二','杜甫','唐','唐诗','tang','','[]','方丈渾連水，天臺總映雲。',48,'全唐诗/poet.tang.11000.json','["方丈渾連水，天臺總映雲。", "人間長見畫，老去恨空聞。", "范蠡舟偏小，王喬鶴不羣。", "此生隨萬物，何路出塵氛。"]'),
('6f072a04-f0e8-4487-b814-ff6828d0e3de','觀李固請司馬弟山水圖三首 三','杜甫','唐','唐诗','tang','','[]','高浪垂翻屋，崩崖欲壓牀。',48,'全唐诗/poet.tang.11000.json','["高浪垂翻屋，崩崖欲壓牀。", "野橋分子細，沙岸繞微茫。", "紅浸珊瑚短，青懸薜荔長。", "浮查並坐得，仙老暫相將。"]'),
('7f1258da-f56c-4485-aea5-e405a6ce4997','題桃樹','杜甫','唐','唐诗','tang','','[]','小徑升堂舊不斜，五株桃樹亦從遮。',64,'全唐诗/poet.tang.11000.json','["小徑升堂舊不斜，五株桃樹亦從遮。", "高秋總餧貧人實，來歲還舒滿眼花。", "簾戶每宜通乳燕，兒童莫信打慈鵶。", "寡妻羣盜非今日，天下車書正一家。"]'),
('76d1a527-f7ad-4732-98a1-248d9b64c781','蕭八明府隄處覓桃栽','杜甫','唐','唐诗','tang','','[]','奉乞桃栽一百根，春前爲送浣花村。',32,'全唐诗/poet.tang.11000.json','["奉乞桃栽一百根，春前爲送浣花村。", "河陽縣裏雖無數，濯錦江邊未滿園。"]'),
('b53c554d-abd0-4532-84d2-529d14fdebce','從韋二明府續處覓綿竹','杜甫','唐','唐诗','tang','','[]','華軒藹藹他年到，綿竹亭亭出縣高。',32,'全唐诗/poet.tang.11000.json','["華軒藹藹他年到，綿竹亭亭出縣高。", "江上舍前無此物，幸分蒼翠拂波濤。"]'),
('b31ab8d7-ae0d-4311-ae58-3a2b1e8854b1','憑何十一少府邕覓榿木栽','杜甫','唐','唐诗','tang','','[]','草堂塹西無樹林，非子誰復見幽心。',32,'全唐诗/poet.tang.11000.json','["草堂塹西無樹林，非子誰復見幽心。", "飽聞榿木三年大，與致溪邊十畝陰。"]'),
('4786e50d-a729-4149-b919-d6947757b010','憑韋少府班覓松樹子','杜甫','唐','唐诗','tang','','[]','落落出羣非櫸柳，青青不朽豈楊梅。',32,'全唐诗/poet.tang.11000.json','["落落出羣非櫸柳，青青不朽豈楊梅。", "欲存老蓋千年意，爲覓霜根數寸栽。"]'),
('6e4817d5-dad7-4724-9649-c26b1d2e5b42','又于韋處乞大邑瓷盌','杜甫','唐','唐诗','tang','','[]','大邑燒瓷輕且堅，扣如哀玉錦城傳。',32,'全唐诗/poet.tang.11000.json','["大邑燒瓷輕且堅，扣如哀玉錦城傳。", "君家白盌勝霜雪，急送茅齋也可憐。"]'),
('07452799-e7a9-49e9-ae54-0a10684431fb','詣徐卿覓果栽','杜甫','唐','唐诗','tang','','[]','草堂少花今欲栽，不問綠李與黃梅。',32,'全唐诗/poet.tang.11000.json','["草堂少花今欲栽，不問綠李與黃梅。", "石笋街中却歸去，果園坊裏爲求來。"]'),
('4581792b-5959-4d76-86a0-4802beae1ace','贈別何邕','杜甫','唐','唐诗','tang','','[]','生死論交地，何由見一人。',48,'全唐诗/poet.tang.11000.json','["生死論交地，何由見一人。", "悲君隨燕雀，薄宦走風塵。", "綿谷元通漢，沱江不向秦。", "五陵花滿眼，傳語故鄉春。"]'),
('6762895b-27c7-4f96-9433-0a6cec62d77f','贈別鄭鍊赴襄陽','杜甫','唐','唐诗','tang','','[]','戎馬交馳際，柴門老病身。',48,'全唐诗/poet.tang.11000.json','["戎馬交馳際，柴門老病身。", "把君詩過日，念此別驚神。", "地闊峨眉晚，天高峴首春。", "爲於耆舊內，試覓姓龐人。"]'),
('bdf17c2d-cce3-4dab-b352-d320ab10dc63','重贈鄭鍊','杜甫','唐','唐诗','tang','','[]','鄭子將行罷使臣，囊無一物獻尊親。',32,'全唐诗/poet.tang.11000.json','["鄭子將行罷使臣，囊無一物獻尊親。", "江山路遠羇離日，裘馬誰爲感激人。"]'),
('63d30939-2ba1-4403-a51e-774249ba209b','奉和嚴中丞西城晚眺十韻','杜甫','唐','唐诗','tang','','[]','汲黯匡君切，廉頗出將頻。',120,'全唐诗/poet.tang.11000.json','["汲黯匡君切，廉頗出將頻。", "直詞才不世，雄略動如神。", "政簡移風速，詩清立意新。", "層城臨暇景，絕域望餘春。", "旗尾蛟龍會，樓頭燕雀馴。", "地平江動蜀，天闊樹浮秦。", "帝念深分閫，軍須遠算緡。", "花羅封蛺蝶，瑞錦送麒麟。", "辭第輸高義，觀圖憶古人。", "征南多興緒，事業闇相親。"]'),
('35976f47-d2ee-4703-82c3-7c675e65929b','嚴中丞枉駕見過','杜甫','唐','唐诗','tang','','[]','元戎小隊出郊坰，問柳尋花到野亭。',64,'全唐诗/poet.tang.11000.json','["元戎小隊出郊坰，問柳尋花到野亭。", "川合東西瞻使節，地分南北任流萍。", "扁舟不獨如張翰，白帽還應似管寧。", "寂寞江天雲霧裏，何人道有少微星。"]'),
('069d67fe-d21b-4f83-b2ae-de6cb3af910b','廣州段功曹到得楊五長史譚書功曹却歸聊寄此詩','杜甫','唐','唐诗','tang','','[]','衛青開幕府，楊僕將樓船。',48,'全唐诗/poet.tang.11000.json','["衛青開幕府，楊僕將樓船。", "漢節梅花外，春城海水邊。", "銅梁書遠及，珠浦使將旋。", "貧病他鄉老，煩君萬里傳。"]'),
('2a57a598-b725-46c4-b02a-067039c14263','得廣州張判官叔卿書使還以詩代意','杜甫','唐','唐诗','tang','','[]','鄉關胡騎遠，宇宙蜀城偏。',48,'全唐诗/poet.tang.11000.json','["鄉關胡騎遠，宇宙蜀城偏。", "忽得炎州信，遙從月峽傳。", "雲深驃騎幕，夜隔孝廉船。", "却寄雙愁眼，相思淚點懸。"]'),
('28431a64-2f55-46b1-98a3-5752ba6190a5','送段功曹歸廣州','杜甫','唐','唐诗','tang','','[]','南海春天外，功曹幾月程。',48,'全唐诗/poet.tang.11000.json','["南海春天外，功曹幾月程。", "峽雲籠樹小，湖日落船明。", "交趾丹砂重，韶州白葛輕。", "幸君因旅客，時寄錦官城。"]'),
('9cc96131-623f-46e5-994b-5c3e0f924224','絕句漫興九首 一','杜甫','唐','唐诗','tang','','["\u6625\u5929", "\u5ba2\u6101"]','眼見客愁愁不醒，無賴春色到江亭。',32,'全唐诗/poet.tang.11000.json','["眼見客愁愁不醒，無賴春色到江亭。", "即遣花開深造次，便覺鶯語太丁寧。"]'),
('09a20b1a-c3e2-44cf-9e1f-f4cb5737dd7f','絕句漫興九首 二','杜甫','唐','唐诗','tang','','["\u6625\u5929", "\u5199\u98ce", "\u6292\u60c5", "\u98ce"]','手種桃李非無主，野老牆低還似家。',32,'全唐诗/poet.tang.11000.json','["手種桃李非無主，野老牆低還似家。", "恰似春風相欺得，夜來吹折數枝花。"]'),
('18ea78a0-a031-4bf3-88b6-84810110737e','絕句漫興九首 三','杜甫','唐','唐诗','tang','','[]','熟知茅齋絕低小，江上燕子故來頻。',32,'全唐诗/poet.tang.11000.json','["熟知茅齋絕低小，江上燕子故來頻。", "銜泥點污琴書內，更接飛蟲打著人。"]'),
('b404e60a-6bdf-47fc-9b84-9e224df3a938','絕句漫興九首 四','杜甫','唐','唐诗','tang','','["\u5c81\u6708", "\u6625\u5929", "\u611f\u53f9", "\u7ec4\u8bd7"]','二月已破三月來，漸老逢春能幾迴。',32,'全唐诗/poet.tang.11000.json','["二月已破三月來，漸老逢春能幾迴。", "莫思身外無窮事，且盡生前有限桮。"]'),
('0970d861-e8b1-4379-86d5-cfea6900e51a','絕句漫興九首 五','杜甫','唐','唐诗','tang','','["\u6292\u60c5", "\u5bd3\u4eba", "\u6843\u82b1", "\u5199\u666f"]','腸斷春江欲盡頭，杖藜徐步立芳洲。',32,'全唐诗/poet.tang.11000.json','["腸斷春江欲盡頭，杖藜徐步立芳洲。", "顛狂柳絮隨風去，輕薄桃花逐水流。"]'),
('83648d7d-4cd5-4a8d-9df7-b3c8eb7bb1cc','絕句漫興九首 六','杜甫','唐','唐诗','tang','','[]','嬾慢無堪不出村，呼兒日在掩柴門。',32,'全唐诗/poet.tang.11000.json','["嬾慢無堪不出村，呼兒日在掩柴門。", "蒼苔濁酒林中靜，碧水春風野外昏。"]'),
('58ba4d44-398a-4af4-9ae5-764f809b0de1','絕句漫興九首 七','杜甫','唐','唐诗','tang','','["\u7ec4\u8bd7", "\u590f\u5929", "\u5199\u666f"]','糝徑楊花鋪白氈，點溪荷葉疊青錢。',32,'全唐诗/poet.tang.11000.json','["糝徑楊花鋪白氈，點溪荷葉疊青錢。", "筍根稚子無人見，沙上鳧雛傍母眠。"]'),
('db15a7ee-09b5-4207-86d2-1dd41208ea23','絕句漫興九首 八','杜甫','唐','唐诗','tang','','[]','舍西柔桑葉可拈，江畔細麥復纖纖。',32,'全唐诗/poet.tang.11000.json','["舍西柔桑葉可拈，江畔細麥復纖纖。", "人生幾何春已夏，不放香醪如蜜甜。"]'),
('4a88edd5-84ad-4d97-a77b-f60be6dcf70e','絕句漫興九首 九','杜甫','唐','唐诗','tang','','[]','隔戶楊柳弱嫋嫋，恰似十五女兒腰。',32,'全唐诗/poet.tang.11000.json','["隔戶楊柳弱嫋嫋，恰似十五女兒腰。", "誰謂朝來不作意，狂風挽斷最長條。"]'),
('7e8b6fb6-8dc7-4b6e-b55d-3078e5d22734','江畔獨步尋花七絕句 一','杜甫','唐','唐诗','tang','','[]','江上被花惱不徹，無處告訴只顛狂。',32,'全唐诗/poet.tang.11000.json','["江上被花惱不徹，無處告訴只顛狂。", "走覓南鄰愛酒伴，經旬出飲獨空牀。"]'),
('1d19ca9d-420c-46cb-b165-936133fc2658','江畔獨步尋花七絕句 二','杜甫','唐','唐诗','tang','','[]','稠花亂蘂畏江濱，行步欹危實怕春。',32,'全唐诗/poet.tang.11000.json','["稠花亂蘂畏江濱，行步欹危實怕春。", "詩酒尚堪驅使在，未須料理白頭人。"]'),
('8036c622-e19b-454b-be17-d5fd4f9ec789','江畔獨步尋花七絕句 三','杜甫','唐','唐诗','tang','','[]','江深竹靜兩三家，多事紅花映白花。',32,'全唐诗/poet.tang.11000.json','["江深竹靜兩三家，多事紅花映白花。", "報答春光知有處，應須美酒送生涯。"]'),
('da2b176c-74f1-4ef1-a4d0-1982c14d44ec','江畔獨步尋花七絕句 四','杜甫','唐','唐诗','tang','','[]','東望少城花滿煙，百花高樓更可憐。',32,'全唐诗/poet.tang.11000.json','["東望少城花滿煙，百花高樓更可憐。", "誰能載酒開金盞，喚取佳人舞繡筵。"]'),
('0f24216b-df07-4b64-9071-d2eb78e4c7cb','江畔獨步尋花七絕句 五','杜甫','唐','唐诗','tang','','["\u6625", "\u5199\u666f", "\u6c34", "\u6843\u82b1", "\u8d4f\u82b1"]','黃師塔前江水東，春光嬾困倚微風。',32,'全唐诗/poet.tang.11000.json','["黃師塔前江水東，春光嬾困倚微風。", "桃花一簇開無主，可愛深紅愛淺紅。"]'),
('573bb059-28f0-4ff4-aaed-619bb2924198','江畔獨步尋花七絕句 六','杜甫','唐','唐诗','tang','','["\u6625", "\u5199\u666f", "\u82b1", "\u5199\u82b1", "\u516d\u5e74\u7ea7\u4e0b\u518c", "\u5c0f\u5b66\u53e4\u8bd7"]','黃四娘家花滿蹊，千朵萬朵壓枝低。',32,'全唐诗/poet.tang.11000.json','["黃四娘家花滿蹊，千朵萬朵壓枝低。", "留連戲蝶時時舞，自在嬌鶯恰恰啼。"]'),
('eb02a25c-ef4d-4aeb-9fc7-3a361d2643f3','江畔獨步尋花七絕句 七','杜甫','唐','唐诗','tang','','[]','不是愛花即肯死，只恐花盡老相催。',32,'全唐诗/poet.tang.11000.json','["不是愛花即肯死，只恐花盡老相催。", "繁枝容易紛紛落，嫩葉商量細細開。"]'),
('87ac0c18-5dc2-4a90-88f7-bbabb262d585','三絕句 一','杜甫','唐','唐诗','tang','','[]','楸樹馨香倚釣磯，斬新花蘂未應飛。',32,'全唐诗/poet.tang.11000.json','["楸樹馨香倚釣磯，斬新花蘂未應飛。", "不如醉裏風吹盡，可忍醒時雨打稀。"]'),
('1845dbc5-ff20-4c9c-9394-7781f94aaef9','三絕句 二','杜甫','唐','唐诗','tang','','[]','門外鸕鷀去不來，沙頭忽見眼相猜。',32,'全唐诗/poet.tang.11000.json','["門外鸕鷀去不來，沙頭忽見眼相猜。", "自今已後知人意，一日須來一百回。"]'),
('27e9b2c5-664f-49fb-b6c2-a56c2085c232','三絕句 三','杜甫','唐','唐诗','tang','','["\u548f\u7269\u8bd7", "\u548f\u7269"]','無數春笋滿林生，柴門密掩斷人行。',32,'全唐诗/poet.tang.11000.json','["無數春笋滿林生，柴門密掩斷人行。", "會須上番看成竹，客至從嗔不出迎。"]'),
('db0b8b88-0632-4a98-b864-bf722b7814e6','戲爲六絕句 一','杜甫','唐','唐诗','tang','','["\u54f2\u7406", "\u8bbd\u523a"]','庾信文章老更成，凌雲健筆意縱橫。',32,'全唐诗/poet.tang.11000.json','["庾信文章老更成，凌雲健筆意縱橫。", "今人嗤點流傳賦，不覺前賢畏後生。"]'),
('33a67972-ca3d-4597-a45e-e6e1dd2623b4','戲爲六絕句 二','杜甫','唐','唐诗','tang','','["\u6587\u5b66", "\u89c2\u70b9", "\u52b1\u5fd7"]','楊王盧駱當時體，輕薄爲文哂未休。',32,'全唐诗/poet.tang.11000.json','["楊王盧駱當時體，輕薄爲文哂未休。", "爾曹身與名俱滅，不廢江河萬古流。"]'),
('5b664d03-c089-40df-9909-16b9a0faea26','戲爲六絕句 三','杜甫','唐','唐诗','tang','','[]','從使盧王操翰墨，劣于漢魏近風騷。',32,'全唐诗/poet.tang.11000.json','["從使盧王操翰墨，劣于漢魏近風騷。", "龍文虎脊皆君馭，歷塊過都見爾曹。"]'),
('25dc0364-8d19-4385-b35a-e56abc13fcab','戲爲六絕句 四','杜甫','唐','唐诗','tang','','[]','才力應難誇數公，凡今誰是出羣雄。',32,'全唐诗/poet.tang.11000.json','["才力應難誇數公，凡今誰是出羣雄。", "或看翡翠蘭苕上，未掣鯨魚碧海中。"]'),
('d29fb28a-590d-4d67-9be7-a0217dc6f0c8','戲爲六絕句 五','杜甫','唐','唐诗','tang','','[]','不薄今人愛古人，清詞麗句必爲鄰。',32,'全唐诗/poet.tang.11000.json','["不薄今人愛古人，清詞麗句必爲鄰。", "竊攀屈宋宜方駕，恐與齊梁作後塵。"]'),
('25ab327b-62f9-426e-b195-bd7522b5db7f','戲爲六絕句 六','杜甫','唐','唐诗','tang','','[]','未及前賢更勿疑，遞相祖述復先誰。',32,'全唐诗/poet.tang.11000.json','["未及前賢更勿疑，遞相祖述復先誰。", "別裁僞體親風雅，轉益多師是汝師。"]'),
('4ccf27df-fb7e-4665-a27b-c7cd92e8321d','江頭四詠 丁香','杜甫','唐','唐诗','tang','','[]','丁香體柔弱，亂結枝猶墊。',48,'全唐诗/poet.tang.11000.json','["丁香體柔弱，亂結枝猶墊。", "細葉帶浮毛，疎花披素豔。", "深栽小齋後，庶近幽人占。", "晚墮蘭麝中，休懷粉身念。"]'),
('4e048354-fb21-45be-b06b-6429129fca07','江頭四詠 梔子','杜甫','唐','唐诗','tang','','[]','梔子比衆木，人間誠未多。',48,'全唐诗/poet.tang.11000.json','["梔子比衆木，人間誠未多。", "於身色有用，與道氣傷和。", "紅取風霜實，青看雨露柯。", "無情移得汝，貴在映江波。"]'),
('c114f681-f10b-4974-9640-c09d4b7f4658','江頭四詠 鸂鶒','杜甫','唐','唐诗','tang','','[]','故使籠寬織，須知動損毛。',48,'全唐诗/poet.tang.11000.json','["故使籠寬織，須知動損毛。", "看雲莫悵望，失水任呼號。", "六翮曾經剪，孤飛卒未高。", "且無鷹隼慮，留滯莫辭勞。"]'),
('3df2ee44-0907-409e-8efb-4d21c1b65908','江頭四詠 花鴨','杜甫','唐','唐诗','tang','','["\u548f\u7269\u8bd7", "\u6292\u6000", "\u548f\u7269"]','花鴨無泥滓，堦前每緩行。',48,'全唐诗/poet.tang.11000.json','["花鴨無泥滓，堦前每緩行。", "羽毛知獨立，黑白太分明。", "不覺羣心妒，休牽衆眼驚。", "稻粱霑汝在，作意莫先鳴。"]'),
('55ea6a6b-4849-4712-b076-f343e5c9080c','畏人','杜甫','唐','唐诗','tang','','[]','早花隨處發，春鳥異方啼。',48,'全唐诗/poet.tang.11000.json','["早花隨處發，春鳥異方啼。", "萬里清江上，三年落日低。", "畏人成小築，褊性合幽棲。", "門徑從榛草，無心走馬蹄。"]'),
('ef3344f2-2cdc-4221-b650-d744a5d454d4','遠遊','杜甫','唐','唐诗','tang','','[]','賤子何人記，迷芳著處家。',48,'全唐诗/poet.tang.11000.json','["賤子何人記，迷芳著處家。", "竹風連野色，江沫擁春沙。", "種藥扶衰病，吟詩解歎嗟。", "似聞胡騎走，失喜問京華。"]'),
('d77f340f-1a04-4c5b-9704-2536e4249c6b','野望','杜甫','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u4e03\u8a00\u5f8b\u8bd7", "\u5199\u666f", "\u6292\u60c5"]','西山白雪三奇戍，南浦清江萬里橋。',64,'全唐诗/poet.tang.11000.json','["西山白雪三奇戍，南浦清江萬里橋。", "海內風塵諸弟隔，天涯涕淚一身遙。", "唯將遲暮供多病，未有涓埃荅聖朝。", "跨馬出郊時極目，不堪人事日蕭條。"]'),
('d667cadd-45f0-44ef-947c-1c166be18ccd','官池春鴈二首 一','杜甫','唐','唐诗','tang','','[]','自古稻粱多不足，至今鸂鶒亂爲羣。',32,'全唐诗/poet.tang.11000.json','["自古稻粱多不足，至今鸂鶒亂爲羣。", "且休悵望看春水，更恐歸飛隔暮雲。"]'),
('b4d1bf61-c4e9-4826-86d9-83b237289e87','官池春鴈二首 二','杜甫','唐','唐诗','tang','','[]','青春欲盡急還鄉，紫塞寧論尚有霜。',34,'全唐诗/poet.tang.11000.json','["青春欲盡急還鄉，紫塞寧論尚有霜。", "翅在雲天終不遠，力微[矰]繳絕須防。"]'),
('ddcb96ce-37ef-4674-9ce3-c9b3b9116191','水檻遣心二首 一','杜甫','唐','唐诗','tang','','[]','去郭軒楹敞，無村眺望賒。',48,'全唐诗/poet.tang.11000.json','["去郭軒楹敞，無村眺望賒。", "澄江平少岸，幽樹晚多花。", "細雨魚兒出，微風燕子斜。", "城中十萬戶，此地兩三家。"]'),
('01005a3d-74b2-4be9-b025-6b82b05d936f','水檻遣心二首 二','杜甫','唐','唐诗','tang','','[]','蜀天常夜雨，江檻已朝晴。',48,'全唐诗/poet.tang.11000.json','["蜀天常夜雨，江檻已朝晴。", "葉潤林塘密，衣乾枕席清。", "不堪秪老病，何得尚浮名。", "淺把涓涓酒，深憑送此生。"]'),
('f54ce551-a776-477b-b9a7-0a5896fa2325','屏跡三首 一','杜甫','唐','唐诗','tang','','[]','用拙存吾道，幽居近物情。',48,'全唐诗/poet.tang.11000.json','["用拙存吾道，幽居近物情。", "桑麻深雨露，燕雀半生成。", "村鼓時時急，漁舟箇箇輕。", "杖藜從白首，心跡喜雙清。"]'),
('c78c67c0-9223-44c3-a77c-0ebd19d09a56','屏跡三首 二','杜甫','唐','唐诗','tang','','[]','晚起家何事，無營地轉幽。',48,'全唐诗/poet.tang.11000.json','["晚起家何事，無營地轉幽。", "竹光團野色，舍影漾江流。", "失學從兒嬾，長貧任婦愁。", "百年渾得醉，一月不梳頭。"]'),
('6e9f685e-b34b-416b-ba2b-77fb54c47ec1','屏跡三首 三','杜甫','唐','唐诗','tang','','[]','衰顏甘屏迹，幽事供高臥。',48,'全唐诗/poet.tang.11000.json','["衰顏甘屏迹，幽事供高臥。", "鳥下竹根行，龜開萍葉過。", "年荒酒價乏，日併園蔬課。", "猶酌甘泉歌，歌長擊樽破。"]'),
('bbacb2f4-5bbb-427e-94ad-6ceac6e92253','奉酬嚴公寄題野亭之作','杜甫','唐','唐诗','tang','','[]','拾遺曾奏數行書，嬾性從來水竹居。',64,'全唐诗/poet.tang.11000.json','["拾遺曾奏數行書，嬾性從來水竹居。", "奉引濫騎沙苑馬，幽棲真釣錦江魚。", "謝安不倦登臨費，阮籍焉知禮法疎。", "枉沐旌麾出城府，草茅無徑欲教鋤。"]'),
('a79d86da-f914-4a15-97e6-34a36d856701','中丞嚴公雨中垂寄見憶一絕奉荅二絕 一','杜甫','唐','唐诗','tang','','[]','雨映行宮辱贈詩，元戎肯赴野人期。',32,'全唐诗/poet.tang.11000.json','["雨映行宮辱贈詩，元戎肯赴野人期。", "江邊老病雖無力，強擬晴天理釣絲。"]'),
('a36829d1-e25f-4c31-99cc-f76f540e84b9','中丞嚴公雨中垂寄見憶一絕奉荅二絕 二','杜甫','唐','唐诗','tang','','[]','何日雨晴雲出溪，白沙青石先無泥。',32,'全唐诗/poet.tang.11000.json','["何日雨晴雲出溪，白沙青石先無泥。", "只須伐竹開荒徑，倚杖穿花聽馬嘶。"]'),
('f7961f8c-6bd0-4a4d-89f8-0a10ba3f77b9','謝嚴中丞送青城山道士乳酒一瓶','杜甫','唐','唐诗','tang','','[]','山瓶乳酒下青雲，氣味濃香幸見分。',32,'全唐诗/poet.tang.11000.json','["山瓶乳酒下青雲，氣味濃香幸見分。", "鳴鞭走送憐漁父，洗盞開嘗對馬軍。"]'),
('3cc5a45c-2739-4fc6-9ea9-ca01d2eee3e7','嚴公仲夏枉駕草堂兼攜酒饌','杜甫','唐','唐诗','tang','','[]','竹裏行廚洗玉盤，花邊立馬簇金鞍。',64,'全唐诗/poet.tang.11000.json','["竹裏行廚洗玉盤，花邊立馬簇金鞍。", "非關使者徵求急，自識將軍禮數寬。", "百年地闢柴門逈，五月江深草閣寒。", "看弄漁舟移白日，老農何有罄交歡。"]'),
('8e754fed-aabb-441a-8bdb-ed98dfa07e89','嚴公廳宴同詠蜀道畫圖','杜甫','唐','唐诗','tang','','[]','日臨公館靜，畫滿地圖雄。',48,'全唐诗/poet.tang.11000.json','["日臨公館靜，畫滿地圖雄。", "劒閣星橋北，松州雪嶺東。", "華夷山不斷，吳蜀水相通。", "興與煙霞會，清樽幸不空。"]'),
('39df70ad-1359-4f75-9358-421aa7db5fe6','奉送嚴公入朝十韻','杜甫','唐','唐诗','tang','','["\u6292\u60c5", "\u53cb\u4eba", "\u60c6\u6005"]','鼎湖瞻望遠，象闕憲章新。',120,'全唐诗/poet.tang.11000.json','["鼎湖瞻望遠，象闕憲章新。", "四海猶多難，中原憶舊臣。", "與時安反側，自昔有經綸。", "感激張天步，從容靜塞塵。", "南圖迴羽翮，北極捧星辰，漏鼓還思晝，宮鶯罷囀春。", "空留玉帳術，愁殺錦城人。", "閣道通丹地，江潭隱白蘋。", "此生那老蜀，不死會歸秦。", "公若登台輔，臨危莫愛身。"]'),
('11d6a21c-af79-4347-91b6-27c5009d8b42','送嚴侍郎到綿州同登杜使君江樓','杜甫','唐','唐诗','tang','','[]','野興每難盡，江樓延賞心。',120,'全唐诗/poet.tang.11000.json','["野興每難盡，江樓延賞心。", "歸朝送使節，落景惜登臨。", "稍稍煙集渚，微微風動襟。", "重船依淺瀨，輕鳥度層陰。", "檻峻背幽谷，窗虛交茂林。", "燈光散遠近，月彩靜高深。", "城擁朝來客，天橫醉後參。", "窮途衰謝意，苦調短長吟。", "此會共能幾，諸孫賢至今。", "不勞朱戶閉，自待白河沈。"]'),
('c2c83ee2-940f-4ae3-9ab3-4f509d2991f3','奉濟驛重送嚴公四韻','杜甫','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u9001\u522b", "\u4e94\u8a00\u5f8b\u8bd7", "\u60dc\u522b"]','遠送從此別，青山空復情。',48,'全唐诗/poet.tang.11000.json','["遠送從此別，青山空復情。", "幾時桮重把，昨夜月同行。", "列郡謳歌惜，三朝出入榮。", "江村獨歸處，寂寞養殘生。"]'),
('522051e4-d5f3-4417-886a-93f2a54b6a7d','送梓州李使君之任','杜甫','唐','唐诗','tang','','[]','籍甚黃丞相，能名自潁川。',96,'全唐诗/poet.tang.11000.json','["籍甚黃丞相，能名自潁川。", "近看除刺史，還喜得吾賢。", "五馬何時到，雙魚會早傳。", "老思筇竹杖，冬要錦衾眠。", "不作臨岐恨，惟聽舉最先。", "火雲揮汗日，山驛醒心泉。", "遇害陳公殞，於今蜀道憐。", "君行射洪縣，爲我一潸然。"]'),
('5536e9ad-1b12-4070-b6e0-908f7874e832','巴西驛亭觀江漲呈竇使君','杜甫','唐','唐诗','tang','','[]','宿雨南江漲，波濤亂遠峰。',48,'全唐诗/poet.tang.11000.json','["宿雨南江漲，波濤亂遠峰。", "孤亭凌噴薄，萬井逼舂容。", "霄漢愁高鳥，泥沙困老龍。", "天邊同客舍，攜我豁心胸。"]'),
('04fa7a4c-e624-4083-9668-b05394a5a61d','九日登梓州城','杜甫','唐','唐诗','tang','','[]','伊昔黃花酒，如今白髮翁。',48,'全唐诗/poet.tang.11000.json','["伊昔黃花酒，如今白髮翁。", "追歡筋力異，望遠歲時同。", "弟妹悲歌裏，朝廷醉眼中。", "兵戈與關塞，此日意無窮。"]'),
('c56fd82e-2fab-4c3b-b52c-2631132e0ddf','九日奉寄嚴大夫','杜甫','唐','唐诗','tang','','[]','九日應愁思，經時冒險艱。',48,'全唐诗/poet.tang.11000.json','["九日應愁思，經時冒險艱。", "不眠持漢節，何路出巴山。", "小驛香醪嫩，重巖細菊斑。", "遙知簇鞍馬，迴首白雲間。"]'),
('5a5a2b89-5aa0-4c83-ade1-9fba0784f6e6','黃草','杜甫','唐','唐诗','tang','','[]','黃草峽西船不歸，赤甲山下行人稀。',64,'全唐诗/poet.tang.11000.json','["黃草峽西船不歸，赤甲山下行人稀。", "秦中驛使無消息，蜀道兵戈有是非。", "萬里秋風吹錦水，誰家別淚濕羅衣。", "莫愁劒閣終堪據，聞道松州已被圍。"]'),
('15bd7c09-3748-4340-b221-13d9e3e1ea38','懷舊','杜甫','唐','唐诗','tang','','[]','地下蘇司業，情親獨有君。',48,'全唐诗/poet.tang.11000.json','["地下蘇司業，情親獨有君。", "那因喪亂後，便有死生分。", "老罷知明鏡，悲來望白雲。", "自從失詞伯，不復更論文。"]'),
('963be762-f666-4505-918f-9576c1696f8f','所思','杜甫','唐','唐诗','tang','','[]','鄭老身仍竄，台州信所傳。',48,'全唐诗/poet.tang.11000.json','["鄭老身仍竄，台州信所傳。", "爲農山澗曲，臥病海雲邊。", "世已疎儒素，人猶乞酒錢。", "徒勞望牛斗，無計劚龍泉。"]'),
('5bce54d8-5f1a-487b-807c-b30714c006f4','不見','杜甫','唐','唐诗','tang','','["\u5e90\u5c71", "\u5199\u4eba", "\u5199\u4eba\u8bd7"]','不見李生久，佯狂真可哀。',48,'全唐诗/poet.tang.11000.json','["不見李生久，佯狂真可哀。", "世人皆欲殺，吾意獨憐才。", "敏捷詩千首，飄零酒一桮。", "匡山讀書處，頭白好歸來。"]'),
('785ea8b0-4589-4ea2-a01c-226a2556dbe5','題玄武禪師屋壁','杜甫','唐','唐诗','tang','','["\u5e90\u5c71"]','何年顧虎頭，滿壁畫瀛州。',48,'全唐诗/poet.tang.11000.json','["何年顧虎頭，滿壁畫瀛州。", "赤日石林氣，青天江海流。", "錫飛常近鶴，桮度不驚鷗。", "似得廬山路，真隨惠遠遊。"]'),
('a60d32f9-47fc-4974-8e11-e4473e976fa9','客夜','杜甫','唐','唐诗','tang','','[]','客睡何曾著，秋天不肯明。',48,'全唐诗/poet.tang.11000.json','["客睡何曾著，秋天不肯明。", "卷簾殘月影，高枕遠江聲。", "計拙無衣食，途窮仗友生。", "老妻書數紙，應悉未歸情。"]'),
('f0d0cc44-b364-4ac6-82cf-bedbe162d184','客亭','杜甫','唐','唐诗','tang','','["\u6292\u60c5", "\u5199\u666f"]','秋窗猶曙色，落木更天風。',48,'全唐诗/poet.tang.11000.json','["秋窗猶曙色，落木更天風。", "日出寒山外，江流宿霧中。", "聖朝無棄物，老病已成翁。", "多少殘生事，飄零似轉蓬。"]'),
('0f0c8f24-0fc9-49b9-9f2a-151c2dd1d7ef','秋盡','杜甫','唐','唐诗','tang','','[]','秋盡東行且未迴，茅齋寄在少城隈。',64,'全唐诗/poet.tang.11000.json','["秋盡東行且未迴，茅齋寄在少城隈。", "籬邊老却陶潛菊，江上徒逢袁紹桮。", "雪嶺獨看西日落，劒門猶阻北人來。", "不辭萬里長爲客，懷抱何時得好開。"]'),
('c6d43315-55b6-466c-93e9-2ca33b1c7f41','陪王侍御宴通泉東山野亭','杜甫','唐','唐诗','tang','','[]','江水東流去，清樽日復斜。',48,'全唐诗/poet.tang.11000.json','["江水東流去，清樽日復斜。", "異方同宴賞，何處是京華。", "亭景臨山水，村煙對浦沙。", "狂歌過于勝，得醉即爲家。"]'),
('6261e535-3294-4e7f-b9ba-f014cb45fdf2','野望','杜甫','唐','唐诗','tang','','[]','金華山北涪水西，仲冬風日始淒淒。',64,'全唐诗/poet.tang.11000.json','["金華山北涪水西，仲冬風日始淒淒。", "山連越巂蟠三蜀，水散巴渝下五溪。", "獨鶴不知何事舞，飢烏似欲向人啼。", "射洪春酒寒仍綠，目極傷神誰爲攜。"]'),
('22e90c0d-2b59-4500-8e5d-80d38ec4692c','聞官軍收河南河北','杜甫','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u4e03\u8a00\u5f8b\u8bd7", "\u601d\u5f52", "\u516d\u5e74\u7ea7\u4e0b\u518c", "\u5c0f\u5b66\u53e4\u8bd7"]','劒外忽傳收薊北，初聞涕淚滿衣裳。',64,'全唐诗/poet.tang.11000.json','["劒外忽傳收薊北，初聞涕淚滿衣裳。", "却看妻子愁何在，漫卷詩書喜欲狂。", "白日放歌須縱酒，青春作伴好還鄉。", "即從巴峽穿巫峽，便下襄陽向洛陽。"]'),
('26c93a67-071e-4dae-b2af-94bb6e5b6c40','涪江泛舟送韋班歸京','杜甫','唐','唐诗','tang','','[]','追餞同舟日，傷春一水間。',48,'全唐诗/poet.tang.11000.json','["追餞同舟日，傷春一水間。", "飄零爲客久，衰老羨君還。", "花遠重重樹，雲輕處處山。", "天涯故人少，更益鬢毛斑。"]'),
('199341fd-ab03-4ea1-8862-f5948784254f','春日梓州登樓二首 一','杜甫','唐','唐诗','tang','','[]','行路難如此，登樓望欲迷。',48,'全唐诗/poet.tang.11000.json','["行路難如此，登樓望欲迷。", "身無却少壯，跡有但羇栖。", "江水流城郭，春風入鼓鞞。", "雙雙新燕子，依舊已銜泥。"]'),
('eb5d2cce-6719-4c86-809a-d5b9e9ec5317','春日梓州登樓二首 二','杜甫','唐','唐诗','tang','','[]','天畔登樓眼，隨春入故園。',48,'全唐诗/poet.tang.11000.json','["天畔登樓眼，隨春入故園。", "戰場今始定，移柳更能存。", "厭蜀交遊冷，思吳勝事繁。", "應須理舟楫，長嘯下荆門。"]'),
('0a77f43c-343a-4023-88af-959e5ef629d9','郪城西原送李判官兄武判官弟赴成都府','杜甫','唐','唐诗','tang','','[]','憑高送所親，久坐惜芳辰。',48,'全唐诗/poet.tang.11000.json','["憑高送所親，久坐惜芳辰。", "遠水非無浪，他山自有春。", "野花隨處發，官柳著行新。", "天際傷愁別，離筵何太頻。"]'),
('5d44ba72-a869-4ab1-a67b-07dbaf6deefe','泛江送魏十八倉曹還京因寄岑中允參范郎中季明','杜甫','唐','唐诗','tang','','[]','遲日深春水，輕舟送別筵。',48,'全唐诗/poet.tang.11000.json','["遲日深春水，輕舟送別筵。", "帝鄉愁緒外，春色淚痕邊。", "見酒須相憶，將詩莫浪傳。", "若逢岑與范，爲報各衰年。"]'),
('2a3b9a26-f709-4ea8-a717-29545fb55d61','送路六侍御入朝','杜甫','唐','唐诗','tang','','["\u9001\u522b"]','童稚情親四十年，中間消息兩茫然。',64,'全唐诗/poet.tang.11000.json','["童稚情親四十年，中間消息兩茫然。", "更爲後會知何地，忽漫相逢是別筵。", "不分桃花紅勝錦，生憎柳絮白於綿。", "劒南春色還無賴，觸忤愁人到酒邊。"]'),
('ce481d03-508e-4392-95f6-06ff82d8bb3c','泛江送客','杜甫','唐','唐诗','tang','','[]','二月頻送客，東津江欲平。',48,'全唐诗/poet.tang.11000.json','["二月頻送客，東津江欲平。", "煙花山際重，舟楫浪前輕。", "淚逐勸桮下，愁連吹笛生。", "離筵不隔日，那得易爲情。"]'),
('a0a4bf94-c1b4-45fa-98bc-26705d77a88a','上牛頭寺','杜甫','唐','唐诗','tang','','[]','青山意不盡，衮衮上牛頭。',48,'全唐诗/poet.tang.11000.json','["青山意不盡，衮衮上牛頭。", "無復能拘礙，真成浪出遊。", "花濃春寺靜，竹細野池幽。", "何處鶯啼切，移時獨未休。"]'),
('370c5c28-2d1b-4142-a1c0-f65ed1dd3275','望牛頭寺','杜甫','唐','唐诗','tang','','[]','牛頭見鶴林，梯徑繞幽深。',48,'全唐诗/poet.tang.11000.json','["牛頭見鶴林，梯徑繞幽深。", "春色浮山外，天河宿殿陰。", "傳燈無白日，布地有黃金。", "休作狂歌老，迴看不住心。"]'),
('c341f4ff-dc3d-43a5-acaa-3554bc604c89','上兜率寺','杜甫','唐','唐诗','tang','','[]','兜率知名寺，真如會法堂。',48,'全唐诗/poet.tang.11000.json','["兜率知名寺，真如會法堂。", "江山有巴蜀，棟宇自齊梁。", "庾信哀雖久，何顒好不忘。", "白牛車遠近，且欲上慈航。"]'),
('390a0252-d484-4267-be3a-6326461d93cf','望兜率寺','杜甫','唐','唐诗','tang','','[]','樹密當山徑，江深隔寺門。',48,'全唐诗/poet.tang.11000.json','["樹密當山徑，江深隔寺門。", "霏霏雲氣重，閃閃浪花飜。", "不復知天大，空餘見佛尊。", "時應清盥罷，隨喜給孤園。"]'),
('09d3f32e-3fc8-48dc-8dfe-0fbbef4614a1','甘園','杜甫','唐','唐诗','tang','','[]','春日清江岸，千甘二頃園。',48,'全唐诗/poet.tang.11000.json','["春日清江岸，千甘二頃園。", "青雲羞葉密，白雪避花繁。", "結子隨邊使，開筒近至尊。", "後於桃李熟，終得獻金門。"]'),
('cedb3c9c-602a-47db-b024-c51c9247233d','數陪李梓州泛江有女樂在諸舫戲爲豔曲二首贈李 一','杜甫','唐','唐诗','tang','','[]','上客迴空騎，佳人滿近船。',48,'全唐诗/poet.tang.11000.json','["上客迴空騎，佳人滿近船。", "江清歌扇底，野曠舞衣前。", "玉袖凌風並，金壺隱浪偏。", "競將明媚色，偷眼豔陽天。"]'),
('40e3b186-d3b4-4ae8-a65c-bd5ba20d80de','數陪李梓州泛江有女樂在諸舫戲爲豔曲二首贈李 二','杜甫','唐','唐诗','tang','','[]','白日移歌袖，清霄近笛牀。',48,'全唐诗/poet.tang.11000.json','["白日移歌袖，清霄近笛牀。", "翠眉縈度曲，雲鬢儼分行。", "立馬千山暮，迴舟一水香。", "使君自有婦，莫學野鴛鴦。"]'),
('c40be16a-a428-4903-abb8-27d292a62cf9','登牛頭山亭子','杜甫','唐','唐诗','tang','','[]','路出雙林外，亭窺萬井中。',48,'全唐诗/poet.tang.11000.json','["路出雙林外，亭窺萬井中。", "江城孤照日，山谷遠含風。", "兵革身將老，關河信不通。", "猶殘數行淚，忍對百花叢。"]'),
('3068ad59-dc74-4ef7-8f15-30c1d235ec0b','陪李梓州王閬州蘇遂州李果州四使君登惠義寺','杜甫','唐','唐诗','tang','','[]','春日無人境，虛空不住天。',48,'全唐诗/poet.tang.11000.json','["春日無人境，虛空不住天。", "鶯花隨世界，樓閣寄山巔。", "遲暮身何得，登臨意惘然。", "誰能解金印，瀟灑共安禪。"]'),
('197b472d-2b3f-4099-be8e-11a17dd96c20','送何侍御歸朝','杜甫','唐','唐诗','tang','','[]','舟楫諸侯餞，車輿使者歸。',48,'全唐诗/poet.tang.11000.json','["舟楫諸侯餞，車輿使者歸。", "山花相映發，水鳥自孤飛。", "春日垂霜鬢，天隅把繡衣。", "故人從此去，寥落寸心違。"]'),
('18c5fa19-1eba-4c04-933c-f66b8f3e8d84','江亭送眉州辛別駕昇之','杜甫','唐','唐诗','tang','','[]','柳影含雲幕，江波近酒壺。',48,'全唐诗/poet.tang.11000.json','["柳影含雲幕，江波近酒壺。", "異方驚會面，終宴惜征途。", "沙晚低風蝶，天晴喜浴鳧。", "別離傷老大，意緒日荒蕪。"]'),
('2c7af851-a5b4-4726-bb19-551d2e2035df','涪城縣香積寺官閣','杜甫','唐','唐诗','tang','','[]','寺下春江深不流，山腰官閣迥添愁。',64,'全唐诗/poet.tang.11000.json','["寺下春江深不流，山腰官閣迥添愁。", "含風翠壁孤雲細，背日丹楓萬木稠。", "小院迴廊春寂寂，浴鳧飛鷺晚悠悠。", "諸天合在藤蘿外，昏黑應須到上頭。"]'),
('20c07417-d1ac-43f8-b3e9-504103647e99','戲題寄上漢中王三首 一','杜甫','唐','唐诗','tang','','[]','西漢親王子，成都老客星。',48,'全唐诗/poet.tang.11000.json','["西漢親王子，成都老客星。", "百年雙白鬢，一別五秋螢。", "忍斷桮中物，秪看座右銘。", "不能隨皂蓋，自醉逐浮萍。"]'),
('47a316ac-ed57-45fb-8ca7-8ee26389a7d2','戲題寄上漢中王三首 二','杜甫','唐','唐诗','tang','','[]','策杖時能出，王門異昔遊。',48,'全唐诗/poet.tang.11000.json','["策杖時能出，王門異昔遊。", "已知嗟不起，未許醉相留。", "蜀酒濃無敵，江魚美可求。", "終思一酩酊，淨掃鴈池頭。"]'),
('d4c8cd03-d2a8-4bc9-97f1-496566f10b3a','戲題寄上漢中王三首 三','杜甫','唐','唐诗','tang','','[]','羣盜無歸路，衰顏會遠方。',48,'全唐诗/poet.tang.11000.json','["羣盜無歸路，衰顏會遠方。", "尚憐詩警策，猶記酒顛狂。", "魯衛彌尊重，徐陳略喪亡。", "空餘枚叟在，應念早升堂。"]'),
('e339d42e-c929-458f-ab1c-a37215e654e5','陪章留後侍御宴南樓','杜甫','唐','唐诗','tang','','[]','絕域長夏晚，茲樓清宴同。',98,'全唐诗/poet.tang.11000.json','["絕域長夏晚，茲樓清宴同。", "朝廷燒棧北，鼓角滿天東。", "屢食將軍第，仍騎御史驄。", "本無丹竈術，那免白頭翁。", "寇盜狂歌外，形骸痛飲中。", "野雲低渡水，簷雨細隨風。", "出號江城黑，題詩蠟炬紅。", "此身醒[復]醉，不擬哭途窮。"]'),
('e00f687e-eb10-4e20-a11c-fbe28180a0c9','臺上','杜甫','唐','唐诗','tang','','[]','改席臺能迥，留門月復光。',48,'全唐诗/poet.tang.11000.json','["改席臺能迥，留門月復光。", "雲行遺暑濕，山谷進風涼。", "老去一桮足，誰憐屢舞長。", "何須把官燭，似惱鬢毛蒼。"]'),
('99862a76-dfe7-4990-b83c-156f72808a7e','送王十五判官扶侍還黔中','杜甫','唐','唐诗','tang','','[]','大家東征逐子迴，風生洲渚錦帆開。',64,'全唐诗/poet.tang.11000.json','["大家東征逐子迴，風生洲渚錦帆開。", "青青竹笋迎船出，日日江魚入饌來。", "離別不堪無限意，艱危深仗濟時才。", "黔陽信使應稀少，莫怪頻頻勸酒杯。"]'),
('d0650e64-eb25-45ff-90b5-c14f3bab9f44','倦夜','杜甫','唐','唐诗','tang','','["\u7231\u56fd", "\u6708\u591c", "\u5fe7\u6c11", "\u79cb\u5929", "\u5199\u666f"]','竹涼浸臥內，野月滿庭隅。',48,'全唐诗/poet.tang.11000.json','["竹涼浸臥內，野月滿庭隅。", "重露成涓滴，稀星乍有無。", "暗飛螢自照，水宿鳥相呼。", "萬事干戈裏，空悲清夜徂。"]'),
('28ec8f35-8740-4889-a17b-7b344d9c6b9a','悲秋','杜甫','唐','唐诗','tang','','[]','涼風動萬里，羣盜尚縱橫。',48,'全唐诗/poet.tang.11000.json','["涼風動萬里，羣盜尚縱橫。", "家遠傳書日，秋來爲客情。", "秋窺高鳥過，老逐衆人行。", "始欲投三峽，何由見兩京。"]'),
('c1d50761-3ecb-4fa7-903d-9245dffe99d8','對雨','杜甫','唐','唐诗','tang','','[]','莽莽天涯雨，江邊獨立時。',48,'全唐诗/poet.tang.11000.json','["莽莽天涯雨，江邊獨立時。", "不愁巴道路，恐濕漢旌旗。", "雪嶺防秋急，繩橋戰勝遲。", "西戎甥舅禮，未敢背恩私。"]'),
('c914be80-dbd6-4137-af06-5a38dfbb325f','警急','杜甫','唐','唐诗','tang','','[]','才名舊楚將，妙略擁兵機。',48,'全唐诗/poet.tang.11000.json','["才名舊楚將，妙略擁兵機。", "玉壘雖傳檄，松州會解圍。", "和親知拙計，公主漫無歸。", "青海今誰得，西戎實飽飛。"]'),
('4d89dc1a-b63d-4061-8284-3a5538524bd8','王命','杜甫','唐','唐诗','tang','','[]','漢北豺狼滿，巴西道路難。',48,'全唐诗/poet.tang.11000.json','["漢北豺狼滿，巴西道路難。", "血埋諸將甲，骨斷使臣鞍。", "牢落新燒棧，蒼茫舊築壇。", "深懷喻蜀意，慟哭望王官。"]'),
('0eb40e92-9106-40de-8045-8ecb376e5519','征夫','杜甫','唐','唐诗','tang','','[]','十室幾人在，千山空自多。',48,'全唐诗/poet.tang.11000.json','["十室幾人在，千山空自多。", "路衢唯見哭，城市不聞歌。", "漂梗無安地，銜枚有荷戈。", "官軍未通蜀，吾道竟如何。"]'),
('e4d82478-9848-469c-a277-ee7b5c6cb01f','有感五首 一','杜甫','唐','唐诗','tang','','[]','將帥蒙恩澤，兵戈有歲年。',47,'全唐诗/poet.tang.11000.json','["將帥蒙恩澤，兵戈有歲年。", "至今勞聖主，何以報皇天。", "白骨新交戰，雲臺舊拓邊乘槎斷消息，無處覓張騫。"]'),
('4fe56ec8-afff-43c7-a1f2-f5cc8e8701c5','有感五首 二','杜甫','唐','唐诗','tang','','[]','幽薊餘虵豕，乾坤尚虎狼。',48,'全唐诗/poet.tang.11000.json','["幽薊餘虵豕，乾坤尚虎狼。", "諸侯春不貢，使者日相望。", "慎勿吞青海，無勞問越裳。", "大君先息戰，歸馬華山陽。"]'),
('dc17a18c-4b21-44cb-a1f1-df4a7999392b','有感五首 三','杜甫','唐','唐诗','tang','','[]','洛下舟車入，天中貢賦均。',48,'全唐诗/poet.tang.11000.json','["洛下舟車入，天中貢賦均。", "日聞紅粟腐，寒待翠華春。", "莫取金湯固，長令宇宙新。", "不過行儉德，盜賊本王臣。"]'),
('c87e5521-7e1c-4998-a0b0-952ec1dc8bb5','有感五首 四','杜甫','唐','唐诗','tang','','[]','丹桂風霜急，青梧日夜凋。',48,'全唐诗/poet.tang.11000.json','["丹桂風霜急，青梧日夜凋。", "由來強幹地，未有不臣朝。", "受鉞親賢往，卑宮制詔遙。", "終依古封建，豈獨聽簫韶。"]'),
('1176aa60-c713-464f-bcf8-b48cb11a1af6','有感五首 五','杜甫','唐','唐诗','tang','','[]','盜滅人還亂，兵殘將自疑。',48,'全唐诗/poet.tang.11000.json','["盜滅人還亂，兵殘將自疑。", "登壇名絕假，報主爾何遲。", "領郡輙無色，之官皆有詞。", "願聞哀痛詔，端拱問瘡痍。"]'),
('0549697d-6b1c-45e1-a103-3544530cf6c1','送元二適江左','杜甫','唐','唐诗','tang','','[]','亂後今相見，秋深復遠行。',48,'全唐诗/poet.tang.11000.json','["亂後今相見，秋深復遠行。", "風塵爲客日，江海送君情。", "晉室丹陽尹，公孫白帝城。", "經過自愛惜，取次莫論兵。"]'),
('d4483613-0e22-4a92-b300-32a04e7b795e','章梓州水亭','杜甫','唐','唐诗','tang','','[]','城晚通雲霧，亭深到芰荷。',48,'全唐诗/poet.tang.11000.json','["城晚通雲霧，亭深到芰荷。", "吏人橋外少，秋水席邊多。", "近屬淮王至，高門薊子過。", "荆州愛山簡，吾醉亦長歌。"]'),
('b8c7c683-7bc9-4fe3-bf8f-83561f4d5be4','翫月呈漢中王','杜甫','唐','唐诗','tang','','[]','夜深露氣清，江月滿江城。',48,'全唐诗/poet.tang.11000.json','["夜深露氣清，江月滿江城。", "浮客轉危坐，歸舟應獨行。", "關山同一照，烏鵲自多驚。", "欲得淮王術，風吹暈已生。"]'),
('5d1e2cf0-65a6-4b4f-8c24-0e507c1113fc','戲作寄上漢中王二首 一','杜甫','唐','唐诗','tang','','[]','雲裏不聞雙鴈過，掌中貪見一珠新。',32,'全唐诗/poet.tang.11000.json','["雲裏不聞雙鴈過，掌中貪見一珠新。", "秋風嫋嫋吹江漢，只在他鄉何處人。"]'),
('550784b8-2f3b-4e4f-a131-bb835ad1e92f','戲作寄上漢中王二首 二','杜甫','唐','唐诗','tang','','[]','謝安舟楫風還起，梁苑池臺雪欲飛。',32,'全唐诗/poet.tang.11000.json','["謝安舟楫風還起，梁苑池臺雪欲飛。", "杳杳東山攜漢妓，泠泠修竹待王歸。"]'),
('38740d36-f32e-4ae4-b0db-a120d8a2dcbe','投簡梓州幕府兼簡韋十郎官','杜甫','唐','唐诗','tang','','[]','幕下郎官安穩無，從來不奉一行書。',32,'全唐诗/poet.tang.11000.json','["幕下郎官安穩無，從來不奉一行書。", "固知貧病人須棄，能使韋郎跡也疎。"]'),
('a4d718ee-c020-42b4-97df-499cd0076f7b','登高','杜甫','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u957f\u6c5f", "\u4e03\u8a00\u5f8b\u8bd7", "\u5199\u666f", "\u5fe7\u56fd\u5fe7\u6c11", "\u79cb\u5929"]','風急天高猨嘯哀，渚清沙白鳥飛迴。',64,'全唐诗/poet.tang.11000.json','["風急天高猨嘯哀，渚清沙白鳥飛迴。", "無邊落木蕭蕭下，不盡長江衮衮來。", "萬里悲秋常作客，百年多病獨登臺。", "艱難苦恨繁霜鬢，潦倒新停濁酒桮。"]'),
('a0a22f26-bd2a-457b-8f7d-74add294e009','九日','杜甫','唐','唐诗','tang','','[]','去年登高郪縣北，今日重在涪江濱。',64,'全唐诗/poet.tang.11000.json','["去年登高郪縣北，今日重在涪江濱。", "苦遭白髮不相放，羞見黃花無數新。", "世亂鬱鬱久爲客，路難悠悠常傍人。", "酒闌却憶十年事，腸斷驪山清路塵。"]'),
('45a36ed3-5e37-4daa-a253-33734a21e2e4','遣憤','杜甫','唐','唐诗','tang','','[]','聞道花門將，論功未盡歸。',48,'全唐诗/poet.tang.11000.json','["聞道花門將，論功未盡歸。", "自從收帝里，誰復總戎機。", "蜂蠆終懷毒，雷霆可震威。", "莫令鞭血地，再濕漢臣衣。"]'),
('290c5ecc-f832-4b5f-b0cd-51630106148f','章梓州橘亭餞成都竇少尹','杜甫','唐','唐诗','tang','','[]','秋日野亭千橘香，玉盤錦席高雲涼。',64,'全唐诗/poet.tang.11000.json','["秋日野亭千橘香，玉盤錦席高雲涼。", "主人送客何所作，行酒賦詩殊未央。", "衰老應爲難離別，賢聲此去有輝光。", "預傳籍籍新京尹，青史無勞數趙張。"]'),
('dfcaab39-5c64-4eba-911e-2dec1cedc259','送陵州路使君赴任','杜甫','唐','唐诗','tang','','[]','王室比多難，高官皆武臣。',96,'全唐诗/poet.tang.11000.json','["王室比多難，高官皆武臣。", "幽燕通使者，岳牧用詞人。", "國待賢良急，君當拔擢新。", "佩刀成氣象，行蓋出風塵。", "戰伐乾坤破，瘡痍府庫貧。", "衆僚宜潔白，萬役但平均。", "霄漢瞻佳士，泥途任此身。", "秋天正搖落，迴首大江濱。"]'),
('3de9c519-a79d-41d1-9750-53ac57588765','薄暮','杜甫','唐','唐诗','tang','','[]','江水長流地，山雲薄暮時。',48,'全唐诗/poet.tang.11000.json','["江水長流地，山雲薄暮時。", "寒花隱亂草，宿鳥擇深枝。", "舊國見何日，高秋心苦悲。", "人生不再好，鬢髮白成絲。"]'),
('8d95a8c6-e757-4b75-8c96-a3506d6c7c6f','西山三首 一','杜甫','唐','唐诗','tang','','[]','彝界荒山頂，蕃州積雪邊。',48,'全唐诗/poet.tang.11000.json','["彝界荒山頂，蕃州積雪邊。", "築城依白帝，轉粟上青天。", "蜀將分旗鼓，羌兵助井泉。", "西戎背和好，殺氣日相纏。"]'),
('c0a261d6-76ee-446e-b25d-3fd213d0ddbc','西山三首 二','杜甫','唐','唐诗','tang','','[]','辛苦三城戍，長防萬里秋。',48,'全唐诗/poet.tang.11000.json','["辛苦三城戍，長防萬里秋。", "煙塵浸火井，雨雪閉松州。", "風動將軍幕，天寒使者裘。", "漫山賊營壘，迴首得無憂。"]'),
('23b089b2-2b63-471c-aaac-952b04185e5b','西山三首 三','杜甫','唐','唐诗','tang','','[]','子弟猶深入，關城未解圍。',48,'全唐诗/poet.tang.11000.json','["子弟猶深入，關城未解圍。", "蠶崖鐵馬瘦，灌口米船稀。", "辯士安邊策，元戎決勝威。", "今朝烏鵲喜，欲報凱歌歸。"]'),
('7cec2aa6-8090-476f-bdbb-aaaa8aecf58c','薄遊','杜甫','唐','唐诗','tang','','[]','淅淅風生砌，團團日隱牆。',48,'全唐诗/poet.tang.11000.json','["淅淅風生砌，團團日隱牆。", "遙空秋鴈滅，半嶺暮雲長。", "病葉多先墜，寒花只暫香。", "巴城添淚眼，今夜復清光。"]'),
('bf516a51-e7a6-4240-a5be-5deae79afe96','贈韋贊善別','杜甫','唐','唐诗','tang','','[]','扶病送君發，自憐猶不歸。',48,'全唐诗/poet.tang.11000.json','["扶病送君發，自憐猶不歸。", "秪應盡客淚，復作掩荆扉。", "江漢故人少，音書從此稀。", "往還二十載，歲晚寸心違。"]'),
('a994e456-ce7d-4226-b287-10e41612b718','送李卿嘩','杜甫','唐','唐诗','tang','','[]','王子思歸日，長安已亂兵。',48,'全唐诗/poet.tang.11000.json','["王子思歸日，長安已亂兵。", "霑衣問行在，走馬向承明。", "暮景巴蜀僻，春風江漢清。", "晉山雖自棄，魏闕尚含情。"]'),
('dc5bb894-c908-405b-8280-571cdb08da82','絕句','杜甫','唐','唐诗','tang','','[]','江邊踏青罷，迴首見旌旗。',24,'全唐诗/poet.tang.11000.json','["江邊踏青罷，迴首見旌旗。", "風起春城暮，高樓鼓角悲。"]'),
('7cb7e51b-c366-4df8-ad63-514d23284330','城上','杜甫','唐','唐诗','tang','','[]','草滿巴西綠，空城白日長。',48,'全唐诗/poet.tang.11000.json','["草滿巴西綠，空城白日長。", "風吹花片片，春動水茫茫。", "八駿隨天子，羣臣從武皇。", "遙聞出巡守，早晚徧遐荒。"]'),
('dd0063b6-941f-409a-b14e-e149d44df3a3','舍弟占歸草堂檢校聊示此詩','杜甫','唐','唐诗','tang','','[]','久客應吾道，相隨獨爾來。',48,'全唐诗/poet.tang.11000.json','["久客應吾道，相隨獨爾來。", "孰知江路近，頻爲草堂迴。", "鵝鴨宜長數，柴荆莫浪開。", "東林竹影薄，臘月更須栽。"]'),
('cf81140d-3582-401f-a17d-87607f23ac91','傷春五首 一','杜甫','唐','唐诗','tang','','[]','天下兵雖滿，春光日自濃。',72,'全唐诗/poet.tang.11000.json','["天下兵雖滿，春光日自濃。", "西京疲百戰，北闕任羣兇。", "關塞三千里，煙花一萬重。", "蒙塵清路急，御宿且誰供。", "殷復前王道，周遷舊國容。", "蓬萊足雲氣，應合總從龍。"]'),
('49d2767d-7281-4df2-ba8f-36276d5928e4','傷春五首 二','杜甫','唐','唐诗','tang','','[]','鸎入新年語，花開滿故枝。',72,'全唐诗/poet.tang.11000.json','["鸎入新年語，花開滿故枝。", "天青風捲幔，草碧水通池。", "牢落官軍速，蕭條萬事危。", "鬢毛元自白，淚點向來垂。", "不是無兄弟，其如有別離。", "巴山春色靜，北望轉逶迤。"]'),
('5bd8927c-c929-4a2d-98d9-d6c31a8a8378','傷春五首 三','杜甫','唐','唐诗','tang','','[]','日月還相鬬，星辰屢合圍。',72,'全唐诗/poet.tang.11000.json','["日月還相鬬，星辰屢合圍。", "不成誅執法，焉得變危機。", "大角纏兵氣，鉤陳出帝畿。", "煙塵昏御道，耆舊把天衣。", "行在諸軍闕，來朝大將稀。", "賢多隱屠釣，王肯載同歸。"]'),
('97239505-e2b5-49d0-aa4a-d3a91d939622','傷春五首 四','杜甫','唐','唐诗','tang','','[]','再有朝廷亂，難知消息真。',72,'全唐诗/poet.tang.11000.json','["再有朝廷亂，難知消息真。", "近傳王在洛，復道使歸秦。", "奪馬悲公主，登車泣貴嬪。", "蕭關迷北上，滄海欲東巡。", "敢料安危體，猶多老大臣。", "豈無嵇紹血，霑灑屬車塵。"]'),
('d7bb9666-5122-4a9e-8fb6-404217f2db34','傷春五首 五','杜甫','唐','唐诗','tang','','[]','聞說初東幸，孤兒却走多。',72,'全唐诗/poet.tang.11000.json','["聞說初東幸，孤兒却走多。", "難分太倉粟，競棄魯陽戈。", "胡虜登前殿，王公出御河。", "得無中夜舞，誰憶大風歌。", "春色生烽燧，幽人泣薜蘿。", "君臣重修德，猶足見時和。"]'),
('4d27b426-ebfa-44d6-9574-86c1dfe83093','王閬州筵奉酬十一舅惜別之作','杜甫','唐','唐诗','tang','','[]','萬壑樹聲滿，千崖秋氣高。',72,'全唐诗/poet.tang.11000.json','["萬壑樹聲滿，千崖秋氣高。", "浮舟出郡郭，別酒寄江濤。", "良會不復久，此生何太勞。", "窮愁但有骨，羣盜尚如毛。", "吾舅惜分手，使君寒贈袍。", "沙頭暮黃鴣，失侶自哀號。"]'),
('23834280-4f62-49ac-ba7b-1c27752825fc','放船','杜甫','唐','唐诗','tang','','[]','送客蒼溪縣，山寒雨不開。',48,'全唐诗/poet.tang.11000.json','["送客蒼溪縣，山寒雨不開。", "直愁騎馬滑，故作泛舟迴。", "青惜峰巒過，黃知橘柚來。", "江流大自在，坐穩興悠哉。"]'),
('d883f11d-db2f-4729-b587-b378f3a6a133','奉待嚴大夫','杜甫','唐','唐诗','tang','','[]','殊方又喜故人來，重鎮還須濟世才。',64,'全唐诗/poet.tang.11000.json','["殊方又喜故人來，重鎮還須濟世才。", "常怪偏裨終日待，不知旌節隔年迴。", "欲辭巴徼啼鶯合，遠下旌門去鷁催。", "身老時危思會面，一生襟抱向誰開。"]'),
('6ffb52c7-3cf0-4d4b-939c-9497851ab6bd','奉寄高常侍','杜甫','唐','唐诗','tang','','[]','汶上相逢年頗多，飛騰無那故人何。',64,'全唐诗/poet.tang.11000.json','["汶上相逢年頗多，飛騰無那故人何。", "總戎楚蜀應全未，方駕曹劉不啻過。", "今日朝廷須汲黯，中原將帥憶廉頗。", "天涯春色催遲暮，別淚遙添錦水波。"]'),
('1df24506-ebde-45a0-9d0d-d449f1020b3b','奉寄章十侍御','杜甫','唐','唐诗','tang','','[]','淮海維揚一俊人，金章紫綬照青春。',64,'全唐诗/poet.tang.11000.json','["淮海維揚一俊人，金章紫綬照青春。", "指麾能事迴天地，訓練強兵動鬼神。", "湘西不得歸關羽，河內猶宜借寇恂。", "朝覲從容問幽仄，勿云江漢有垂綸。"]'),
('34be343f-1efd-450f-a5c8-e99c08600aed','將赴荆南寄別李劒州','杜甫','唐','唐诗','tang','','[]','使君高義驅今古，寥落三年坐劒州。',64,'全唐诗/poet.tang.11000.json','["使君高義驅今古，寥落三年坐劒州。", "但見文翁能化俗，焉知李廣未封侯。", "路經灧澦雙蓬鬢，天入滄浪一釣舟。", "戎馬相逢更何日，春風迴首仲宣樓。"]'),
('4ab03240-492d-44fa-b967-00441fb20900','奉寄別馬巴州','杜甫','唐','唐诗','tang','','[]','勳業終歸馬伏波，功曹非復漢蕭何。',64,'全唐诗/poet.tang.11000.json','["勳業終歸馬伏波，功曹非復漢蕭何。", "扁舟繫纜沙邊久，南國浮雲水上多。", "獨把魚竿終遠去，難隨鳥翼一相過。", "知君未愛春湖色，興在驪駒白玉珂。"]'),
('8d2d7846-56ad-418c-a6e2-6f8e5f490c4b','泛江','杜甫','唐','唐诗','tang','','[]','方舟不用楫，極目總無波。',48,'全唐诗/poet.tang.11000.json','["方舟不用楫，極目總無波。", "長日容盃酒，深江淨綺羅。", "亂離還奏樂，飄泊且聽歌。", "故國流清渭，如今花正多。"]'),
('a4856804-965c-40d0-a54d-5379ace1d95c','陪王使君晦日泛江就黃家亭子二首 一','杜甫','唐','唐诗','tang','','[]','山豁何時斷，江平不肯流。',48,'全唐诗/poet.tang.11000.json','["山豁何時斷，江平不肯流。", "稍知花改岸，始驗鳥隨舟。", "結束多紅粉，歡娛恨白頭。", "非君愛人客，晦日更添愁。"]'),
('cfefd449-c8d9-4b64-b391-480f64682615','陪王使君晦日泛江就黃家亭子二首 二','杜甫','唐','唐诗','tang','','[]','有徑金沙軟，無人碧草芳。',48,'全唐诗/poet.tang.11000.json','["有徑金沙軟，無人碧草芳。", "野畦連蛺蝶，江檻俯鴛鴦。", "日晚煙花亂，風生錦繡香。", "不須吹急管，衰老易悲傷。"]'),
('251a7dea-9d42-445d-84de-39a9b71b8bcf','南征','杜甫','唐','唐诗','tang','','["\u6625\u5929", "\u5199\u666f", "\u611f\u6168", "\u5fe7\u56fd\u5fe7\u6c11", "\u6292\u6000"]','春岸桃花水，雲帆楓樹林。',48,'全唐诗/poet.tang.11000.json','["春岸桃花水，雲帆楓樹林。", "偷生長避地，適遠更霑襟。", "老病南征日，君恩北望心。", "百年歌自苦，未見有知音。"]'),
('87334352-82e2-40c3-84b4-ab78ae38e411','久客','杜甫','唐','唐诗','tang','','[]','羈旅知交態，淹留見俗情。',48,'全唐诗/poet.tang.11000.json','["羈旅知交態，淹留見俗情。", "衰顏聊自哂，小吏最相輕。", "去國哀王粲，傷時哭賈生。", "狐狸何足道，豺虎正縱橫。"]'),
('3735888b-0625-49aa-bd0b-22b38bb81c92','春遠','杜甫','唐','唐诗','tang','','["\u6625\u5929", "\u601d\u4e61"]','肅肅花絮晚，菲菲紅素輕。',48,'全唐诗/poet.tang.11000.json','["肅肅花絮晚，菲菲紅素輕。", "日長唯鳥雀，春遠獨柴荆。", "數有關中亂，何曾劒外清。", "故鄉歸不得，地入亞夫營。"]'),
('f8bd9e71-19f2-405b-b654-c5501a8d9acb','暮寒','杜甫','唐','唐诗','tang','','[]','霧隱平郊樹，風含廣岸波。',48,'全唐诗/poet.tang.11000.json','["霧隱平郊樹，風含廣岸波。", "沈沈春色靜，慘慘暮寒多。", "戍鼓猶長擊，林鸎遂不歌。", "忽思高宴會，朱袖拂雲和。"]'),
('a2cf02e5-3f41-4a70-a202-6e16c3b8d59c','雙鷰','杜甫','唐','唐诗','tang','','[]','旅食驚雙鷰，銜泥入此堂。',48,'全唐诗/poet.tang.11000.json','["旅食驚雙鷰，銜泥入此堂。", "應同避燥濕，且復過炎涼。", "養子風塵際，來時道路長。", "今秋天地在，吾亦離殊方。"]'),
('1232ea58-6d47-4e23-a8b3-0c1181aa1afc','百舌','杜甫','唐','唐诗','tang','','[]','百舌來何處，重重祗報春。',48,'全唐诗/poet.tang.11000.json','["百舌來何處，重重祗報春。", "知音兼衆語，整翮豈多身。", "花密藏難見，枝高聽轉新。", "過時如發口，君側有讒人。"]'),
('b2357d9c-7e63-41e4-a3c6-cd71d0117881','地隅','杜甫','唐','唐诗','tang','','[]','江漢山重阻，風雲地一隅。',48,'全唐诗/poet.tang.11000.json','["江漢山重阻，風雲地一隅。", "年年非故物，處處是窮途。", "喪亂秦公子，悲涼楚大夫。", "平生心已折，行路日荒蕪。"]'),
('3aed731e-5ee5-45d4-a3d0-26c8d2ff8dc5','游子','杜甫','唐','唐诗','tang','','[]','巴蜀愁誰語，吳門興杳然。',48,'全唐诗/poet.tang.11000.json','["巴蜀愁誰語，吳門興杳然。", "九江春草外，三峽暮帆前。", "厭就成都卜，休爲吏部眠。", "蓬萊如可到，衰白問羣仙。"]'),
('c89b78bc-576e-40b0-923d-916d181cf73d','歸夢','杜甫','唐','唐诗','tang','','["\u6292\u6000", "\u601d\u4e61"]','道路時通塞，江山日寂寥。',48,'全唐诗/poet.tang.11000.json','["道路時通塞，江山日寂寥。", "偷生唯一老，伐叛已三朝。", "雨急青楓暮，雲深黑水遙。", "夢歸歸未得，不用楚辭招。"]'),
('29556155-b2af-48ef-b0d4-3d38b02d7a48','江亭王閬州筵餞蕭遂州','杜甫','唐','唐诗','tang','','[]','離亭非舊國，春色是他鄉。',48,'全唐诗/poet.tang.11000.json','["離亭非舊國，春色是他鄉。", "老畏歌聲斷，愁隨舞曲長。", "二天開寵餞，五馬爛生光。", "川路風煙接，俱宜下鳳皇。"]'),
('c55ccfa6-8820-40b0-90ff-79412f03c7a8','絕句二首 一','杜甫','唐','唐诗','tang','','["\u6625\u5929", "\u5199\u666f", "\u6625"]','遲日江山麗，春風花草香。',24,'全唐诗/poet.tang.11000.json','["遲日江山麗，春風花草香。", "泥融飛燕子，沙暖睡鴛鴦。"]'),
('d38fe4da-790a-4eaa-b357-360d49d02bd7','絕句二首 二','杜甫','唐','唐诗','tang','','[]','江碧鳥逾白，山青花欲燃。',12,'全唐诗/poet.tang.11000.json','["江碧鳥逾白，山青花欲燃。"]'),
('1546bb1b-8d81-403c-b807-9b5a798fc65e','滕王亭子','杜甫','唐','唐诗','tang','','[]','君王臺榭枕巴山，萬丈丹梯尚可攀。',64,'全唐诗/poet.tang.11000.json','["君王臺榭枕巴山，萬丈丹梯尚可攀。", "春日鸎啼脩竹裏，仙家犬吠白雲間。", "清江錦石傷心麗，嫩蘂濃花滿目班。", "人到於今歌出牧，來遊此地不知還。"]'),
('b8500c5b-349d-41e5-b495-7b8ef514f191','玉臺觀','杜甫','唐','唐诗','tang','','[]','中天積翠玉臺遙，上帝高居絳節朝。',64,'全唐诗/poet.tang.11000.json','["中天積翠玉臺遙，上帝高居絳節朝。", "遂有馮夷來擊鼓，始知嬴女善吹簫。", "江光隱見黿鼉窟，石勢參差烏鵲橋。", "更肯紅顏生羽翼，便應黃髮老漁樵。"]'),
('d66f1624-d12b-41ca-b51d-b90d430bf734','滕王亭子','杜甫','唐','唐诗','tang','','[]','寂寞春山路，君王不復行。',48,'全唐诗/poet.tang.11000.json','["寂寞春山路，君王不復行。", "古牆猶竹色，虛閣自松聲。", "鳥雀荒村暮，雲霞過客情。", "尚思歌吹入，千騎把霓旌。"]'),
('009701aa-5f62-4c7c-b0d7-c7a195709dd9','玉臺觀','杜甫','唐','唐诗','tang','','[]','浩劫因王造，平臺訪古遊。',48,'全唐诗/poet.tang.11000.json','["浩劫因王造，平臺訪古遊。", "綵雲蕭史駐，文字魯恭留。", "宮闕通羣帝，乾坤到十洲。", "人傳有笙鶴，時過此山頭。"]'),
('d10fbfdb-8ed3-4bbc-8e9b-d42b59a97ad9','渡江','杜甫','唐','唐诗','tang','','[]','春江不可渡，二月已風濤。',48,'全唐诗/poet.tang.11000.json','["春江不可渡，二月已風濤。", "舟楫欹斜疾，魚龍偃臥高。", "渚花兼素錦，汀草亂青袍。", "戲問垂綸客，悠悠見汝曹。"]'),
('642a76f7-5cef-4296-a804-1e9c47694e42','喜雨','杜甫','唐','唐诗','tang','','[]','南國旱無雨，今朝江出雲。',48,'全唐诗/poet.tang.11000.json','["南國旱無雨，今朝江出雲。", "入空纔漠漠，灑迥已紛紛。", "巢燕高飛盡，林花潤色分。", "晚來聲不絕，應得夜深聞。"]'),
('0d99511b-3c00-46f9-9f6a-142a52914f9e','送韋郎司直歸成都','杜甫','唐','唐诗','tang','','[]','竄身來蜀地，同病得韋郎。',48,'全唐诗/poet.tang.11000.json','["竄身來蜀地，同病得韋郎。", "天下干戈滿，江邊歲月長。", "別筵花欲暮，春日鬢俱蒼。", "爲問南溪竹，抽梢合過墻。"]'),
('d61e94df-d121-4e6e-93c4-a00ae7135c3e','將赴成都草堂途中有作先寄嚴鄭公五首 一','杜甫','唐','唐诗','tang','','[]','得歸茅屋赴成都，直爲文翁再剖符。',63,'全唐诗/poet.tang.11000.json','["得歸茅屋赴成都，直爲文翁再剖符。", "但使閭閻還揖讓，敢論松竹久荒蕪。", "魚知丙穴由來美酒憶郫筒不用酤。", "五馬舊曾諳小徑，幾回書札待潛夫。"]'),
('8138a2d0-cd03-4430-95cf-487daa5d6902','將赴成都草堂途中有作先寄嚴鄭公五首 二','杜甫','唐','唐诗','tang','','[]','處處青江帶白蘋，故園猶得見殘春。',64,'全唐诗/poet.tang.11000.json','["處處青江帶白蘋，故園猶得見殘春。", "雪山斥候無兵馬，錦里逢迎有主人。", "休怪兒童延俗客，不教鵝鴨惱比鄰。", "習池未覺風流盡，況復旌州賞更新。"]'),
('49fc2b80-a407-453f-8ba7-1d03786dcf70','將赴成都草堂途中有作先寄嚴鄭公五首 三','杜甫','唐','唐诗','tang','','[]','竹寒沙碧浣花溪，菱刺藤梢咫尺迷。',64,'全唐诗/poet.tang.11000.json','["竹寒沙碧浣花溪，菱刺藤梢咫尺迷。", "過客徑須愁出入，居人不自解東西。", "書籤藥裏封蛛網，野店山橋送馬蹄。", "豈藉荒庭春草色，先判一飲醉如泥。"]'),
('d0acd2d0-4a13-4846-a376-ef98cd6adc8a','將赴成都草堂途中有作先寄嚴鄭公五首 四','杜甫','唐','唐诗','tang','','[]','常苦沙崩損藥欄，也從江檻落風湍。',64,'全唐诗/poet.tang.11000.json','["常苦沙崩損藥欄，也從江檻落風湍。", "新松恨不高千尺，惡竹應須斬萬竿。", "生理祗憑黃閣老，衰顏欲付紫金丹。", "三年奔走空皮骨，信有人間行路難。"]'),
('5165a927-d370-4d22-859a-b990ed586169','將赴成都草堂途中有作先寄嚴鄭公五首 五','杜甫','唐','唐诗','tang','','[]','錦官城西生事微，烏皮几在還思歸。',64,'全唐诗/poet.tang.11000.json','["錦官城西生事微，烏皮几在還思歸。", "昔去爲憂亂兵入，今來已恐鄰人非。", "側身天地更懷古，迴首風塵甘息機。", "共說總戎雲鳥陣，不妨遊子芰荷衣。"]'),
('c19e64b1-604b-40b7-9e41-6ef57b9c6f7b','別房太尉墓','杜甫','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u5fe7\u56fd\u5fe7\u6c11", "\u611f\u4f24", "\u4e94\u8a00\u5f8b\u8bd7", "\u60bc\u4ea1"]','他鄉復行役，駐馬別孤墳。',48,'全唐诗/poet.tang.11000.json','["他鄉復行役，駐馬別孤墳。", "近淚無乾土，低空有斷雲。", "對碁陪謝傅，把劒覓徐君。", "唯見林花落，鸎啼送客聞。"]'),
('03888191-1fe8-46a6-b8d4-49d65adde905','自閬州領妻子却赴蜀州山行三首 一','杜甫','唐','唐诗','tang','','[]','汨汨避羣盜，悠悠經十年。',48,'全唐诗/poet.tang.11000.json','["汨汨避羣盜，悠悠經十年。", "不成向南國，復作遊西川。", "物役水虛照，魂傷山寂然。", "我生無倚著，盡室畏途邊。"]'),
('598342f1-e4d1-45d1-b813-6aa0cac1ce52','自閬州領妻子却赴蜀州山行三首 二','杜甫','唐','唐诗','tang','','[]','長林偃風色，迴復意猶迷。',48,'全唐诗/poet.tang.11000.json','["長林偃風色，迴復意猶迷。", "衫裛翠微潤，馬銜青草嘶。", "棧縣斜避石，橋斷却尋溪。", "何日干戈盡，飄飄媿老妻。"]'),
('3678278c-bddf-4639-837c-45fa64d6b28b','自閬州領妻子却赴蜀州山行三首 三','杜甫','唐','唐诗','tang','','[]','行色遞隱見，人煙時有無。',48,'全唐诗/poet.tang.11000.json','["行色遞隱見，人煙時有無。", "僕夫穿竹語，稚子入雲呼。", "轉石驚魑魅，抨弓落狖鼯。", "真供一笑樂，似欲慰窮途。"]'),
('41d75b9e-6d29-4ba1-8d86-334eded1d58e','山館','杜甫','唐','唐诗','tang','','[]','南國晝多霧，北風天正寒。',48,'全唐诗/poet.tang.11000.json','["南國晝多霧，北風天正寒。", "路危行木杪，身遠宿雲端。", "山鬼吹燈滅，廚人語夜闌。", "雞鳴問前館，世亂敢求安。"]'),
('7db9a125-9ac8-48a3-a81c-5e61329eaaee','行次鹽亭縣卿題四韻奉簡嚴遂州蓬州兩使君諮議諸昆季','杜甫','唐','唐诗','tang','','[]','馬首見鹽亭，高山擁縣青。',48,'全唐诗/poet.tang.11000.json','["馬首見鹽亭，高山擁縣青。", "雲溪花淡淡，春郭水泠泠。", "全蜀多名士，嚴家聚德星。", "長歌意無極，好爲老夫聽。"]'),
('7cdb4a32-f710-4533-87d3-089684f18062','倚杖','杜甫','唐','唐诗','tang','','[]','看花雖郭內，倚杖即溪邊。',48,'全唐诗/poet.tang.11000.json','["看花雖郭內，倚杖即溪邊。", "山縣早休市，江橋春聚船。", "狎鷗輕白浪，歸鴈喜青天。", "物色兼生意，淒涼憶去年。"]'),
('b3b9d6ef-b19c-4429-b799-db527e8907a4','陪王漢州留杜綿州泛房公西湖','杜甫','唐','唐诗','tang','','["\u897f\u6e56"]','舊相恩追後，春池賞不稀。',50,'全唐诗/poet.tang.11000.json','["舊相恩追後，春池賞不稀。", "闕庭分未到，舟楫有光輝。", "豉化蓴絲熟，刀鳴[鱠]縷飛。", "使君雙皁蓋，灘淺正相依。"]'),
('7d58ca74-af48-4268-93bb-783f2a2d111f','舟前小鵝兒','杜甫','唐','唐诗','tang','','[]','鵝兒黃似酒，對酒愛新鵝。',48,'全唐诗/poet.tang.11000.json','["鵝兒黃似酒，對酒愛新鵝。", "引頸嗔船逼，無行亂眼多。", "翅開遭宿雨，力小困滄波。", "客散層城暮，狐狸奈若何。"]'),
('6b243693-2a80-43cd-8c64-8c0e520a22ae','得房公池鵝','杜甫','唐','唐诗','tang','','[]','房相西亭鵝一羣，眠沙泛浦白於雲。',32,'全唐诗/poet.tang.11000.json','["房相西亭鵝一羣，眠沙泛浦白於雲。", "鳳皇池上應迴首，爲報籠隨王右軍。"]'),
('6203888d-a574-47fa-8171-628b4d9d5155','荅楊梓州','杜甫','唐','唐诗','tang','','[]','悶到房公池水頭，坐逢楊子鎮東州。',32,'全唐诗/poet.tang.11000.json','["悶到房公池水頭，坐逢楊子鎮東州。", "却向青溪不相見，迴船應載阿戎遊。"]'),
('12919986-2d09-4d2e-b5ad-f2485e40ada5','登樓','杜甫','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u968b\u30fb\u5510\u30fb\u4e94\u4ee3", "\u4e03\u8a00\u5f8b\u8bd7", "\u5199\u666f", "\u6000\u53e4", "\u4e00\u5e74\u7ea7\u4e0b\u518c"]','花近高樓傷客心，萬方多難此登臨。',64,'全唐诗/poet.tang.11000.json','["花近高樓傷客心，萬方多難此登臨。", "錦江春色來天地，玉壘浮雲變古今。", "北極朝廷終不改，西山寇盜莫相侵。", "可憐後主還祠廟，日暮聊爲梁甫吟。"]'),
('2f4ed534-1654-4701-8969-2cdc4c02b58b','春歸','杜甫','唐','唐诗','tang','','["\u6292\u60c5", "\u5199\u666f", "\u5fe7\u8651", "\u6101\u82e6"]','苔徑臨江竹，茅簷覆地花。',72,'全唐诗/poet.tang.11000.json','["苔徑臨江竹，茅簷覆地花。", "別來頻甲子，倏忽又春華。", "倚杖看孤石，傾壺就淺沙。", "遠鷗浮水靜，輕鷰受風斜。", "世路雖多梗，吾生亦有涯。", "此身醒復醉，乘興即爲家。"]'),
('b325248c-fe36-4299-97fc-78e31bac554d','歸鴈','杜甫','唐','唐诗','tang','','["\u601d\u4e61", "\u5199\u9e1f", "\u9e1f"]','東來萬里客，亂定幾年歸。',24,'全唐诗/poet.tang.11000.json','["東來萬里客，亂定幾年歸。", "腸斷江城鴈，高高正北飛。"]'),
('59f7c852-316a-4a45-838a-923df108a993','贈王二十四侍御契四十韻','杜甫','唐','唐诗','tang','','[]','往往雖相見，飄飄媿此身。',288,'全唐诗/poet.tang.11000.json','["往往雖相見，飄飄媿此身。", "不關輕紱冕，俱是避風塵。", "一別星橋夜，三移斗柄春。", "敗亡非赤壁，奔走爲黃巾。", "子去何瀟灑，余藏異隱淪。", "書成無過雁，衣故有縣鶉。", "恐懼行裝數，伶俜臥疾頻。", "曉鸎工迸淚，秋月解傷神。", "會面嗟黧黑，含悽話苦辛。", "接輿還入楚，王粲不歸秦。", "錦里殘丹竈，花溪得釣綸。", "消中祗自惜，晚起索誰親。", "伏柱聞周史，乘槎有漢臣。", "鴛鴻不易狎，龍虎未宜馴。", "客則挂冠至，交非傾蓋新。", "由來意氣合，直取性情真。", "浪跡同生死，無心恥賤貧。", "偶然存蔗芋，幸各對松筠。", "麤飯依他日，窮愁怪此辰。", "女長裁褐穩，男大卷書勻。", "漰口江如練，蠶崖雪似銀。", "名園當翠巘，野棹沒青蘋。", "屢喜王侯宅，時邀江海人。", "追隨不覺晚，欵曲動彌旬。"]'),
('34493244-b343-4762-b07b-f9c0110926ea','寄董卿嘉榮十韻','杜甫','唐','唐诗','tang','','[]','聞道君牙帳，防秋近赤霄。',120,'全唐诗/poet.tang.11000.json','["聞道君牙帳，防秋近赤霄。", "下臨千雪嶺，却背五繩橋。", "海內久戎服，京師今晏朝。", "犬羊曾爛熳，宮闕尚蕭條。", "猛將宜嘗膽，龍泉必在腰。", "黃圖遭污辱，月窟可焚燒。", "會取干戈利，無令斥候驕。", "居然雙捕虜，自是一嫖姚。", "落日思輕騎，高天憶射雕。", "雲臺畫形像，皆爲掃氛妖。"]'),
('9340f8a2-3051-48fd-b8a5-09a2669f722b','寄司馬山人十二韻','杜甫','唐','唐诗','tang','','[]','關內昔分袂，天邊今轉蓬。',144,'全唐诗/poet.tang.11000.json','["關內昔分袂，天邊今轉蓬。", "驅馳不可說，談笑偶然同。", "道術曾留意，先生早擊蒙。", "家家迎薊子，處處識壺公。", "長嘯峨嵋北，潛行玉壘東。", "有時騎猛虎，虛室使仙童。", "髮少何勞白，顏衰肯更紅。", "望雲悲轗軻，畢景羨沖融。", "喪亂形仍役，淒涼信不通。", "懸旌要路口，倚劒短亭中。", "永作殊方客，殘生一老翁。", "相哀骨可換，亦遣馭清風。"]'),
('6aad28c5-dded-4c0c-884f-1c21d25854ef','黃河二首 一','杜甫','唐','唐诗','tang','','["\u9ec4\u6cb3"]','黃河北岸海西軍，椎鼓鳴鐘天下聞。',32,'全唐诗/poet.tang.11000.json','["黃河北岸海西軍，椎鼓鳴鐘天下聞。", "鐵馬長鳴不知數，胡人高鼻動成羣。"]'),
('1913f5e2-b937-40ac-ba4b-ea09007d13e1','黃河二首 二','杜甫','唐','唐诗','tang','','["\u9ec4\u6cb3"]','黃河西岸是吾蜀，欲須供給家無粟。',32,'全唐诗/poet.tang.11000.json','["黃河西岸是吾蜀，欲須供給家無粟。", "願驅衆蔗戴君王，混一車書棄金玉。"]'),
('a671ac61-41e6-479a-80fe-f132f6d433dc','寄李十四員外布十二韻','杜甫','唐','唐诗','tang','','[]','名參漢望苑，職述景題輿。',144,'全唐诗/poet.tang.11000.json','["名參漢望苑，職述景題輿。", "巫峽將之郡，荆門好附書。", "遠行無自苦，內熱比何如。", "正是炎天闊，那堪野館疎。", "黃牛平駕浪，畫鷁上凌虛。", "試待盤渦歇，方期解纜初。", "悶能過小徑，自爲摘嘉蔬。", "渚柳元幽僻，村花不掃除。", "宿陰繁素柰，過雨亂紅蕖。", "寂寂夏先晚，泠泠風有餘。", "江清心可瑩，竹冷髮堪梳。", "直作移巾几，秋帆發弊廬。"]'),
('8aa9b90a-e380-494c-a312-e82ce2fd95c1','歸來','杜甫','唐','唐诗','tang','','[]','客裏有所過，歸來知路難。',48,'全唐诗/poet.tang.11000.json','["客裏有所過，歸來知路難。", "開門野鼠走，散帙壁魚乾。", "洗杓開新醞，低頭拭小盤。", "憑誰給麴蘖，細酌老江干。"]'),
('f3881b29-fd35-4459-93c9-80fc02411b53','王錄事許脩草堂貲不到聊小詰','杜甫','唐','唐诗','tang','','[]','爲嗔王錄事，不寄草堂貲。',24,'全唐诗/poet.tang.11000.json','["爲嗔王錄事，不寄草堂貲。", "昨屬愁春雨，能忘欲漏時。"]'),
('88d481a0-19f1-46f9-8959-6ba465381437','寄邛州崔錄事','杜甫','唐','唐诗','tang','','[]','邛州崔錄事，聞在果園坊。',48,'全唐诗/poet.tang.11000.json','["邛州崔錄事，聞在果園坊。", "久待無消息，終朝有底忙。", "應愁江樹遠，怯見野亭荒。", "浩蕩風塵外，誰知酒熟香。"]'),
('0a97b732-79e2-426f-81ac-c16bec77daf2','過故斛斯校書莊二首 一','杜甫','唐','唐诗','tang','','[]','此老已云歿，鄰人嗟亦休。',48,'全唐诗/poet.tang.11000.json','["此老已云歿，鄰人嗟亦休。", "竟無宣室召，徒有茂陵求。", "妻子寄他食，園林非昔遊。", "空餘繐帷在，淅淅野風秋。"]'),
('0145ae39-2773-42f7-9287-ea653ce947a7','過故斛斯校書莊二首 二','杜甫','唐','唐诗','tang','','[]','燕入非旁舍，鷗歸祗故池。',48,'全唐诗/poet.tang.11000.json','["燕入非旁舍，鷗歸祗故池。", "斷橋無復板，臥柳自生枝。", "遂有山陽作，多慚鮑叔知。", "素交零落盡，白首淚雙垂。"]'),
('322046c5-fbdd-4d0d-b085-51250f255e61','立秋雨院中有作','杜甫','唐','唐诗','tang','','[]','山雲行絕塞，大火復西流。',96,'全唐诗/poet.tang.11000.json','["山雲行絕塞，大火復西流。", "飛雨動華屋，蕭蕭梁棟秋。", "窮途媿知己，暮齒借前籌。", "已費清晨謁，那成長者謀。", "解衣開北戶，高枕對南樓。", "樹濕風涼進，江喧水氣浮。", "禮寬心有適，節爽病微瘳。", "主將歸調鼎，吾還訪舊丘。"]'),
('bc9806ac-4ec6-43fa-b84d-f9502d5c8aa9','奉和嚴大夫軍城早秋','杜甫','唐','唐诗','tang','','[]','秋風褭褭動高旌，玉帳分弓射虜營。',32,'全唐诗/poet.tang.11000.json','["秋風褭褭動高旌，玉帳分弓射虜營。", "已收滴博雲間戍，更奪蓬婆雪外城。"]'),
('7cdb6ea4-8134-4ac9-a201-952fec088296','院中晚晴懷西郭茅舍','杜甫','唐','唐诗','tang','','[]','幕府秋風日夜清，澹雲疎雨過高城。',64,'全唐诗/poet.tang.11000.json','["幕府秋風日夜清，澹雲疎雨過高城。", "葉心朱實看時落，階面青苔先自生。", "復有樓臺銜暮景，不勞鐘鼓報新晴。", "浣花溪裏花饒笑，肯信吾兼吏隱名。"]'),
('b67cee37-9190-4581-89ec-473df5ef0c6f','到村','杜甫','唐','唐诗','tang','','[]','碧澗雖多雨，秋沙先少泥。',72,'全唐诗/poet.tang.11000.json','["碧澗雖多雨，秋沙先少泥。", "蛟龍引子過，荷芰逐花低。", "老去參戎幕，歸來散馬蹄。", "稻粱須就列，榛草即相迷。", "蓄積思江漢，疎頑惑町畦。", "稍酬知己分，還入故林棲。"]'),
('f540f519-e3c4-41c2-b299-f1d255977705','宿府','杜甫','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u611f\u65f6", "\u5b64\u72ec", "\u4e03\u8a00\u5f8b\u8bd7"]','清秋幕府井梧寒，獨宿江城蠟炬殘。',64,'全唐诗/poet.tang.11000.json','["清秋幕府井梧寒，獨宿江城蠟炬殘。", "永夜角聲悲自語，中天月色好誰看。", "風塵荏苒音書絕，關塞蕭條行路難。", "已忍伶俜十年事，強移栖息一枝安。"]'),
('a9d85d1f-936c-489c-a074-9e2be10e5af6','遣悶奉呈嚴公二十韻','杜甫','唐','唐诗','tang','','[]','白水魚竿客，清秋鶴髮翁。',242,'全唐诗/poet.tang.11000.json','["白水魚竿客，清秋鶴髮翁。", "胡爲來幕下，秪合在舟中。", "黃卷真如律，青袍也自公。", "老妻憂坐[痹]，幼女問頭風。", "平地專欹倒，分曹失異同。", "禮甘衰力就，義忝上官通。", "疇昔論詩蚤，光輝仗鉞雄。", "寬容存性拙，剪拂念途窮。", "露裛思藤架，煙霏想桂叢。", "信然龜觸網，直作鳥窺籠。", "西嶺紆村北，南江遶舍東。", "竹皮寒舊翠，椒實雨新紅。", "浪簸船應坼，杯乾甕即空。", "藩籬生野徑，斤斧任樵童。", "束縛酬知己，蹉跎効小忠。", "周防期稍稍，太簡遂悤悤。", "曉入朱扉啓，昏歸畫角終。", "不成尋別業，未敢息微躬。", "烏鵲愁銀漢，駑駘怕錦幪。", "會希全物色，時放倚梧桐。"]'),
('e0352351-cbb8-4181-a13c-560a59351f65','送舍弟頻赴齊州三首 一','杜甫','唐','唐诗','tang','','[]','岷嶺南蠻北，徐關東海西。',48,'全唐诗/poet.tang.11000.json','["岷嶺南蠻北，徐關東海西。", "此行何日到，送汝萬行啼。", "絕域惟高枕，清風獨杖藜。", "危時暫相見，衰白意都迷。"]'),
('63d7c6b3-e7ae-46f9-ba66-a92675741240','送舍弟頻赴齊州三首 二','杜甫','唐','唐诗','tang','','[]','風塵暗不開，汝去幾時來。',36,'全唐诗/poet.tang.11000.json','["風塵暗不開，汝去幾時來。", "兄弟分離苦，形容老病催。", "江通一柱觀，日落望鄉臺。"]'),
('9d334d8a-642f-4f6d-9dae-a3e4cb7165b3','送舍弟頻赴齊州三首 三','杜甫','唐','唐诗','tang','','[]','諸姑今海畔，兩弟亦山東。',48,'全唐诗/poet.tang.11000.json','["諸姑今海畔，兩弟亦山東。", "去傍干戈覓，來看道路通。", "短衣防戰地，匹馬逐秋風。", "莫作俱流落，長瞻碣石鴻。"]'),
('b3b34546-d2b2-45f5-bb3b-177fcb29e35e','嚴鄭公階下新松','杜甫','唐','唐诗','tang','','[]','弱質豈自負，移根方爾瞻。',48,'全唐诗/poet.tang.11000.json','["弱質豈自負，移根方爾瞻。", "細聲聞玉帳，疎翠近珠簾。", "未見紫烟集，虛蒙清露霑。", "何當一百丈，欹蓋擁高簷。"]'),
('a2c64cce-66c4-481f-bcce-0b54ff36d87f','嚴鄭公宅同詠竹','杜甫','唐','唐诗','tang','','["\u5bb4\u996e", "\u548f\u7269\u8bd7", "\u548f\u7269"]','綠竹半含籜，新梢纔出牆。',48,'全唐诗/poet.tang.11000.json','["綠竹半含籜，新梢纔出牆。", "色侵書帙晚，陰過酒樽涼。", "雨洗娟娟淨，風吹細細香。", "但令無剪伐，會見拂雲長。"]'),
('0ac25dea-5343-40b0-92ff-f61969a78556','奉觀嚴鄭公廳事岷山沱江畫圖十韻','杜甫','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','沱水流中座，岷山到此堂。',120,'全唐诗/poet.tang.11000.json','["沱水流中座，岷山到此堂。", "白波吹粉壁，青嶂插雕梁。", "直訝杉松冷，兼疑菱荇香。", "雪雲虛點綴，沙草得微茫。", "嶺鴈隨毫末，川蜺飲練光。", "霏紅洲蘂亂，拂黛石蘿長。", "暗谷非關雨，丹楓不爲霜。", "秋成玄圃外，景物洞庭旁。", "繪事功殊絕，幽襟興激昂。", "從來謝太傅，丘壑道難忘。"]'),
('dceaa342-8374-4c18-9c45-85943d152c38','晚秋陪嚴鄭公摩訶池泛舟','杜甫','唐','唐诗','tang','','[]','湍駛風醒酒，船迴霧起隄。',48,'全唐诗/poet.tang.11000.json','["湍駛風醒酒，船迴霧起隄。", "高城秋自落，雜樹晚相迷。", "坐觸鴛鴦起，巢傾翡翠低。", "莫須驚白鷺，爲伴宿清溪。"]'),
('cb25edb2-93ff-438b-9d11-5823c96c0dd4','初冬','杜甫','唐','唐诗','tang','','[]','垂老戎衣窄，歸休寒色深。',48,'全唐诗/poet.tang.11000.json','["垂老戎衣窄，歸休寒色深。", "漁舟上急水，獵火著高林。", "日有習池醉，愁來梁甫吟。", "干戈未偃息，出處遂何心。"]'),
('6fd3e5b2-168d-4899-b0c9-8e74dc2237ab','至後','杜甫','唐','唐诗','tang','','[]','冬至至後日初長，遠在劒南思洛陽。',64,'全唐诗/poet.tang.11000.json','["冬至至後日初長，遠在劒南思洛陽。", "青袍白馬有何意，金谷銅駝非故鄉。", "梅花欲開不自覺，棣蕚一別永相望。", "愁極本憑詩遣興，詩成吟詠轉淒涼。"]'),
('0b722208-9e02-4dac-9ec5-979859eea818','正月三日歸溪上有作簡院內諸公','杜甫','唐','唐诗','tang','','[]','野外堂依竹，籬邊水向城。',48,'全唐诗/poet.tang.11000.json','["野外堂依竹，籬邊水向城。", "蟻浮仍臘味，鷗泛已春聲。", "藥許隣人劚，書從稚子擎。", "白頭趨幕府，深覺負平生。"]'),
('467b678a-283e-40bd-831c-a90532233f85','弊廬遣興奉寄嚴公','杜甫','唐','唐诗','tang','','[]','野水平橋路，春沙映竹村。',72,'全唐诗/poet.tang.11000.json','["野水平橋路，春沙映竹村。", "風輕粉蝶喜，花暖蜜蜂喧。", "把酒宜深酌，題詩好細論。", "府中瞻暇日，江上憶詞源。", "跡忝朝廷舊，情依節制尊。", "還思長者轍，恐避席爲門。"]'),
('3d2b033b-eceb-4425-a345-7116bcdb2f5a','春日江村五首 一','杜甫','唐','唐诗','tang','','[]','農務村村急，春流岸岸深。',48,'全唐诗/poet.tang.11000.json','["農務村村急，春流岸岸深。", "乾坤萬里眼，時序百年心。", "茅屋還堪賦，桃源自可尋。", "艱難賤生理，飄泊到如今。"]'),
('c9dd1e11-5396-498a-a228-9afeb720dc41','春日江村五首 二','杜甫','唐','唐诗','tang','','[]','迢遞來三蜀，蹉跎有六年。',48,'全唐诗/poet.tang.11000.json','["迢遞來三蜀，蹉跎有六年。", "客身逢故舊，發興自林泉。", "過懶從衣結，頻遊任履穿。", "藩籬無限景，恣意買江天。"]'),
('c8928378-7719-4940-a9b9-848d78b21d5b','春日江村五首 三','杜甫','唐','唐诗','tang','','[]','種竹交加翠，栽桃爛熳紅。',48,'全唐诗/poet.tang.11000.json','["種竹交加翠，栽桃爛熳紅。", "經心石鏡月，到面雪山風。", "赤管隨王命，銀章付老翁。", "豈知牙齒落，名玷薦賢中。"]'),
('22063a2e-01e8-4550-ade4-56e43fe96672','春日江村五首 四','杜甫','唐','唐诗','tang','','[]','扶病垂朱紱，歸休步紫苔。',48,'全唐诗/poet.tang.11000.json','["扶病垂朱紱，歸休步紫苔。", "郊扉存晚計，幕府媿羣材。", "燕外晴絲卷，鷗邊水葉開。", "隣家送魚鼈，問我數能來。"]'),
('81144889-f17a-4590-bbeb-5a9fdb7fcf4d','春日江村五首 五','杜甫','唐','唐诗','tang','','[]','羣盜哀王粲，中年召賈生。',48,'全唐诗/poet.tang.11000.json','["羣盜哀王粲，中年召賈生。", "登樓初有作，前席竟爲榮。", "宅入先賢傳，才高處士名。", "異時懷二子，春日復含情。"]'),
('8379509c-ec9d-4644-9da0-80007c6acfa5','絕句六首 一','杜甫','唐','唐诗','tang','','[]','日出籬東水，雲生舍北泥。',24,'全唐诗/poet.tang.11000.json','["日出籬東水，雲生舍北泥。", "竹高鳴翡翠，沙僻舞鵾雞。"]'),
('7c544b70-ded0-42f3-9bd0-2a5d8e9bb537','絕句六首 二','杜甫','唐','唐诗','tang','','[]','藹藹花蘂亂，飛飛蜂蝶多。',24,'全唐诗/poet.tang.11000.json','["藹藹花蘂亂，飛飛蜂蝶多。", "幽棲身懶動，客至欲如何。"]'),
('9edc47c9-17a3-4552-adcf-ebe56de05289','絕句六首 三','杜甫','唐','唐诗','tang','','[]','鑿井交椶葉，開渠斷竹根。',24,'全唐诗/poet.tang.11000.json','["鑿井交椶葉，開渠斷竹根。", "扁舟輕褭纜，小徑曲通村。"]'),
('3ed2c62d-92af-4ff1-b54e-f8eea706be9b','絕句六首 四','杜甫','唐','唐诗','tang','','[]','急雨捎溪足，斜暉轉樹腰。',24,'全唐诗/poet.tang.11000.json','["急雨捎溪足，斜暉轉樹腰。", "隔巢黃鳥竝，翻藻白魚跳。"]'),
('3905360b-f2f9-49ac-8bee-2b3081665a8a','絕句六首 五','杜甫','唐','唐诗','tang','','[]','舍下笋穿壁，庭中藤刺簷。',24,'全唐诗/poet.tang.11000.json','["舍下笋穿壁，庭中藤刺簷。", "地晴絲冉冉，江白草纖纖。"]'),
('e50791c1-e9ee-4e3f-bc49-1bab0654b7f5','絕句六首 六','杜甫','唐','唐诗','tang','','[]','江動月移石，溪虛雲傍花。',24,'全唐诗/poet.tang.11000.json','["江動月移石，溪虛雲傍花。", "鳥棲知故道，帆過宿誰家。"]'),
('7d59bd22-bdfc-4105-9379-3be27dab92da','絕句四首 一','杜甫','唐','唐诗','tang','','[]','堂西長笋別開門，塹北行椒却背村。',32,'全唐诗/poet.tang.11000.json','["堂西長笋別開門，塹北行椒却背村。", "梅熟許同朱老喫，松高擬對阮生論。"]'),
('23a057b3-7f46-441b-855a-2182a3402d5f','絕句四首 二','杜甫','唐','唐诗','tang','','[]','欲作魚梁雲復湍，因驚四月雨聲寒。',32,'全唐诗/poet.tang.11000.json','["欲作魚梁雲復湍，因驚四月雨聲寒。", "青溪先有蛟龍窟，竹石如山不敢安。"]'),
('abf4daf0-0c7b-4b0c-87a2-2c48097d6a65','絕句四首 三','杜甫','唐','唐诗','tang','','["\u5199\u96ea", "\u6625", "\u5199\u666f", "\u96ea", "\u4e8c\u5e74\u7ea7\u4e0b\u518c", "\u5199\u9e1f"]','兩箇黃鸝鳴翠柳，一行白鷺上青天。',32,'全唐诗/poet.tang.11000.json','["兩箇黃鸝鳴翠柳，一行白鷺上青天。", "窗含西嶺千秋雪，門泊東吳萬里船。"]'),
('4e5de1b6-c28a-4201-b8cb-a1072c618eae','絕句四首 四','杜甫','唐','唐诗','tang','','[]','藥條藥甲潤青青，色過棕亭入草亭。',32,'全唐诗/poet.tang.11000.json','["藥條藥甲潤青青，色過棕亭入草亭。", "苗滿空山慙取譽，根居隙地怯成形。"]'),
('91a20b44-5212-4aad-9948-95708855ba5a','哭嚴僕射歸櫬','杜甫','唐','唐诗','tang','','[]','素幔隨流水，歸舟返舊京。',48,'全唐诗/poet.tang.11000.json','["素幔隨流水，歸舟返舊京。", "老親如宿昔，部曲異平生。", "風送蛟龍雨，天長驃騎營。", "一哀三峽暮，遺後見君情。"]'),
('c57d32a1-4b7d-4827-9b1f-cd8077a3604f','宴戎州楊使君東樓','杜甫','唐','唐诗','tang','','[]','勝絕驚身老，情忘發興奇。',48,'全唐诗/poet.tang.11000.json','["勝絕驚身老，情忘發興奇。", "座從歌妓密，樂任主人爲。", "重碧拈春酒，輕紅擘荔枝。", "樓高欲愁思，橫笛未休吹。"]'),
('d7c5694c-6914-48bc-97ae-7c2d99bf7e07','渝州候嚴六侍御不到先下峽','杜甫','唐','唐诗','tang','','[]','聞道乘驄發，沙邊待至今。',48,'全唐诗/poet.tang.11000.json','["聞道乘驄發，沙邊待至今。", "不知雲雨散，虛費短長吟。", "山帶烏蠻闊，江連白帝深。", "船經一柱觀，留眼共登臨。"]'),
('1091cece-e986-4808-af31-676ce83a1083','撥悶','杜甫','唐','唐诗','tang','','[]','聞道雲安麴米春，纔傾一醆即醺人。',64,'全唐诗/poet.tang.11000.json','["聞道雲安麴米春，纔傾一醆即醺人。", "乘舟取醉非難事，下峽消愁定幾巡。", "長年三老遙憐汝，棙柁開頭捷有神。", "已辦青錢防雇直，當令美味入吾脣。"]'),
('5d0a7058-2f6e-44ac-abe0-e04a56a1a694','聞高常侍亡','杜甫','唐','唐诗','tang','','[]','歸朝不相見，蜀使忽傳亡。',48,'全唐诗/poet.tang.11000.json','["歸朝不相見，蜀使忽傳亡。", "虛歷金華省，何殊地下郎。", "致君丹檻折，哭友白雲長。", "獨步詩名在，秪令故舊傷。"]'),
('96d17152-8094-4bb1-bfad-079daf16d81b','宴忠州使君姪宅','杜甫','唐','唐诗','tang','','[]','出守吾家姪，殊方此日歡。',48,'全唐诗/poet.tang.11000.json','["出守吾家姪，殊方此日歡。", "自須遊阮巷，不是怕湖灘。", "樂助長歌逸，杯饒旅思寬。", "昔曾如意舞，牽率強爲看。"]'),
('c9fb2949-5ca8-4ac5-a00a-c35b190d3881','禹廟','杜甫','唐','唐诗','tang','','["\u548f\u7269\u8bd7", "\u968b\u30fb\u5510\u30fb\u4e94\u4ee3", "\u548f\u7269"]','禹廟空山裏，秋風落日斜。',48,'全唐诗/poet.tang.11000.json','["禹廟空山裏，秋風落日斜。", "荒庭垂橘柚，古屋畫龍蛇。", "雲氣生虛壁，江聲走白沙。", "早知乘四載，疏鑿控三巴。"]'),
('ddcca940-28ef-4cc4-b493-d692dc423aee','題忠州龍興寺所居院壁','杜甫','唐','唐诗','tang','','[]','忠州三峽內，井邑聚雲根。',48,'全唐诗/poet.tang.11000.json','["忠州三峽內，井邑聚雲根。", "小市常爭米，孤城早閉門。", "空看過客淚，莫覓主人恩。", "淹泊仍愁虎，深居賴獨園。"]'),
('f96506ea-e8ac-47e0-a0a6-ccd306e56645','旅夜書懷','杜甫','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u5199\u666f", "\u5b64\u72ec", "\u6292\u6000", "\u4e94\u8a00\u5f8b\u8bd7"]','細草微風岸，危檣獨夜舟。',48,'全唐诗/poet.tang.11000.json','["細草微風岸，危檣獨夜舟。", "星垂平野闊，月湧大江流。", "名豈文章著，官因老病休。", "飄飄何所似，天地一沙鷗。"]'),
('a08a9f3c-8345-4aa6-b0ee-ac8be76a1d93','別常徵君','杜甫','唐','唐诗','tang','','[]','兒扶猶杖策，臥病一秋強。',48,'全唐诗/poet.tang.11000.json','["兒扶猶杖策，臥病一秋強。", "白髮少新洗，寒衣寬總長。", "故人憂見及，此別淚相忘。", "各逐萍流轉，來書細作行。"]'),
('2024061f-63cc-4adf-b3bc-b321eb7d282e','三絕句 一','杜甫','唐','唐诗','tang','','[]','前年渝州殺刺史，今年開州殺刺史。',32,'全唐诗/poet.tang.11000.json','["前年渝州殺刺史，今年開州殺刺史。", "羣盜相隨劇虎狼，食人更肯留妻子。"]'),
('ce14cdf4-17a0-4a0f-b49e-cec74b99d7c1','三絕句 二','杜甫','唐','唐诗','tang','','[]','二十一家同入蜀，惟殘一人出駱谷。',32,'全唐诗/poet.tang.11000.json','["二十一家同入蜀，惟殘一人出駱谷。", "自說二女齧臂時，回頭却向秦雲哭。"]'),
('bff9cf4e-3d22-4ca6-a7e8-54ebd99fccb0','三絕句 三','杜甫','唐','唐诗','tang','','[]','殿前兵馬雖驍雄，縱暴略與羌渾同。',32,'全唐诗/poet.tang.11000.json','["殿前兵馬雖驍雄，縱暴略與羌渾同。", "聞道殺人漢水上，婦女多在官軍中。"]'),
('c48a84c4-9481-4d6a-8f18-b7890f940d88','十二月一日三首 一','杜甫','唐','唐诗','tang','','[]','今朝臘月春意動，雲安縣前江可憐。',64,'全唐诗/poet.tang.11000.json','["今朝臘月春意動，雲安縣前江可憐。", "一聲何處送書鴈，百丈誰家上水船。", "未將梅蘂驚愁眼，要取楸花媚遠天。", "明光起草人所羨，肺病幾時朝日邊。"]'),
('989669f3-7208-4452-b8b1-bc7e258a74be','十二月一日三首 二','杜甫','唐','唐诗','tang','','[]','寒輕市上山煙碧，日滿樓前江霧黃。',64,'全唐诗/poet.tang.11000.json','["寒輕市上山煙碧，日滿樓前江霧黃。", "負鹽出井此谿女，打鼓發船何郡郎。", "新亭舉目風景切，茂陵著書消渴長。", "春花不愁不爛漫，楚客唯聽棹相將。"]'),
('0ed35d16-2972-44be-beb9-cc6d586ab0f2','十二月一日三首 三','杜甫','唐','唐诗','tang','','[]','即看燕子入山扉，豈有黃鸝歷翠微。',64,'全唐诗/poet.tang.11000.json','["即看燕子入山扉，豈有黃鸝歷翠微。", "短短桃花臨水岸，輕輕柳絮點人衣。", "春來準擬開懷久，老去親知見面稀。", "他日一杯難強進，重嗟筋力故山違。"]'),
('49577c84-9adc-4983-96ef-81d474492aa9','又雪','杜甫','唐','唐诗','tang','','[]','南雪不到地，青崖霑未消。',48,'全唐诗/poet.tang.11000.json','["南雪不到地，青崖霑未消。", "微微向日薄，脈脈去人遙。", "冬熱鴛鴦病，峽深豺虎驕。", "愁邊有江水，焉得北之朝。"]'),
('a8603405-d351-470e-9a35-421734940554','奉漢中王手札','杜甫','唐','唐诗','tang','','[]','國有乾坤大，王今叔父尊。',168,'全唐诗/poet.tang.11000.json','["國有乾坤大，王今叔父尊。", "剖符來蜀道，歸蓋取荆門。", "峽險通舟過，江長注海奔。", "主人留上客，避暑得名園。", "前後緘書報，分明饌玉恩。", "天雲浮絕壁，風竹在華軒。", "已覺良宵永，何看駭浪翻。", "入期朱邸雪，朝傍紫微垣。", "枚乘文章老，河間禮樂存。", "悲秋宋玉宅，失路武陵源。", "淹薄俱崖口，東西異石根。", "夷音迷咫尺，鬼物傍黃昏。", "犬馬誠爲戀，狐貍不足論。", "從容草奏罷，宿昔奉清罇。"]'),
('5ac1b352-d7b5-4be4-bf0d-2b3f0935e340','贈崔十三評事公輔','杜甫','唐','唐诗','tang','','[]','飄飄西極馬，來自渥洼池。',240,'全唐诗/poet.tang.11000.json','["飄飄西極馬，來自渥洼池。", "颯飁定山桂，低徊風雨枝。", "我聞龍正直，道屈爾何爲。", "且有元戎命，悲歌識者誰。", "官聯辭宂長，行路洗欹危。", "脫劒主人贈，去帆春色隨。", "陰沈鐵鳳闕，教練羽林兒。", "天子朝侵早，雲臺仗數移。", "分軍應供給，百姓日支離。", "黠吏因封己，公才或守雌。", "燕王買駿骨，渭老得熊羆。", "活國名公在，拜壇羣寇疑。", "冰壺動瑤碧，野水失蛟螭。", "入幕諸彥集，渴賢高選宜。", "騫騰坐可致，九萬起於斯。", "復進出矛戟，昭然開鼎彝。", "會看之子貴，歎及老夫衰。", "豈但江曾決，還思霧一披。", "暗塵生古鏡，拂匣照西施。", "舅氏多人物，無慙困翮垂。"]'),
('22624fe3-d419-451c-81e0-51d4be56e014','長江二首 一','杜甫','唐','唐诗','tang','','["\u957f\u6c5f"]','衆水會涪萬，瞿塘爭一門。',48,'全唐诗/poet.tang.11000.json','["衆水會涪萬，瞿塘爭一門。", "朝宗人共挹，盜賊爾誰尊。", "孤石隱如馬，高蘿垂飲猨。", "歸心異波浪，何事即飛飜。"]'),
('5b7bdb65-ec29-4ebe-b698-19a2f60498df','長江二首 二','杜甫','唐','唐诗','tang','','["\u957f\u6c5f"]','浩浩終不息，乃知東極臨。',48,'全唐诗/poet.tang.11000.json','["浩浩終不息，乃知東極臨。", "衆流歸海意，萬國奉君心。", "色借瀟湘闊，聲驅灧澦深。", "未辭添霧雨，接上遇衣襟。"]'),
('e03aea9d-c2c8-4fce-bfd4-93d0aa46960b','承聞故房相公靈櫬自閬州啓殯歸葬東都有作二首 一','杜甫','唐','唐诗','tang','','[]','遠聞房太守，歸葬陸渾山。',48,'全唐诗/poet.tang.11000.json','["遠聞房太守，歸葬陸渾山。", "一德興王後，孤魂久客間。", "孔明多故事，安石竟崇班。", "他日嘉陵涕，仍沾楚水還。"]'),
('3fd1ccca-7ddb-41ec-9627-8a093b3f5721','承聞故房相公靈櫬自閬州啓殯歸葬東都有作二首 二','杜甫','唐','唐诗','tang','','[]','丹旐飛飛日，初傳發閬州。',48,'全唐诗/poet.tang.11000.json','["丹旐飛飛日，初傳發閬州。", "風塵終不解，江漢忽同流。", "劒動新身匣，書歸故國樓。", "盡哀知有處，爲客恐長休。"]'),
('b3415e02-0a13-47d3-8ba2-e33bc0e079b1','雲安九日鄭十八攜酒陪諸公宴','杜甫','唐','唐诗','tang','','[]','寒花開已盡，菊蘂獨盈枝。',48,'全唐诗/poet.tang.11000.json','["寒花開已盡，菊蘂獨盈枝。", "舊摘人頻異，輕香酒蹔隨。", "地偏初衣裌，山擁更登危。", "萬國皆戎馬，酣歌淚欲垂。"]'),
('52c51321-a3dd-4dfd-998a-af8309e58d77','荅鄭十七郎一絕','杜甫','唐','唐诗','tang','','[]','雨後過畦潤，花殘步屐遲。',24,'全唐诗/poet.tang.11000.json','["雨後過畦潤，花殘步屐遲。", "把文驚小陸，好客見當時。"]'),
('c4d9440e-b2d8-4c43-930b-ba0c5dd68548','將曉二首 一','杜甫','唐','唐诗','tang','','[]','石城除擊柝，鐵鎖欲開關。',48,'全唐诗/poet.tang.11000.json','["石城除擊柝，鐵鎖欲開關。", "鼓角悲荒塞，星河落曙山。", "巴人常小梗，蜀使動無還。", "垂老孤帆色，飄飄犯百蠻。"]'),
('84b3f473-2a29-4cf9-ba9c-11676206d700','將曉二首 二','杜甫','唐','唐诗','tang','','[]','軍吏回官燭，舟人自楚歌。',48,'全唐诗/poet.tang.11000.json','["軍吏回官燭，舟人自楚歌。", "寒沙蒙薄霧，落月去清波。", "壯惜身名晚，衰慙應接多。", "歸朝日簪笏，筋力定如何。"]'),
('6f90e24f-0ed7-4a52-a3cc-afccd7a14933','懷錦水居止二首 一','杜甫','唐','唐诗','tang','','[]','軍旅西征僻，風塵戰伐多。',48,'全唐诗/poet.tang.11000.json','["軍旅西征僻，風塵戰伐多。", "猶聞蜀父老，不忘舜謳歌。", "天險終難立，柴門豈重過。", "朝朝巫峽水，遠逗錦江波。"]'),
('2908cc58-a479-4472-a5b8-d81f874d14f3','懷錦水居止二首 二','杜甫','唐','唐诗','tang','','[]','萬里橋南宅，百花潭北莊。',48,'全唐诗/poet.tang.11000.json','["萬里橋南宅，百花潭北莊。", "層軒皆面水，老樹飽經霜。", "雪嶺界天白，錦城曛日黃。", "惜哉形勝地，回首一茫茫。"]'),
('4168a793-7936-473c-8a83-e72796a70469','子規','杜甫','唐','唐诗','tang','','[]','峽裏雲安縣，江樓翼瓦齊。',48,'全唐诗/poet.tang.11000.json','["峽裏雲安縣，江樓翼瓦齊。", "兩邊山木合，終日子規啼。", "眇眇春風見，蕭蕭夜色淒。", "客愁那聽此，故作傍人低。"]'),
('240b5111-54b8-466d-9b35-d5206013dcd1','立春','杜甫','唐','唐诗','tang','','[]','春日春盤細生菜，忽憶兩京梅發時。',64,'全唐诗/poet.tang.11000.json','["春日春盤細生菜，忽憶兩京梅發時。", "盤出高門行白玉，菜傳纖手送青絲。", "巫峽寒江那對眼，杜陵遠客不勝悲。", "此身未知歸定處，呼兒覓紙一題詩。"]'),
('52b90e6f-c015-4833-bed8-40d2092a3d35','漫成一絕','杜甫','唐','唐诗','tang','','[]','江月去人只數尺，風燈照夜欲三更。',32,'全唐诗/poet.tang.11000.json','["江月去人只數尺，風燈照夜欲三更。", "沙頭宿鷺聯拳靜，船尾跳魚撥刺鳴。"]'),
('642f5dc6-0c6f-4964-b64e-f4445b079109','老病','杜甫','唐','唐诗','tang','','[]','老病巫山裏，稽留楚客中。',48,'全唐诗/poet.tang.11000.json','["老病巫山裏，稽留楚客中。", "藥殘他日裹，花發去年叢。", "夜足霑沙雨，春多逆水風。", "合分雙賜筆，猶作一飄蓬。"]'),
('191c54af-8c42-40be-b931-db22b2e46c06','南楚','杜甫','唐','唐诗','tang','','[]','南楚青春異，暄寒早早分。',48,'全唐诗/poet.tang.11000.json','["南楚青春異，暄寒早早分。", "無名江上草，隨意嶺頭雲。", "正月蜂相見，非時鳥共聞。", "杖藜妨躍馬，不是故離羣。"]'),
('18101e75-88aa-4533-821f-438d99ceecdf','寄常徵君','杜甫','唐','唐诗','tang','','[]','白水青山空復春，徵君晚節傍風塵。',64,'全唐诗/poet.tang.11000.json','["白水青山空復春，徵君晚節傍風塵。", "楚妃堂上色殊衆，海鶴階前鳴向人。", "萬事糾紛猶絕粒，一官羇絆實藏身。", "開州入夏知涼冷，不似雲安毒熱新。"]'),
('510af400-6dc4-4fdd-a6a1-29645ea01164','寄岑嘉州','杜甫','唐','唐诗','tang','','[]','不見故人十年餘，不道故人無素書。',96,'全唐诗/poet.tang.11000.json','["不見故人十年餘，不道故人無素書。", "願逢顏色關塞遠，豈意出守江城居。", "外江三峽且相接，斗酒新詩終日疎。", "謝朓每篇堪諷誦，馮唐已老聽吹噓。", "泊船秋夜經春草，伏枕青楓限玉除。", "眼前所寄選何物，贈子雲安雙鯉魚。"]'),
('d190d386-7eeb-4e0d-8421-7ebf0cf9fa85','移居夔州郭','杜甫','唐','唐诗','tang','','[]','伏枕雲安縣，遷居白帝城。',48,'全唐诗/poet.tang.11000.json','["伏枕雲安縣，遷居白帝城。", "春知催柳別，江與放船清。", "農事聞人說，山光見鳥情。", "禹功饒斷石，且就土微平。"]'),
('6ee869b1-4f09-431c-9438-cf5a2e75d34b','船下夔州郭宿雨濕不得上岸別王十二判官','杜甫','唐','唐诗','tang','','["\u79bb\u522b", "\u53cb\u4eba"]','依沙宿舸船，石瀨月娟娟。',48,'全唐诗/poet.tang.11000.json','["依沙宿舸船，石瀨月娟娟。", "風起春燈亂，江鳴夜雨懸。", "晨鐘雲外濕，勝地石堂煙。", "柔櫓輕鷗外，含悽覺汝賢。"]'),
('5cd5c586-f560-4a72-acea-f2674561aabb','雨不絕','杜甫','唐','唐诗','tang','','["\u5199\u96e8", "\u96e8", "\u548f\u7269", "\u548f\u7269\u8bd7"]','鳴雨既過漸細微，映空搖颺如絲飛。',64,'全唐诗/poet.tang.11000.json','["鳴雨既過漸細微，映空搖颺如絲飛。", "階前短草泥不亂，院裏長條風乍稀。", "舞石旋應將乳子，行雲莫自濕仙衣。", "眼邊江舸何怱促，未待安流逆浪歸。"]'),
('d86d1df4-dba7-4ef2-9efc-9111c80ae92e','崔評事弟許相迎不到應慮老夫見泥雨怯出必愆佳期走筆戲簡','杜甫','唐','唐诗','tang','','[]','江閣要賓許馬迎，午時起坐自天明。',64,'全唐诗/poet.tang.11000.json','["江閣要賓許馬迎，午時起坐自天明。", "浮雲不負青春色，細雨何孤白帝城。", "身過花間霑濕好，醉於馬上往來輕。", "虛疑皓首衝泥怯，實少銀鞍傍險行。"]'),
('5564daec-7353-412f-8979-50a31cfc7339','宿江邊閣','杜甫','唐','唐诗','tang','','["\u5fe7\u56fd\u5fe7\u6c11", "\u5199\u666f"]','暝色延山徑，高齋次水門。',48,'全唐诗/poet.tang.11000.json','["暝色延山徑，高齋次水門。", "薄雲巖際宿，孤月浪中飜。", "鸛鶴追飛靜，豺狼得食喧。", "不眠憂戰伐，無力正乾坤。"]'),
('d1ad17df-2a5c-4f93-af23-b66893e495f3','夜宿西閣曉呈元二十一曹長','杜甫','唐','唐诗','tang','','[]','城暗更籌急，樓高雨雪微。',48,'全唐诗/poet.tang.11000.json','["城暗更籌急，樓高雨雪微。", "稍通綃幕霽，遠帶玉繩稀。", "門鵲晨光起，牆烏宿處飛。", "寒江流甚細，有意待人歸。"]'),
('134597c9-e2f1-42cc-9891-d201d5fb542c','西閣口號','杜甫','唐','唐诗','tang','','[]','山木抱雲稠，寒江繞上頭。',48,'全唐诗/poet.tang.11000.json','["山木抱雲稠，寒江繞上頭。", "雪崖纔變石，風幔不依樓。", "社稷堪流涕，安危在運籌。", "看君話王室，感動幾銷憂。"]'),
('e6313a11-5990-45ec-8dc7-2cffd50ede93','西閣雨望','杜甫','唐','唐诗','tang','','[]','樓雨霑雲幔，山寒著水城。',48,'全唐诗/poet.tang.11000.json','["樓雨霑雲幔，山寒著水城。", "徑添沙面出，湍減石稜生。", "菊蘂淒疎放，松林駐遠情。", "滂沱朱檻濕，萬慮傍簷楹。"]'),
('d1194ad8-9977-44bd-b1a2-235eab904fa4','不離西閣二首 一','杜甫','唐','唐诗','tang','','[]','江柳非時發，江花冷色頻。',48,'全唐诗/poet.tang.11000.json','["江柳非時發，江花冷色頻。", "地偏應有瘴，臘近已含春。", "失學從愚子，無家住老身。", "不知西閣意，肯別定留人。"]'),
('294a2fee-f9ee-4b2b-9442-f15496b6eb8e','不離西閣二首 二','杜甫','唐','唐诗','tang','','[]','西閣從人別，人今亦故亭。',48,'全唐诗/poet.tang.11000.json','["西閣從人別，人今亦故亭。", "江雲飄素練，石壁斷空青。", "滄海先迎日，銀河倒列星。", "平生耽勝事，吁駭始初經。"]'),
('349ea830-2ad3-4b39-9b60-23594d6c57a1','西閣三度期大昌嚴明府同宿不到','杜甫','唐','唐诗','tang','','[]','問子能來宿，今疑索故要。',48,'全唐诗/poet.tang.11000.json','["問子能來宿，今疑索故要。", "匣琴虛夜夜，手板自朝朝。", "金吼霜鐘徹，花催臘炬銷。", "早鳧江檻底，雙影漫飄颻。"]'),
('2e0476ef-0c5f-4789-aa92-26f52da3586f','西閣二首 一','杜甫','唐','唐诗','tang','','[]','巫山小搖落，碧色見松林。',72,'全唐诗/poet.tang.11000.json','["巫山小搖落，碧色見松林。", "百鳥各相命，孤雲無自心。", "層軒俯江壁，要路亦高深。", "朱紱猶紗帽，新詩近玉琴。", "功名不早立，衰病謝知音。", "哀世非王粲，終然學越吟。"]'),
('9eb4426c-cc99-40d4-949a-0574ecc33240','西閣二首 二','杜甫','唐','唐诗','tang','','[]','嬾心似江水，日夜向滄洲。',72,'全唐诗/poet.tang.11000.json','["嬾心似江水，日夜向滄洲。", "不道含香賤，其如鑷白休。", "經過調碧柳，蕭索倚朱樓。", "畢娶何時竟，消中得自由。", "豪華看古往，服食寄冥搜。", "詩盡人間興，兼須入海求。"]'),
('0f5874bf-3748-44c9-bc3a-be4a8c3eb2f6','閣夜','杜甫','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996"]','歲暮陰陽催短景，天涯霜雪霽寒宵。',64,'全唐诗/poet.tang.11000.json','["歲暮陰陽催短景，天涯霜雪霽寒宵。", "五更鼓角聲悲壯，三峽星河影動搖。", "野哭幾家聞戰伐，夷歌數處起漁樵。", "臥龍躍馬終黃土，人事依依漫寂寥。"]'),
('807e27bc-7987-4c96-bbf8-69dbf3149bae','西閣夜','杜甫','唐','唐诗','tang','','[]','恍惚寒山暮，逶迤白霧昏。',48,'全唐诗/poet.tang.11000.json','["恍惚寒山暮，逶迤白霧昏。", "山虛風落石，樓靜月侵門。", "擊柝可憐子，無衣何處村。", "時危關百慮，盜賊爾猶存。"]'),
('6ba0521b-3a2e-4c50-bce8-06bc4f512685','瀼西寒望','杜甫','唐','唐诗','tang','','[]','水色含羣動，朝光切太虛。',48,'全唐诗/poet.tang.11000.json','["水色含羣動，朝光切太虛。", "年侵頻悵望，興遠一蕭疎。", "猨挂時相學，鷗行炯自如。", "瞿唐春欲至，定卜瀼西居。"]'),
('ffcf04ad-885a-4f9e-89c3-df5eb7eb7d75','入宅三首 一','杜甫','唐','唐诗','tang','','[]','奔峭背赤甲，斷崖當白鹽。',48,'全唐诗/poet.tang.11000.json','["奔峭背赤甲，斷崖當白鹽。", "客居愧遷次，春酒漸多添。", "花亞欲移竹，鳥窺新捲簾。", "衰年不敢恨，勝概欲相兼。"]'),
('9098a316-70d2-41df-8018-5a18e82a8cfb','入宅三首 二','杜甫','唐','唐诗','tang','','[]','亂後居難定，春歸客未還。',48,'全唐诗/poet.tang.11000.json','["亂後居難定，春歸客未還。", "水生魚復浦，雲暖麝香山。", "半頂梳頭白，過眉拄杖斑。", "相看多使者，一一問函關。"]'),
('79c0662e-6dc6-4146-80bd-c0eee78dc0b4','入宅三首 三','杜甫','唐','唐诗','tang','','[]','宋玉歸州宅，雲通白帝城。',48,'全唐诗/poet.tang.11000.json','["宋玉歸州宅，雲通白帝城。", "吾人淹老病，旅食豈才名。", "峽口風常急，江流氣不平。", "只應與兒子，飄轉任浮生。"]'),
('e199059f-0155-4650-bd27-2048062f8d10','赤甲','杜甫','唐','唐诗','tang','','[]','卜居赤甲遷居新，兩見巫山楚水春。',64,'全唐诗/poet.tang.11000.json','["卜居赤甲遷居新，兩見巫山楚水春。", "炙背可以獻天子，美芹由來知野人。", "荆州鄭薛寄書近，蜀客郗岑非我鄰。", "笑接郎中評事飲，病從深酌道吾真。"]'),
('bbcd3acf-f256-4ea4-9ba3-dff2f0727a2c','卜居','杜甫','唐','唐诗','tang','','[]','歸羨遼東鶴，吟同楚執珪。',48,'全唐诗/poet.tang.11000.json','["歸羨遼東鶴，吟同楚執珪。", "未成遊碧海，著處覓丹梯。", "雲障寬江左，春耕破瀼西。", "桃紅客若至，定似昔人迷。"]'),
('95ecb516-eef9-4ab8-b4aa-091c84aba40d','暮春題瀼西新賃草屋五首 一','杜甫','唐','唐诗','tang','','[]','久嗟三峽客，再與暮春期。',48,'全唐诗/poet.tang.11000.json','["久嗟三峽客，再與暮春期。", "百舌欲無語，繁花能幾時。", "谷虛雲氣薄，波亂日華遲。", "戰伐何由定，哀傷不在茲。"]'),
('3b810d01-f954-481f-8b2c-4aef51904c75','暮春題瀼西新賃草屋五首 二','杜甫','唐','唐诗','tang','','[]','此邦千樹橘，不見比封君。',48,'全唐诗/poet.tang.11000.json','["此邦千樹橘，不見比封君。", "養拙干戈際，全生麋鹿羣。", "畏人江北草，旅食瀼西雲。", "萬里巴渝曲，三年實飽聞。"]'),
('b3e78cdb-4a2b-439c-99da-34b466fe138e','暮春題瀼西新賃草屋五首 三','杜甫','唐','唐诗','tang','','[]','綵雲陰復白，錦樹曉來青。',48,'全唐诗/poet.tang.11000.json','["綵雲陰復白，錦樹曉來青。", "身世雙蓬鬢，乾坤一草亭。", "哀歌時自短，醉舞爲誰醒。", "細雨荷鋤立，江猨吟翠屏。"]'),
('590b9fa1-2f29-41fa-8b37-4c9869e7ec1a','暮春題瀼西新賃草屋五首 四','杜甫','唐','唐诗','tang','','[]','壯年學書劒，他日委泥沙。',48,'全唐诗/poet.tang.11000.json','["壯年學書劒，他日委泥沙。", "事主非無祿，浮生即有涯。", "高齋依藥餌，絕域改春華。", "喪亂丹心破，王臣未一家。"]'),
('8393ea07-5a6e-4f70-892c-8130b54b519e','暮春題瀼西新賃草屋五首 五','杜甫','唐','唐诗','tang','','[]','欲陳濟世策，已老尚書郎。',48,'全唐诗/poet.tang.11000.json','["欲陳濟世策，已老尚書郎。", "未息豺虎鬬，空慙鴛鷺行。", "時危人事急，風逆羽毛傷。", "落日悲江漢，中宵淚滿床。"]'),
('b42248d6-0235-4179-ab4a-2b708eff1301','園','杜甫','唐','唐诗','tang','','[]','仲夏流多水，清晨向小園。',48,'全唐诗/poet.tang.11000.json','["仲夏流多水，清晨向小園。", "碧溪搖艇闊，朱果爛枝繁。", "始爲江山靜，終防市井喧。", "畦蔬繞茅屋，自足媚盤餐。"]'),
('1884cc1c-33fb-4783-bff3-557671719651','豎子至','杜甫','唐','唐诗','tang','','[]','樝梨且綴碧，梅杏半傳黃。',48,'全唐诗/poet.tang.11000.json','["樝梨且綴碧，梅杏半傳黃。", "小子幽園至，輕籠熟柰香。", "山風猶滿把，野露及新嘗。", "欲寄江湖客，提攜日月長。"]'),
('0708f21e-7b95-47f4-9115-18c7f4904786','示獠奴阿段','杜甫','唐','唐诗','tang','','[]','山木蒼蒼落日曛，竹竿褭褭細泉分。',64,'全唐诗/poet.tang.11000.json','["山木蒼蒼落日曛，竹竿褭褭細泉分。", "郡人入夜爭餘瀝，豎子尋源獨不聞。", "病渴三更迴白首，傳聲一注濕青雲。", "曾驚陶侃胡奴異，怪爾常穿虎豹羣。"]'),
('8e1e7b7e-1824-402a-8ef1-ada1b0490f58','秋野五首 一','杜甫','唐','唐诗','tang','','[]','秋野日疏蕪，寒江動碧虛。',48,'全唐诗/poet.tang.11000.json','["秋野日疏蕪，寒江動碧虛。", "繫舟蠻井絡，卜宅楚村墟。", "棗熟從人打，葵荒欲自鋤。", "盤餐老夫食，分減及溪魚。"]'),
('948aee1f-c5d9-47f3-949a-932f22ac79ba','秋野五首 二','杜甫','唐','唐诗','tang','','[]','易識浮生理，難教一物違。',48,'全唐诗/poet.tang.11000.json','["易識浮生理，難教一物違。", "水深魚極樂，林茂鳥知歸。", "吾老甘貧病，榮華有是非。", "秋風吹几杖，不厭此山薇。"]'),
('698d613c-197c-4967-a0d1-c1d7a19e4858','秋野五首 三','杜甫','唐','唐诗','tang','','[]','禮樂攻吾短，山林引興長。',48,'全唐诗/poet.tang.11000.json','["禮樂攻吾短，山林引興長。", "掉頭紗帽仄，曝背竹書光。", "風落收松子，天寒割蜜房。", "稀疎小紅翠，駐屐近微香。"]'),
('e3c69461-79e6-4754-a486-e165cef8606b','秋野五首 四','杜甫','唐','唐诗','tang','','[]','遠岸秋沙白，連山晚照紅。',48,'全唐诗/poet.tang.11000.json','["遠岸秋沙白，連山晚照紅。", "潛鱗輸駭浪，歸翼會高風。", "砧響家家發，樵聲箇箇同。", "飛霜任青女，賜被隔南宮。"]'),
('9e10394a-b2cf-4f84-a07c-2b1103966824','秋野五首 五','杜甫','唐','唐诗','tang','','[]','身許麒膦畫，年衰鴛鷺羣。',48,'全唐诗/poet.tang.11000.json','["身許麒膦畫，年衰鴛鷺羣。", "大江秋易盛，空峽夜多聞。", "徑隱千重石，帆留一片雲。", "兒童解蠻語，不必作參軍。"]'),
('7202af23-2063-4556-be72-f887f5688d3f','溪上','杜甫','唐','唐诗','tang','','[]','峽內淹留客，溪邊四五家。',48,'全唐诗/poet.tang.11000.json','["峽內淹留客，溪邊四五家。", "古苔生迮地，秋竹隱疎花。", "塞俗人無井，山田飯有沙。", "西江使船至，時復問京華。"]'),
('69982aff-b3db-4650-b28f-5b89ff6695a6','樹間','杜甫','唐','唐诗','tang','','[]','岑寂雙甘樹，婆娑一院香。',48,'全唐诗/poet.tang.11000.json','["岑寂雙甘樹，婆娑一院香。", "交柯低几杖，垂實礙衣裳。", "滿歲如松碧，同時待菊黃。", "幾迴霑葉露，乘月坐胡牀。"]'),
('36f359c3-d3d9-4b65-ba49-a281cb8d8ec1','課小豎鉏斫舍北果林枝蔓荒穢淨訖移牀三首 一','杜甫','唐','唐诗','tang','','[]','病枕依茅棟，荒鉏淨果林。',48,'全唐诗/poet.tang.11000.json','["病枕依茅棟，荒鉏淨果林。", "背堂資僻遠，在野興清深。", "山雉防求敵，江猨應獨吟。", "洩雲高不去，隱几亦無心。"]'),
('98275391-c590-4fd1-ae91-3641fa8c4756','課小豎鉏斫舍北果林枝蔓荒穢淨訖移牀三首 二','杜甫','唐','唐诗','tang','','[]','衆壑生寒早，長林卷霧齊。',48,'全唐诗/poet.tang.11000.json','["衆壑生寒早，長林卷霧齊。", "青蟲懸就日，朱果落封泥。", "薄俗防人面，全身學馬蹄。", "吟詩坐迴首，隨意葛巾低。"]'),
('f13724b6-6cd7-4c38-bdae-aa29c39b29c5','課小豎鉏斫舍北果林枝蔓荒穢淨訖移牀三首 三','杜甫','唐','唐诗','tang','','[]','籬弱門何向，沙虛岸只摧。',48,'全唐诗/poet.tang.11000.json','["籬弱門何向，沙虛岸只摧。", "日斜魚更食，客散鳥還來。", "寒水光難定，秋山響易哀。", "天涯稍曛黑，倚杖更裴回。"]'),
('0e2cf65b-d757-4698-97a0-31aedb02f4a3','寒雨朝行視園樹','杜甫','唐','唐诗','tang','','[]','柴門雜樹向千株，丹橘黃甘此地無。',128,'全唐诗/poet.tang.11000.json','["柴門雜樹向千株，丹橘黃甘此地無。", "江上今朝寒雨歇，籬中秀色畫屏紆。", "桃蹊李徑年雖故，梔子紅椒豔復殊。", "鏁石藤稍元自落，倚天松骨見來枯。", "林香出實垂將盡，葉蔕辭枝不重蘇。", "愛日恩光蒙借貸，清霜殺氣得憂虞。", "衰顏更覓藜床坐，緩步仍須竹杖扶。", "散騎未知雲閣處，啼猨僻在楚山隅。"]'),
('14e71d5c-ff47-4b86-b37f-f79cbfbc4796','季秋江村','杜甫','唐','唐诗','tang','','[]','喬木村墟古，疎籬野蔓懸。',48,'全唐诗/poet.tang.11000.json','["喬木村墟古，疎籬野蔓懸。", "清琴將暇日，白首望霜天。", "登俎黃甘重，支床錦石圓。", "遠遊雖寂寞，難見此山川。"]'),
('adb07ed0-a56b-49e6-8ec5-16df727f2c65','小園','杜甫','唐','唐诗','tang','','[]','由來巫峽水，本自楚人家。',48,'全唐诗/poet.tang.11000.json','["由來巫峽水，本自楚人家。", "客病留因藥，春深買爲花。", "秋庭風落果，瀼岸雨頹沙。", "問俗營寒事，將詩待物華。"]'),
('100902e0-ed47-4a70-a85f-05e9bb4e3ca5','自瀼西荆扉且移居東屯茅屋四首 一','杜甫','唐','唐诗','tang','','[]','白鹽危嶠北，赤甲古城東。',48,'全唐诗/poet.tang.11000.json','["白鹽危嶠北，赤甲古城東。", "平地一川穩，高山四面同。", "煙霜淒野日，秔稻熟天風。", "人事傷蓬轉，吾將守桂叢。"]'),
('8f5cc8fa-d12f-4b61-9926-32e8a62baca2','自瀼西荆扉且移居東屯茅屋四首 二','杜甫','唐','唐诗','tang','','[]','東屯復瀼西，一種住青溪。',48,'全唐诗/poet.tang.11000.json','["東屯復瀼西，一種住青溪。", "來往皆茅屋，淹留爲稻畦。", "市喧宜近利，林僻此無蹊。", "若訪衰翁語，須令賸客迷。"]'),
('b3ae6792-2b0a-4714-b6af-90e15c2c546c','自瀼西荆扉且移居東屯茅屋四首 三','杜甫','唐','唐诗','tang','','[]','道北馮都使，高齋見一川。',48,'全唐诗/poet.tang.11000.json','["道北馮都使，高齋見一川。", "子能渠細石，吾亦沼清泉。", "枕帶還相似，柴荆即有焉。", "斫畬應費日，解纜不知年。"]'),
('d87d55c8-dbfb-4a90-a3b7-d34920317999','自瀼西荆扉且移居東屯茅屋四首 四','杜甫','唐','唐诗','tang','','[]','牢落西江外，參差北戶間。',48,'全唐诗/poet.tang.11000.json','["牢落西江外，參差北戶間。", "久遊巴子國，臥病楚人山。", "幽獨移佳境，清深隔遠關。", "寒空見鴛鷺，迴首憶朝班。"]'),
('661bab14-62cd-4385-a173-f47e53e6e649','茅堂檢校收稻二首 一','杜甫','唐','唐诗','tang','','[]','香稻三秋末，平田百頃間。',48,'全唐诗/poet.tang.11000.json','["香稻三秋末，平田百頃間。", "喜無多屋宇，幸不礙雲山。", "御裌侵寒氣，嘗新破旅顏。", "紅鮮終日有，玉粒未吾慳。"]'),
('fde17d21-b335-43ef-8a18-c476b60f4b57','茅堂檢校收稻二首 二','杜甫','唐','唐诗','tang','','[]','稻米炊能白，秋葵煮復新。',48,'全唐诗/poet.tang.11000.json','["稻米炊能白，秋葵煮復新。", "誰云滑易飽，老藉軟俱勻。", "種幸房州熟，苗同伊闕春。", "無勞映渠盌，自有色如銀。"]'),
('7ab1281d-86d5-4114-83bc-384228b89102','東屯月夜','杜甫','唐','唐诗','tang','','[]','抱疾漂萍老，防邊舊穀屯。',96,'全唐诗/poet.tang.11000.json','["抱疾漂萍老，防邊舊穀屯。", "春農親異俗，歲月在衡門。", "青女霜楓重，黃牛峽水喧。", "泥留虎鬬跡，月挂客愁村。", "喬木澄稀影，輕雲倚細根。", "數驚聞雀噪，暫睡想猨蹲。", "日轉東方白，風來北斗昏。", "天寒不成寢，無夢寄歸魂。"]'),
('60dbbd97-f841-4008-9a8a-35188f8242f4','東屯北崦','杜甫','唐','唐诗','tang','','[]','盜賊浮生困，誅求異俗貧。',48,'全唐诗/poet.tang.11000.json','["盜賊浮生困，誅求異俗貧。", "空村惟見鳥，落日未逢人。", "步壑風吹面，看松露滴身。", "遠山迴白首，戰地有黃塵。"]'),
('745560cf-467b-4fe9-a0c9-50d10f03efdb','從驛次草堂復至東屯二首 一','杜甫','唐','唐诗','tang','','[]','峽內歸田客，江邊借馬騎。',48,'全唐诗/poet.tang.11000.json','["峽內歸田客，江邊借馬騎。", "非尋戴安道，似向習家池。", "峽險風煙僻，天寒橘柚垂。", "築場看斂積，一學楚人爲。"]'),
('e1fea3c2-af73-4b77-8cd1-ebf233140999','從驛次草堂復至東屯二首 二','杜甫','唐','唐诗','tang','','[]','短景難高臥，衰年強此身。',48,'全唐诗/poet.tang.11000.json','["短景難高臥，衰年強此身。", "山家蒸栗暖，野飯射麋新。", "世路知交薄，門庭畏客頻。", "牧童斯在眼，田父實爲鄰。"]'),
('f0878d2a-a575-4609-9bae-5b69cd5ce9c7','暫往白帝復還東屯','杜甫','唐','唐诗','tang','','[]','復作歸田去，猶殘穫稻功。',48,'全唐诗/poet.tang.11000.json','["復作歸田去，猶殘穫稻功。", "築場憐穴蟻，拾穗許村童。", "落杵光輝白，除芒子粒紅。", "加餐可扶老，倉庾慰飄蓬。"]'),
('256d10b8-dba7-466f-8bf9-ba87b8deac72','刈稻了詠懷','杜甫','唐','唐诗','tang','','[]','稻穫空雲水，川平對石門。',48,'全唐诗/poet.tang.11000.json','["稻穫空雲水，川平對石門。", "寒風疎落木，旭日散雞豚。", "野哭初聞戰，樵歌稍出村。", "無家問消息，作客信乾坤。"]'),
('b1a9afa8-5b0f-4dcb-85f8-b7f2f23f8b5e','上白帝城','杜甫','唐','唐诗','tang','','[]','城峻隨天壁，樓高更女牆。',48,'全唐诗/poet.tang.11000.json','["城峻隨天壁，樓高更女牆。", "江流思夏后，風至憶襄王。", "老去聞悲角，人扶報夕陽。", "公孫初恃險，躍馬意何長。"]'),
('3a292ae6-2955-4cbb-af62-fc78e4982c7a','上白帝城二首 一','杜甫','唐','唐诗','tang','','[]','江城含變態，一上一回新。',72,'全唐诗/poet.tang.11000.json','["江城含變態，一上一回新。", "天欲今朝雨，山歸萬古春。", "英雄餘事業，衰邁久風塵。", "取醉他鄉客，相逢故國人。", "兵戈猶擁蜀，賦斂強輸秦。", "不是煩形勝，深慙畏損神。"]'),
('d96c86d0-8a1d-477e-be76-96b9443598ad','上白帝城二首 二','杜甫','唐','唐诗','tang','','[]','白帝空祠廟，孤雲自往來。',72,'全唐诗/poet.tang.11000.json','["白帝空祠廟，孤雲自往來。", "江山城宛轉，棟宇客裴回。", "勇略今何在，當年亦壯哉。", "後人將酒肉，虛殿日塵埃。", "谷鳥鳴還過，林花落又開。", "多慙病無力，騎馬入青苔。"]'),
('a8f63a15-ac80-463f-9abf-c7d3b238d289','武侯廟','杜甫','唐','唐诗','tang','','["\u968b\u30fb\u5510\u30fb\u4e94\u4ee3", "\u8d5e\u9882", "\u5199\u4eba", "\u548f\u53f2\u6000\u53e4"]','遺廟丹青落，空山草木長。',24,'全唐诗/poet.tang.11000.json','["遺廟丹青落，空山草木長。", "猶聞辭後主，不復臥南陽。"]'),
('927908c0-999f-4d3f-8192-d67d28f93576','八陣圖','杜甫','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u968b\u30fb\u5510\u30fb\u4e94\u4ee3", "\u6000\u53e4", "\u54f2\u7406", "\u5199\u4eba", "\u4e94\u8a00\u7edd\u53e5"]','功蓋三分國，名高八陣圖。',24,'全唐诗/poet.tang.11000.json','["功蓋三分國，名高八陣圖。", "江流石不轉，遺恨失吞吳。"]'),
('fed8211c-2a95-4571-8ce3-065619d2bc69','謁先主廟','杜甫','唐','唐诗','tang','','[]','慘淡風雲會，乘時各有人。',192,'全唐诗/poet.tang.11000.json','["慘淡風雲會，乘時各有人。", "力侔分社稷，志屈偃經綸。", "復漢留長策，中原仗老臣。", "雜耕心未已，歐血事酸辛。", "霸氣西南歇，雄圖曆數屯。", "錦江元過楚，劒閣復通秦。", "舊俗存祠廟，空山立鬼神。", "虛簷交鳥道，枯木半龍鱗。", "竹送清溪月，苔移玉座春。", "閭閻兒女換，歌舞歲時新。", "絕域歸舟遠，荒城繫馬頻。", "如何對搖落，況乃久風塵。", "孰與關張並，功臨耿鄧親。", "應天才不小，得士契無鄰。", "遲暮堪帷幄，飄零且釣緡。", "向來憂國淚，寂寞灑衣巾。"]'),
('204563c9-a4ca-42f1-b9fb-350a373e1831','白鹽山','杜甫','唐','唐诗','tang','','[]','卓立羣峰外，蟠根積水邊。',48,'全唐诗/poet.tang.11000.json','["卓立羣峰外，蟠根積水邊。", "他皆任厚地，爾獨近高天。", "白牓千家邑，清秋萬估船。", "詞人取佳句，刻畫竟誰傳。"]'),
('c2709295-8e63-474a-97e9-506a1bcbd28b','灩澦堆','杜甫','唐','唐诗','tang','','[]','巨積水中央，江寒出水長。',48,'全唐诗/poet.tang.11000.json','["巨積水中央，江寒出水長。", "沈牛荅雲雨，如馬戒舟航。", "天意存傾覆，神功接混茫。", "干戈連解纜，行止憶垂堂。"]'),
('d50ac001-7581-484a-93bd-667993c3b608','灩澦','杜甫','唐','唐诗','tang','','[]','灧澦既沒孤根深，西來水多愁太陰。',64,'全唐诗/poet.tang.11000.json','["灧澦既沒孤根深，西來水多愁太陰。", "江天漠漠鳥雙去，風雨時時龍一吟。", "舟人漁子歌迴首，估客胡商淚滿襟。", "寄語舟航惡年少，休翻鹽井橫黃金。"]'),
('9f96e94c-3ccf-435a-8c67-9c0447f16d11','白帝','杜甫','唐','唐诗','tang','','[]','白帝城中雲出門，白帝城下雨翻盆。',64,'全唐诗/poet.tang.11000.json','["白帝城中雲出門，白帝城下雨翻盆。", "高江急峽雷霆鬬，翠木蒼藤日月昏。", "戎馬不如歸馬逸，千家今有百家存。", "哀哀寡婦誅求盡，慟哭秋原何處村。"]'),
('b148ee6a-a877-40a0-858a-40bf23f1bf26','白帝城樓','杜甫','唐','唐诗','tang','','[]','江度寒山閣，城高絕塞樓。',48,'全唐诗/poet.tang.11000.json','["江度寒山閣，城高絕塞樓。", "翠屏宜晚對，白谷會深遊。", "急急能鳴鴈，輕輕不下鷗。", "彝陵春色起，漸擬放扁舟。"]'),
('5218857b-75ca-4ec2-9d8d-2ebd4d7075c4','曉望白帝城鹽山','杜甫','唐','唐诗','tang','','[]','徐步移班杖，看山仰白頭。',48,'全唐诗/poet.tang.11000.json','["徐步移班杖，看山仰白頭。", "翠深開斷壁，紅遠結飛樓。", "日出清江望，暄和散旅愁。", "春城見松雪，始擬進歸舟。"]'),
('c0729417-079c-46a2-8d01-efb01e3f2d50','白帝城最高樓','杜甫','唐','唐诗','tang','','[]','城尖徑昃旌斾愁，獨立縹緲之飛樓。',64,'全唐诗/poet.tang.11000.json','["城尖徑昃旌斾愁，獨立縹緲之飛樓。", "峽坼雲霾龍虎臥，江清日抱黿鼉遊。", "扶桑西枝對斷石，弱水東影隨長流。", "杖藜歎世者誰子，泣血迸空迴白頭。"]'),
('726d3ed2-4b2b-42c0-a5a3-5fe1d91a6bf5','白帝樓','杜甫','唐','唐诗','tang','','[]','漠漠虛無裏，連連睥睨侵。',48,'全唐诗/poet.tang.11000.json','["漠漠虛無裏，連連睥睨侵。", "樓光去日遠，峽影入江深。", "臘破思端綺，春歸待一金。", "去年梅柳意，還欲攪邊心。"]'),
('df2138b8-a79c-435a-a1be-737188b31450','陪諸公上白帝城宴越公堂之作','杜甫','唐','唐诗','tang','','[]','此堂存古製，城上俯江郊。',72,'全唐诗/poet.tang.11000.json','["此堂存古製，城上俯江郊。", "落構垂雲雨，荒階蔓草茅。", "柱穿蜂溜蜜，棧缺燕添巢。", "坐接春杯氣，心傷豔蘂梢。", "英靈如過隙，宴衎願投膠。", "莫問東流水，生涯未即拋。"]'),
('04d3bcf8-a082-435c-83cc-381869968238','峽隘','杜甫','唐','唐诗','tang','','[]','聞說江陵府，雲沙靜眇然。',48,'全唐诗/poet.tang.11000.json','["聞說江陵府，雲沙靜眇然。", "白魚如切玉，朱橘不論錢。", "水有遠湖樹，人今何處船。", "青山各在眼，却望峽中天。"]'),
('0b6a4293-c89f-4e4b-9365-be01edb02ccd','諸葛廟','杜甫','唐','唐诗','tang','','[]','久遊巴子國，屢入武侯祠。',72,'全唐诗/poet.tang.11000.json','["久遊巴子國，屢入武侯祠。", "竹日斜虛寢，溪風滿薄帷。", "君臣當共濟，賢聖亦同時。", "翊戴歸先主，幷吞更出師。", "蟲虵穿畫壁，巫覡醉蛛絲。", "歘憶吟梁父，躬耕也未遲。"]'),
('98fc0ac5-1c75-4c64-8e09-6813c8d1b9fc','峽口二首 一','杜甫','唐','唐诗','tang','','[]','峽口大江間，西南控百蠻。',48,'全唐诗/poet.tang.11000.json','["峽口大江間，西南控百蠻。", "城欹連粉堞，岸斷更青山。", "開闢多天險，防隅一水關。", "亂離聞鼓角，秋氣動衰顏。"]'),
('f92010e4-10af-4ea9-8c98-31713be74c52','峽口二首 二','杜甫','唐','唐诗','tang','','[]','時清關失險，世亂戟如林。',48,'全唐诗/poet.tang.11000.json','["時清關失險，世亂戟如林。", "去矣英雄事，荒哉割據心。", "蘆花留客晚，楓樹坐猨深。", "疲薾煩親故，諸侯數賜金。"]'),
('f5857487-ad9f-4ca2-b16f-bee669ac0def','天池','杜甫','唐','唐诗','tang','','[]','天池馬不到，嵐壁鳥纔通。',120,'全唐诗/poet.tang.11000.json','["天池馬不到，嵐壁鳥纔通。", "百頃青雲杪，層波白石中。", "鬱紆騰秀氣，蕭瑟浸寒空。", "直對巫山出，兼疑夏禹功。", "魚龍開闢有，菱芡古今同。", "聞道奔雷黑，初看浴日紅。", "飄零神女雨，斷續楚王風。", "欲問支機石，如臨獻寶宮。", "九秋驚鴈序，萬里狎漁翁。", "更是無人處，誅茅任薄躬。"]'),
('9c996da5-8748-4457-9fb8-50556b2a2901','瞿塘兩崖','杜甫','唐','唐诗','tang','','[]','三峽傳何處，雙崖壯此門。',48,'全唐诗/poet.tang.11000.json','["三峽傳何處，雙崖壯此門。", "入天猶石色，穿水忽雲根。", "猱攫鬚髯古，蛟龍窟宅尊。", "羲和冬馭近，愁畏日車翻。"]'),
('972dea94-8001-40a3-88e1-ad588d2f0567','夔州歌十絕句 一','杜甫','唐','唐诗','tang','','[]','中巴之東巴東山，江水開闢流其間。',32,'全唐诗/poet.tang.11000.json','["中巴之東巴東山，江水開闢流其間。", "白帝高爲三峽鎮，夔州險過百牢關。"]'),
('b68078cf-e7db-43e9-b6d8-48cbdf5c09cc','夔州歌十絕句 二','杜甫','唐','唐诗','tang','','[]','白帝夔州各異城，蜀江楚峽混殊名。',32,'全唐诗/poet.tang.11000.json','["白帝夔州各異城，蜀江楚峽混殊名。", "英雄割據非天意，霸主幷吞在物情。"]'),
('6bb4b66d-fcae-4e98-ae5f-ae24d533e9fe','夔州歌十絕句 三','杜甫','唐','唐诗','tang','','[]','羣雄競起問前朝，王者無外見今朝。',32,'全唐诗/poet.tang.11000.json','["羣雄競起問前朝，王者無外見今朝。", "比訝漁陽結怨恨，元聽舜日舊簫韶。"]'),
('7d804266-6776-4385-b2af-14af2b649671','夔州歌十絕句 四','杜甫','唐','唐诗','tang','','[]','赤甲白鹽俱刺天，閭閻繚繞接山巔。',32,'全唐诗/poet.tang.11000.json','["赤甲白鹽俱刺天，閭閻繚繞接山巔。", "楓林橘樹丹青合，複道重樓錦繡懸。"]'),
('c1c10dd3-d477-42a4-b40d-1f97cc3371a8','夔州歌十絕句 五','杜甫','唐','唐诗','tang','','[]','瀼東瀼西一萬家，江北江南春冬花。',32,'全唐诗/poet.tang.11000.json','["瀼東瀼西一萬家，江北江南春冬花。", "背飛鶴子遺瓊蘂，相趁鳧雛入蔣牙。"]'),
('1977b41a-e00a-457f-a4f1-42ad9c18acb1','夔州歌十絕句 六','杜甫','唐','唐诗','tang','','[]','東屯稻畦一百頃，北有澗水通青苗。',32,'全唐诗/poet.tang.11000.json','["東屯稻畦一百頃，北有澗水通青苗。", "晴浴狎鷗分處處，雨隨神女下朝朝。"]'),
('d102dbb2-b12f-474f-9a18-9bddbf511244','夔州歌十絕句 七','杜甫','唐','唐诗','tang','','[]','蜀麻吳鹽自古通，萬斛之舟行若風。',32,'全唐诗/poet.tang.11000.json','["蜀麻吳鹽自古通，萬斛之舟行若風。", "長年三老長歌裏，白晝攤錢高浪中。"]'),
('75f4689b-85da-4d72-abb5-9b2c67bfc884','夔州歌十絕句 八','杜甫','唐','唐诗','tang','','[]','憶昔咸陽都市合，山水之圖張賣時。',32,'全唐诗/poet.tang.11000.json','["憶昔咸陽都市合，山水之圖張賣時。", "巫峽曾經寶屏見，楚宮猶對碧峰疑。"]'),
('3e021009-78c1-46c6-bb7e-fe82fe759b2e','夔州歌十絕句 九','杜甫','唐','唐诗','tang','','[]','武侯祠堂不可忘，中有松柏參天長。',32,'全唐诗/poet.tang.11000.json','["武侯祠堂不可忘，中有松柏參天長。", "干戈滿地客愁破，雲日如火炎天涼。"]'),
('6d0e3fd3-1493-408b-a616-0b940072d222','夔州歌十絕句 十','杜甫','唐','唐诗','tang','','[]','閬風玄圃與蓬壺，中有高堂天下無。',32,'全唐诗/poet.tang.11000.json','["閬風玄圃與蓬壺，中有高堂天下無。", "借問夔州壓何處，峽門江腹擁城隅。"]'),
('2c6762d2-ede5-4b41-9527-c3d8c8f91533','上卿翁請修武侯廟遺像缺落時崔卿權夔州','杜甫','唐','唐诗','tang','','[]','大賢爲政即多聞，刺史真符不必分。',32,'全唐诗/poet.tang.11000.json','["大賢爲政即多聞，刺史真符不必分。", "尚有西郊諸葛廟，臥龍無首對江濆。"]'),
('1c95696d-8258-4661-a1ad-f34ad1e37cd1','偶題','杜甫','唐','唐诗','tang','','["\u54f2\u7406"]','文章千古事，得失寸心知。',264,'全唐诗/poet.tang.11000.json','["文章千古事，得失寸心知。", "作者皆殊列，名聲豈浪垂。", "騷人嗟不見，漢道盛於斯。", "前輩飛騰入，餘波綺麗爲。", "後賢兼舊列，歷代各清規。", "法自儒家有，心從弱歲疲。", "永懷江左逸，多病鄴中奇。", "騄驥皆良馬，騏驎帶好兒。", "車輪徒已斵，堂構惜仍虧。", "漫作潛夫論，虛傳幼婦碑。", "緣情慰漂蕩，抱疾屢遷移。", "經濟慙長策，飛棲假一枝。", "塵沙傍蜂蠆，江峽繞蛟螭。", "蕭瑟唐虞遠，聯翩楚漢危。", "聖朝兼盜賊，異俗更喧卑。", "鬱鬱星辰劒，蒼蒼雲雨池。", "兩都開幕府，萬宇插軍麾。", "南海殘銅柱，東風避月支。", "音書恨烏鵲，號怒怪熊羆。", "稼穡分詩興，柴荆學土宜。", "故山迷白閣，秋水隱黃陂。", "不敢要佳句，愁來賦別離。"]'),
('34a23446-cb6c-40e2-9d5f-81db0657f3d7','秋興八首 一','杜甫','唐','唐诗','tang','','["\u601d\u5ff5", "\u79cb\u5929", "\u5199\u666f"]','玉露凋傷楓樹林，巫山巫峽氣蕭森。',64,'全唐诗/poet.tang.11000.json','["玉露凋傷楓樹林，巫山巫峽氣蕭森。", "江間波浪兼天湧，塞上風雲接地陰。", "叢菊兩開他日淚，孤舟一繫故園心。", "寒衣處處催刀尺，白帝城高急暮砧。"]'),
('15190dbd-fbb9-4a1a-b4b7-7bc94ea577ef','秋興八首 二','杜甫','唐','唐诗','tang','','[]','夔府孤城落日斜，每依南斗望京華。',64,'全唐诗/poet.tang.11000.json','["夔府孤城落日斜，每依南斗望京華。", "聽猨實下三聲淚，奉使虛隨八月查。", "畫省香爐違伏枕，山樓粉堞隱悲笳。", "請看石上藤蘿月，已暎洲前蘆荻花。"]'),
('0758afd3-8514-4ce5-a716-6c5b1d4ddb41','秋興八首 三','杜甫','唐','唐诗','tang','','[]','千家山郭靜朝暉，一日江樓坐翠微。',64,'全唐诗/poet.tang.11000.json','["千家山郭靜朝暉，一日江樓坐翠微。", "信宿漁人還汎汎，清秋燕子故飛飛。", "匡衡抗疏功名薄，劉向傳經心事違。", "同學少年多不賤，五陵衣馬自輕肥。"]'),
('1ec1bfe2-0243-4f3c-9789-8bdbddc6a015','秋興八首 四','杜甫','唐','唐诗','tang','','[]','聞道長安似弈棊，百年世事不勝悲。',64,'全唐诗/poet.tang.11000.json','["聞道長安似弈棊，百年世事不勝悲。", "王侯第宅皆新主，文武衣冠異昔時。", "直北關山金鼓振，征西車馬羽書遲。", "魚龍寂寞秋江冷，故國平居有所思。"]'),
('e03b89ed-18ab-4576-ad30-fd5a6060f7a7','秋興八首 五','杜甫','唐','唐诗','tang','','[]','蓬萊宮闕對南山，承露金莖霄漢間。',64,'全唐诗/poet.tang.11000.json','["蓬萊宮闕對南山，承露金莖霄漢間。", "西望瑤池降王母，東來紫氣滿函關。", "雲移雉尾開宮扇，日繞龍鱗識聖顏。", "一臥滄江驚歲晚，幾迴青瑣照朝班。"]'),
('5d411317-d3fb-45c2-8a4d-b8d30987028e','秋興八首 六','杜甫','唐','唐诗','tang','','[]','瞿唐峽口曲江頭，萬里風煙接素秋。',64,'全唐诗/poet.tang.11000.json','["瞿唐峽口曲江頭，萬里風煙接素秋。", "花萼夾城通御氣，芙蓉小苑入邊愁。", "朱簾繡柱圍黃鶴，錦纜牙檣起白鷗。", "迴首可憐歌舞地，秦中自古帝王州。"]'),
('40e33874-18b2-4ad8-942e-41240bc9d97c','秋興八首 七','杜甫','唐','唐诗','tang','','[]','昆明池水漢時功，武帝旌旗在眼中。',64,'全唐诗/poet.tang.11000.json','["昆明池水漢時功，武帝旌旗在眼中。", "織女機絲虛月夜，石鯨鱗甲動秋風。", "波漂菰米沈雲黑，露冷蓮房墜粉紅。", "關塞極天唯鳥道，江湖滿地一漁翁。"]'),
('ebcc9d85-c605-489c-a8ce-8233c26bbb8d','秋興八首 八','杜甫','唐','唐诗','tang','','[]','昆吾御宿自逶迤，紫閣峰陰入渼陂。',64,'全唐诗/poet.tang.11000.json','["昆吾御宿自逶迤，紫閣峰陰入渼陂。", "香稻啄餘鸚鵡粒，碧梧棲老鳳皇枝。", "佳人拾翠春相問，仙侶同舟晚更移。", "綵筆昔遊干氣象，白頭吟望苦低垂。"]'),
('03eb4001-023a-4920-bbc7-a0fc52b2836d','詠懷古跡五首 一','杜甫','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u968b\u30fb\u5510\u30fb\u4e94\u4ee3", "\u4e03\u8a00\u5f8b\u8bd7", "\u611f\u53f9", "\u6000\u53e4"]','支離東北風塵際，漂泊西南天地間。',64,'全唐诗/poet.tang.11000.json','["支離東北風塵際，漂泊西南天地間。", "三峽樓臺淹日月，五溪衣服共雲山。", "羯胡事主終無賴，詞客衰時且未還。", "庾信平生最蕭瑟，暮年詩賦動江關。"]'),
('acbe1729-cefd-4678-9719-09c5c9c27db0','詠懷古跡五首 二','杜甫','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u968b\u30fb\u5510\u30fb\u4e94\u4ee3", "\u4e03\u8a00\u5f8b\u8bd7", "\u6000\u53e4", "\u6292\u6000"]','搖落深知宋玉悲，風流儒雅亦吾師。',64,'全唐诗/poet.tang.11000.json','["搖落深知宋玉悲，風流儒雅亦吾師。", "悵望千秋一灑淚，蕭條異代不同時。", "江山故宅空文藻，雲雨荒臺豈夢思。", "最是楚宮俱泯滅，舟人指點到今疑。"]'),
('3b5db620-1964-4674-a01d-ad70ba3ebd2a','詠懷古跡五首 三','杜甫','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u968b\u30fb\u5510\u30fb\u4e94\u4ee3", "\u4e03\u8a00\u5f8b\u8bd7", "\u6000\u53e4", "\u601d\u4e61"]','羣山萬壑赴荆門，生長明妃尚有村。',64,'全唐诗/poet.tang.11000.json','["羣山萬壑赴荆門，生長明妃尚有村。", "一去紫臺連朔漠，獨留青塚向黃昏。", "畫圖省識春風面，環佩空歸月夜魂。", "千載琵琶作胡語，分明怨恨曲中論。"]'),
('733afc7b-e370-4724-b755-e9342c574d22','詠懷古跡五首 四','杜甫','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u968b\u30fb\u5510\u30fb\u4e94\u4ee3", "\u4e03\u8a00\u5f8b\u8bd7", "\u6000\u53e4", "\u6292\u6000"]','蜀主窺吳幸三峽，崩年亦在永安宮。',64,'全唐诗/poet.tang.11000.json','["蜀主窺吳幸三峽，崩年亦在永安宮。", "翠華想像空山裏，玉殿虛無野寺中。", "古廟杉松巢水鶴，歲時伏臘走村翁。", "武侯祠屋常鄰近，一體君臣祭祀同。"]'),
('87f5949b-bdad-4b5e-b488-7015bd45cc4f','詠懷古跡五首 五','杜甫','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u968b\u30fb\u5510\u30fb\u4e94\u4ee3", "\u4e03\u8a00\u5f8b\u8bd7", "\u6000\u53e4", "\u8bae\u8bba"]','諸葛大名垂宇宙，宗臣遺像肅清高。',64,'全唐诗/poet.tang.11000.json','["諸葛大名垂宇宙，宗臣遺像肅清高。", "三分割據紆籌策，萬古雲霄一羽毛。", "伯仲之間見伊呂，指揮若定失蕭曹。", "福移漢祚難恢復，志決身殲軍務勞。"]'),
('2ff3fc01-3028-4ee9-b1a4-f9f8fbe14464','諸將五首 一','杜甫','唐','唐诗','tang','','[]','漢朝陵暮對南山，胡虜千秋尚入關。',64,'全唐诗/poet.tang.11000.json','["漢朝陵暮對南山，胡虜千秋尚入關。", "昨日玉魚蒙葬地，早時今盌出人間。", "見愁汗馬西戎逼，曾閃朱旗北斗殷。", "多少材官守涇渭，將軍且莫破愁顏。"]'),
('246ff1f1-9148-400a-930e-635dbdc699b9','諸將五首 二','杜甫','唐','唐诗','tang','','[]','韓公本意築三城，擬絕天驕拔漢旌。',63,'全唐诗/poet.tang.11000.json','["韓公本意築三城，擬絕天驕拔漢旌。", "豈謂盡煩回紇馬，翻然遠救朔方兵胡來不覺潼關隘，龍起猶聞晉水清。", "獨使至尊憂社稷，諸君何以荅升平。"]'),
('0fbd2f90-69ec-4f6a-9407-3092f035909a','諸將五首 三','杜甫','唐','唐诗','tang','','[]','洛陽宮殿化爲烽，休道秦關百二重。',64,'全唐诗/poet.tang.11000.json','["洛陽宮殿化爲烽，休道秦關百二重。", "滄海未全歸禹貢，薊門何處盡堯封。", "朝廷衮職雖多預，天下軍儲不自供。", "稍喜臨邊王相國，肯銷金甲事春農。"]'),
('9019bc9b-6b53-4266-9933-cab4fdaac333','諸將五首 四','杜甫','唐','唐诗','tang','','[]','迴首扶桑銅柱標，冥冥氛祲未全銷。',64,'全唐诗/poet.tang.11000.json','["迴首扶桑銅柱標，冥冥氛祲未全銷。", "越裳翡翠無消息，南海明珠久寂寥。", "殊錫曾爲大司馬，總戎皆插侍中貂。", "炎風朔雪天王地，只在忠臣翊聖朝。"]'),
('9044d831-e82f-44c9-9b36-176a8bac0d5e','諸將五首 五','杜甫','唐','唐诗','tang','','[]','錦江春色逐人來，巫峽清秋萬壑哀。',64,'全唐诗/poet.tang.11000.json','["錦江春色逐人來，巫峽清秋萬壑哀。", "正憶往時嚴僕射，共迎中使望鄉臺。", "主恩前後三持節，軍令分明數舉桮。", "西蜀地形天下險，安危須仗出羣材。"]'),
('a3aec75e-d67c-4a40-920a-c3ccbac03993','秋日夔府詠懷奉寄鄭監李賓客一百韻','杜甫','唐','唐诗','tang','','[]','絕塞烏蠻北，孤城白帝邊。',288,'全唐诗/poet.tang.11000.json','["絕塞烏蠻北，孤城白帝邊。", "飄零仍百里，消渴已三年。", "雄劒鳴開匣，羣書滿繫船。", "亂離心不展，衰謝日蕭然。", "筋力妻孥問，菁華歲月遷。", "登臨多物色，陶冶賴詩篇。", "峽束滄江起，巖排石樹圓。", "拂雲霾楚氣，朝海蹴吳天。", "煮井爲鹽速，燒畬度地偏。", "有時驚疊嶂，何處覓平川。", "鸂鶒雙雙舞，獼猿壘壘懸。", "碧蘿長似帶，錦石小如錢。", "春草何曾歇，寒花亦可憐。", "獵人吹戍火，野店引山泉。", "喚起搔頭急，扶行幾屐穿。", "兩京猶薄產，四海絕隨肩。", "幕府初交辟，郎官幸備員。", "瓜時猶旅寓，萍泛苦夤緣。", "藥餌虛狼藉，秋風灑靜便。", "開襟驅瘴癘，明目掃雲煙。", "高宴諸侯禮，佳人上客前。", "哀箏傷老大，華屋豔神仙。", "南內開元曲，常時弟子傳。", "法歌聲變轉，滿座涕潺湲。"]'),
('20a6a82e-639c-4244-a3c4-193f16fd0b57','贈李八祕書別三十韻','杜甫','唐','唐诗','tang','','[]','往時中補右，扈蹕上元初。',288,'全唐诗/poet.tang.11000.json','["往時中補右，扈蹕上元初。", "反氣凌行在，妖星下直廬。", "六龍瞻漢闕，萬騎略姚墟。", "玄朔迴天步，神都憶帝車。", "一戎纔汗馬，百姓免爲魚。", "通籍蟠螭印，差肩列鳳輿。", "事殊迎代邸，喜異賞朱虛。", "寇盜方歸順，乾坤欲晏如。", "不才同補衮，奉詔許牽裾。", "鴛鷺叨雲閣，麒麟滯玉除。", "文園多病後，中散舊交疎。", "飄泊哀相見，平生意有餘。", "風煙巫峽遠，臺榭楚宮虛。", "觸目非論故，新文尚起予。", "清秋凋碧柳，別浦落紅蕖。", "消息多旗幟，經過嘆里閭。", "戰連唇齒國，軍急羽毛書。", "幕府籌頻問，山家藥正鋤。", "台星入朝謁，使節有吹噓。", "西蜀災長弭，南翁憤始攄。", "對敭抏士卒，乾沒費倉儲。", "勢藉兵須用，功無禮忽諸。", "御鞍金騕褭，宮硯玉蟾蜍。", "拜舞銀鉤落，恩波錦帕舒。"]'),
('57d76232-2003-4be8-98d5-3a435a067c71','寄劉峽州伯華使君四十韻','杜甫','唐','唐诗','tang','','[]','峽內多雲雨，秋來尚鬱蒸。',288,'全唐诗/poet.tang.11000.json','["峽內多雲雨，秋來尚鬱蒸。", "遠山朝白帝，深水謁彝陵。", "遲暮嗟爲客，西南喜得朋。", "哀猨更起坐，落雁失飛騰。", "伏枕思瓊樹，臨軒對玉繩。", "青松寒不落，碧海闊逾澄。", "昔歲文爲理，羣公價盡增。", "家聲同令聞，時論以儒稱。", "太后當朝肅，多才接跡昇。", "翠虛捎魍魎，丹極上鵾鵬。", "宴引春壺滿，恩分夏簟冰。", "彫章五色筆，紫殿九華燈。", "學並盧王敏，書偕褚薛能。", "老兄真不墜，小子獨無承。", "近有風流作，聊從月繼徵。", "放蹄知赤驥，捩翅服蒼鷹。", "卷軸來何晚，襟懷庶可憑。", "會期吟諷數，益破旅愁凝。", "雕刻初誰料，纖毫欲自矜。", "神融躡飛動，戰勝洗侵凌。", "妙取筌蹄棄，高宜百萬層。", "白頭遺恨在，青竹幾人登。", "迴首追談笑，勞歌跼寢興。", "年華紛已矣，世故莽相仍。"]'),
('f7860ea4-d771-4091-8590-dbaa77bf1729','夔府書懷四十韻','杜甫','唐','唐诗','tang','','[]','昔罷河西尉，初興薊北師。',288,'全唐诗/poet.tang.11000.json','["昔罷河西尉，初興薊北師。", "不才名位晚，敢恨省郎遲。", "扈聖崆峒日，端居灧澦時。", "萍流仍汲引，樗散尚恩慈。", "遂阻雲臺宿，常懷湛露詩。", "翠華森遠矣，白首颯淒其。", "拙被林泉滯，生逢酒賦欺。", "文園終寂寞，漢閣自磷緇。", "病隔君臣議，慚紆德澤私。", "揚鑣驚主辱，拔劒撥年衰。", "社稷經綸地，風雲際會期。", "血流紛在眼，涕灑亂交頤。", "四瀆樓船汎，中原鼓角悲。", "賊壕連白翟，戰瓦落丹墀。", "先帝嚴靈寢，宗臣切受遺。", "恆山猶突騎，遼海競張旗。", "田父嗟膠漆，行人避蒺藜。", "總戎存大體，降將餙卑詞。", "楚貢何年絕，堯封舊俗疑。", "長吁翻北寇，一望卷西夷。", "不必陪玄圃，超然待具茨。", "凶兵鑄農器，講殿闢書帷。", "廟算高難測，天憂實在茲。", "形容真潦倒，荅效莫支持。"]'),
('18580212-5d9c-4483-a89d-bd5e0b9c62c9','解悶十二首 一','杜甫','唐','唐诗','tang','','[]','草閣柴扉星散居，浪翻江黑雨飛初。',32,'全唐诗/poet.tang.11000.json','["草閣柴扉星散居，浪翻江黑雨飛初。", "山禽引子哺紅果，溪友得錢留白魚。"]'),
('379e8d48-0acb-460a-ad3f-4876e6eb6871','解悶十二首 二','杜甫','唐','唐诗','tang','','[]','商胡離別下揚州，憶上西陵故驛樓。',32,'全唐诗/poet.tang.11000.json','["商胡離別下揚州，憶上西陵故驛樓。", "爲問淮南米貴賤，老夫乘興欲東流。"]'),
('cde0bff4-e96a-477b-bcf2-1e6ecb389d21','解悶十二首 三','杜甫','唐','唐诗','tang','','[]','一辭故國十經秋，每見秋瓜憶故丘。',32,'全唐诗/poet.tang.11000.json','["一辭故國十經秋，每見秋瓜憶故丘。", "今日南湖采薇蕨，何人爲覓鄭瓜州。"]'),
('087495fe-5873-442a-9812-deba83408432','解悶十二首 四','杜甫','唐','唐诗','tang','','[]','沈范早知何水部，曹劉不待薛郎中。',32,'全唐诗/poet.tang.11000.json','["沈范早知何水部，曹劉不待薛郎中。", "獨當省署開文苑，兼泛滄浪學釣翁。"]'),
('fef6c5d9-9aba-4405-9d2a-b97f0866e1f3','解悶十二首 五','杜甫','唐','唐诗','tang','','[]','李陵蘇武是吾師，孟子論文更不疑。',32,'全唐诗/poet.tang.11000.json','["李陵蘇武是吾師，孟子論文更不疑。", "一飯未曾留俗客，數篇今見古人詩。"]'),
('52903113-79ce-407c-8525-a5f93bef88f4','解悶十二首 六','杜甫','唐','唐诗','tang','','[]','復憶襄陽孟浩然，清詩句句盡堪傳。',32,'全唐诗/poet.tang.11000.json','["復憶襄陽孟浩然，清詩句句盡堪傳。", "即今耆舊無新語，漫釣槎頭縮頸鯿。"]'),
('9ce47635-1efb-4ec1-9bf3-54b11a23e311','解悶十二首 七','杜甫','唐','唐诗','tang','','[]','陶冶性靈在底物，新詩改罷自長吟。',32,'全唐诗/poet.tang.11000.json','["陶冶性靈在底物，新詩改罷自長吟。", "孰知二謝將能事，頗學陰何苦用心。"]'),
('5f5ac262-5291-469f-9fb7-6421b006dd35','解悶十二首 八','杜甫','唐','唐诗','tang','','[]','不見高人王右丞，藍田丘壑漫寒藤。',32,'全唐诗/poet.tang.11000.json','["不見高人王右丞，藍田丘壑漫寒藤。", "最傳秀句寰區滿，未絕風流相國能。"]'),
('d45caed5-bc9a-4c16-836a-97e68e9b2f81','解悶十二首 九','杜甫','唐','唐诗','tang','','[]','先帝貴妃今寂寞，荔枝還復入長安。',36,'全唐诗/poet.tang.11000.json','["先帝貴妃今寂寞，荔枝還復入長安。", "炎方每續朱[櫻]獻，玉座應悲白露[團]。"]'),
('094c888f-a963-43dc-9e4e-b1b644c54abe','解悶十二首 十','杜甫','唐','唐诗','tang','','[]','憶過瀘戎摘荔枝，青峰隱暎石逶迤。',32,'全唐诗/poet.tang.11000.json','["憶過瀘戎摘荔枝，青峰隱暎石逶迤。", "京中舊見無顏色，紅顆酸甜只自知。"]'),
('ac97eedb-6cc1-4f92-99e2-96b5ea8d9f33','解悶十二首 十一','杜甫','唐','唐诗','tang','','[]','翠瓜碧李沈玉甃，赤梨葡萄寒露成。',32,'全唐诗/poet.tang.11000.json','["翠瓜碧李沈玉甃，赤梨葡萄寒露成。", "可憐先不異枝蔓，此物娟娟長遠生。"]'),
('4485a172-5b62-4e71-b05f-813691727067','解悶十二首 十二','杜甫','唐','唐诗','tang','','[]','側生野岸及江蒲，不熟丹宮滿玉壺。',32,'全唐诗/poet.tang.11000.json','["側生野岸及江蒲，不熟丹宮滿玉壺。", "雲壑布衣駘背死，勞生重馬翠眉須。"]'),
('edf2f562-6df5-40d1-9349-e17b5fe06ede','復愁十二首 一','杜甫','唐','唐诗','tang','','[]','人煙生處僻，虎跡過新蹄。',24,'全唐诗/poet.tang.11000.json','["人煙生處僻，虎跡過新蹄。", "野鶻翻窺草，村船逆上溪。"]'),
('b92d5da0-e175-46f5-b49f-4224da3994b7','復愁十二首 二','杜甫','唐','唐诗','tang','','[]','釣艇收緡盡，昏鴉接翅歸。',24,'全唐诗/poet.tang.11000.json','["釣艇收緡盡，昏鴉接翅歸。", "月生初學扇，雲細不成衣。"]'),
('a398f1df-df49-4789-bc09-bce62a11362d','復愁十二首 三','杜甫','唐','唐诗','tang','','[]','萬國尚防寇，故園今若何。',24,'全唐诗/poet.tang.11000.json','["萬國尚防寇，故園今若何。", "昔歸相識少，早已戰場多。"]'),
('a3df8abc-67d3-4dbf-9e24-0e647dadb3dd','復愁十二首 四','杜甫','唐','唐诗','tang','','[]','身覺省郎在，家須農事歸。',24,'全唐诗/poet.tang.11000.json','["身覺省郎在，家須農事歸。", "年深荒草徑，老恐失柴扉。"]'),
('741560f7-c9c5-48fd-8359-0134553a4aec','復愁十二首 五','杜甫','唐','唐诗','tang','','[]','金絲鏤箭鏃，皂尾製旗竿。',24,'全唐诗/poet.tang.11000.json','["金絲鏤箭鏃，皂尾製旗竿。", "一自風塵起，猶嗟行路難。"]'),
('b281e104-63de-48ea-a879-fae61f49baf2','復愁十二首 六','杜甫','唐','唐诗','tang','','[]','胡虜何曾盛，干戈不肯休。',24,'全唐诗/poet.tang.11000.json','["胡虜何曾盛，干戈不肯休。", "閭閻聽小子，談話覓封侯。"]'),
('3c656a9b-c3d7-4818-bf6d-b9ba56028fa8','復愁十二首 七','杜甫','唐','唐诗','tang','','[]','貞觀銅牙弩，開元錦獸張。',24,'全唐诗/poet.tang.11000.json','["貞觀銅牙弩，開元錦獸張。", "花門小前好，此物棄沙場。"]'),
('cfc10c96-a26d-4899-8719-36b90da945ce','復愁十二首 八','杜甫','唐','唐诗','tang','','[]','今日翔麟馬，先宜駕鼓車。',24,'全唐诗/poet.tang.11000.json','["今日翔麟馬，先宜駕鼓車。", "無勞問河北，諸將覺榮華。"]'),
('e7daa779-d135-4486-aa2c-f9242bc55277','復愁十二首 九','杜甫','唐','唐诗','tang','','[]','任轉江淮粟，休添苑囿兵。',24,'全唐诗/poet.tang.11000.json','["任轉江淮粟，休添苑囿兵。", "由來貔虎士，不滿鳳皇城。"]'),
('fd642541-4a30-4b42-9ded-0c6e4cc44e17','復愁十二首 十','杜甫','唐','唐诗','tang','','[]','江上亦秋色，火雲終不移。',24,'全唐诗/poet.tang.11000.json','["江上亦秋色，火雲終不移。", "巫山猶錦樹，南國且黃鸝。"]'),
('34d953bb-1383-4a20-ab85-9313f0c82b7d','復愁十二首 十一','杜甫','唐','唐诗','tang','','[]','每恨陶彭澤，無錢對菊花。',24,'全唐诗/poet.tang.11000.json','["每恨陶彭澤，無錢對菊花。", "如今九日至，自覺酒須賒。"]'),
('c6b2608c-7a2c-40cf-9d74-c3d9a95e6ba9','復愁十二首 十二','杜甫','唐','唐诗','tang','','[]','病減詩仍拙，吟多意有餘。',24,'全唐诗/poet.tang.11000.json','["病減詩仍拙，吟多意有餘。", "莫看江總老，猶被賞時魚。"]'),
('354d67cf-c1a3-4f2a-baba-0842ab66c099','承聞河北諸道節度入朝歡喜口號絕句十二首 一','杜甫','唐','唐诗','tang','','[]','祿山作逆降天誅，更有思明亦已無。',32,'全唐诗/poet.tang.11000.json','["祿山作逆降天誅，更有思明亦已無。", "洶洶人寰猶不定，時時鬬戰欲何須。"]'),
('8a2e05d0-fefd-4db6-9e0c-8debd1a00056','承聞河北諸道節度入朝歡喜口號絕句十二首 二','杜甫','唐','唐诗','tang','','[]','社稷蒼生計必安，蠻夷雜種錯相干。',32,'全唐诗/poet.tang.11000.json','["社稷蒼生計必安，蠻夷雜種錯相干。", "周宣漢武今王是，孝子忠臣後代看。"]'),
('49b64c40-738b-4939-b39b-ba1edf4542d1','承聞河北諸道節度入朝歡喜口號絕句十二首 三','杜甫','唐','唐诗','tang','','[]','喧喧道路多歌謠，河北將軍盡入朝。',32,'全唐诗/poet.tang.11000.json','["喧喧道路多歌謠，河北將軍盡入朝。", "始是乾坤王室正，却交江漢客魂銷。"]'),
('6d4ea21d-8514-4a94-9303-c93b30773554','承聞河北諸道節度入朝歡喜口號絕句十二首 四','杜甫','唐','唐诗','tang','','[]','不道諸公無表來，茫然庶事遣人猜。',32,'全唐诗/poet.tang.11000.json','["不道諸公無表來，茫然庶事遣人猜。", "擁兵相學干戈銳，使者徒勞百萬迴。"]'),
('2dc3fc21-0ada-4294-a6c2-f55679921fed','承聞河北諸道節度入朝歡喜口號絕句十二首 五','杜甫','唐','唐诗','tang','','[]','鳴玉鏘金盡正臣，修文偃武不無人。',32,'全唐诗/poet.tang.11000.json','["鳴玉鏘金盡正臣，修文偃武不無人。", "興王會靜妖氛氣，聖壽宜過一萬春。"]'),
('c6edfec2-2a10-48fe-a955-e9b7e0088017','承聞河北諸道節度入朝歡喜口號絕句十二首 六','杜甫','唐','唐诗','tang','','[]','英雄見事若通神，聖哲爲心小一身。',32,'全唐诗/poet.tang.11000.json','["英雄見事若通神，聖哲爲心小一身。", "燕趙休矜出佳麗，宮闈不擬選才人。"]'),
('9c26a722-4c4a-4ce6-bd36-e467290006c3','承聞河北諸道節度入朝歡喜口號絕句十二首 七','杜甫','唐','唐诗','tang','','[]','抱病江天白首郎，空山樓閣暮春光。',32,'全唐诗/poet.tang.11000.json','["抱病江天白首郎，空山樓閣暮春光。", "衣冠是日朝天子，草奏何時入帝鄉。"]'),
('eea054bd-aa0c-4d83-931b-7bd4cb9e4715','承聞河北諸道節度入朝歡喜口號絕句十二首 八','杜甫','唐','唐诗','tang','','[]','澶漫山東一百州，削成如桉抱青丘。',32,'全唐诗/poet.tang.11000.json','["澶漫山東一百州，削成如桉抱青丘。", "苞茅重入歸關內，王祭還供盡海頭。"]'),
('761f8b22-e22e-4282-afe9-72db29e8f626','承聞河北諸道節度入朝歡喜口號絕句十二首 九','杜甫','唐','唐诗','tang','','[]','東逾遼水北滹沱，星象風雲喜共和。',32,'全唐诗/poet.tang.11000.json','["東逾遼水北滹沱，星象風雲喜共和。", "紫氣關臨天地闊，黃金臺貯俊賢多。"]'),
('545f7e2c-bb6f-4c24-826d-e137da62626b','承聞河北諸道節度入朝歡喜口號絕句十二首 十','杜甫','唐','唐诗','tang','','[]','漁陽突騎邯鄲兒，酒酣並轡金鞭垂。',32,'全唐诗/poet.tang.11000.json','["漁陽突騎邯鄲兒，酒酣並轡金鞭垂。", "意氣即歸雙闕舞，雄豪復遣五陵知。"]'),
('3bbf18e6-9759-411f-a1e9-dab17c501a16','承聞河北諸道節度入朝歡喜口號絕句十二首 十一','杜甫','唐','唐诗','tang','','[]','李相將軍擁薊門，白頭雖老赤心存。',32,'全唐诗/poet.tang.11000.json','["李相將軍擁薊門，白頭雖老赤心存。", "竟能盡說諸侯入，知有從來天子尊。"]'),
('d3c192f3-be92-462b-8691-98952318810e','承聞河北諸道節度入朝歡喜口號絕句十二首 十二','杜甫','唐','唐诗','tang','','[]','十二年來多戰場，天威已息陣堂堂。',32,'全唐诗/poet.tang.11000.json','["十二年來多戰場，天威已息陣堂堂。", "神靈漢代中興主，功業汾陽異姓王。"]'),
('7b0a1a1a-b2fe-4221-823d-c49b6fe4cf45','喜聞盜賊蕃寇總退口號五首 一','杜甫','唐','唐诗','tang','','["\u9ec4\u6cb3"]','蕭關隴水入官軍，青海黃河卷塞雲。',32,'全唐诗/poet.tang.11000.json','["蕭關隴水入官軍，青海黃河卷塞雲。", "北極轉愁龍虎氣，西戎休縱犬羊羣。"]'),
('aa08844b-7f32-4d6c-9754-a54ee4c31812','喜聞盜賊蕃寇總退口號五首 二','杜甫','唐','唐诗','tang','','[]','贊普多教使入秦，數通和好止煙塵。',32,'全唐诗/poet.tang.11000.json','["贊普多教使入秦，數通和好止煙塵。", "朝廷忽用哥舒將，殺伐虛悲公主親。"]'),
('dbf21098-d1cd-4576-8af7-7d19c49f1503','喜聞盜賊蕃寇總退口號五首 三','杜甫','唐','唐诗','tang','','[]','崆峒西極過崑崙，駝馬由來擁國門。',32,'全唐诗/poet.tang.11000.json','["崆峒西極過崑崙，駝馬由來擁國門。", "逆氣數年吹路斷，蕃人聞道漸星奔。"]'),
('0dacaacd-700f-495c-a03b-b20d4cba7bd7','喜聞盜賊蕃寇總退口號五首 四','杜甫','唐','唐诗','tang','','[]','勃律天西采玉河，堅昆碧盌最來多。',32,'全唐诗/poet.tang.11000.json','["勃律天西采玉河，堅昆碧盌最來多。", "舊隨漢使千堆寶，少荅胡王萬匹羅。"]'),
('50fd5a2b-0e04-410a-9030-1f1a3a75d0a3','喜聞盜賊蕃寇總退口號五首 五','杜甫','唐','唐诗','tang','','[]','今春喜氣滿乾坤，南北東西拱至尊。',32,'全唐诗/poet.tang.11000.json','["今春喜氣滿乾坤，南北東西拱至尊。", "大曆二年調玉燭，玄元皇帝聖雲孫。"]'),
('10b328c2-e211-4351-b921-2cfd04d05e99','洞房','杜甫','唐','唐诗','tang','','["\u9ec4\u5c71"]','洞房環佩冷，玉殿起秋風。',48,'全唐诗/poet.tang.11000.json','["洞房環佩冷，玉殿起秋風。", "秦地應新月，龍池滿舊宮。", "繫舟今夜遠，清漏往時同。", "萬里黃山北，園陵白露中。"]'),
('0366a5ab-545c-4240-96d7-556b4831e749','宿昔','杜甫','唐','唐诗','tang','','[]','宿昔青門裏，蓬萊仗數移。',48,'全唐诗/poet.tang.11000.json','["宿昔青門裏，蓬萊仗數移。", "花嬌迎雜樹，龍喜出平池。", "落日留王母，微風倚少兒。", "宮中行樂祕，少有外人知。"]'),
('b3bb8b3e-8e4e-4501-83e1-e132d94286a5','能畫','杜甫','唐','唐诗','tang','','[]','能畫毛延壽，投壺郭舍人。',48,'全唐诗/poet.tang.11000.json','["能畫毛延壽，投壺郭舍人。", "每蒙天一笑，復似物皆春。", "政化平如水，皇恩斷若神。", "時時用抵戲，亦未雜風塵。"]'),
('33085f30-6606-40c8-99b5-61c4c267e954','鬬雞','杜甫','唐','唐诗','tang','','[]','鬬雞初賜錦，舞馬既登牀。',48,'全唐诗/poet.tang.11000.json','["鬬雞初賜錦，舞馬既登牀。", "簾下宮人出，樓前御柳長。", "仙遊終一閟，女樂久無香。", "寂寞驪山道，清秋草木黃。"]'),
('4d4e5bbc-6394-4a18-8601-5a27899c7db6','鸚鵡','杜甫','唐','唐诗','tang','','[]','鸚鵡含愁思，聰明憶別離。',48,'全唐诗/poet.tang.11000.json','["鸚鵡含愁思，聰明憶別離。", "翠衿渾短盡，紅觜漫多知。", "未有開籠日，空殘舊宿枝。", "世人憐復損，何用羽毛奇。"]'),
('02310cb7-18e8-4d0d-909c-1ef240340ba3','歷歷','杜甫','唐','唐诗','tang','','[]','歷歷開元事，分明在眼前。',48,'全唐诗/poet.tang.11000.json','["歷歷開元事，分明在眼前。", "無端盜賊起，忽已歲時遷。", "巫峽西江外，秦城北斗邊。", "爲郎從白首，臥病數秋天。"]'),
('08057e56-deff-48fe-b60a-f58945fd4476','洛陽','杜甫','唐','唐诗','tang','','[]','洛陽昔陷沒，胡馬犯潼關。',48,'全唐诗/poet.tang.11000.json','["洛陽昔陷沒，胡馬犯潼關。", "天子初愁思，都人慘別顏。", "清笳去宮闕，翠蓋出關山。", "故老仍流涕，龍髯幸再攀。"]'),
('b36a292d-baa6-47fb-a1c2-1fea2127a5a2','驪山','杜甫','唐','唐诗','tang','','[]','驪山絕望幸，花萼罷登臨。',48,'全唐诗/poet.tang.11000.json','["驪山絕望幸，花萼罷登臨。", "地下無朝燭，人間有賜金。", "鼎湖龍去遠，銀海雁飛深。", "萬歲蓬萊日，長懸舊羽林。"]'),
('fef50a5e-24ba-44a0-a1f6-504aba9bac8e','提封','杜甫','唐','唐诗','tang','','[]','提封漢天下，萬國尚同心。',48,'全唐诗/poet.tang.11000.json','["提封漢天下，萬國尚同心。", "借問懸車守，何如儉德臨。", "時徵俊乂入，草竊犬羊侵。", "願戒兵猶火，恩加四海深。"]'),
('751820b9-7a08-41c7-8f9b-356cea9bbf6d','覆舟二首 一','杜甫','唐','唐诗','tang','','[]','巫峽盤渦曉，黔陽貢物秋。',48,'全唐诗/poet.tang.11000.json','["巫峽盤渦曉，黔陽貢物秋。", "丹砂同隕石，翠羽共沈舟。", "羈使空斜影，龍居閟積流。", "篙工幸不溺，俄頃逐輕鷗。"]'),
('9108f782-355e-404d-9cf9-5a1c4a224d10','覆舟二首 二','杜甫','唐','唐诗','tang','','[]','竹宮時望拜，桂館或求仙。',48,'全唐诗/poet.tang.11000.json','["竹宮時望拜，桂館或求仙。", "姹女臨波日，神光照夜年。", "徒聞斬蛟劒，無復爨犀船。", "使者隨秋色，迢迢獨上天。"]'),
('706b060f-bc6b-4d27-956f-c0f19481f770','垂白','杜甫','唐','唐诗','tang','','[]','垂白馮唐老，清秋宋玉悲。',48,'全唐诗/poet.tang.11000.json','["垂白馮唐老，清秋宋玉悲。", "江喧長少睡，樓迥獨移時。", "多難身何補，無家病不辭。", "甘從千日醉，未許七哀詩。"]'),
('9ef7a6cc-5c38-42fc-97ef-1cb713b162e3','草閣','杜甫','唐','唐诗','tang','','[]','草閣臨無地，柴扉永不關。',48,'全唐诗/poet.tang.11000.json','["草閣臨無地，柴扉永不關。", "魚龍迴夜水，星月動秋山。", "久露清初濕，高雲薄未還。", "汎舟慚小婦，飄泊損紅顏。"]'),
('d5efef64-4159-4f6b-87b8-dade0c0e1d4c','江月','杜甫','唐','唐诗','tang','','[]','江月光於水，高樓思殺人。',48,'全唐诗/poet.tang.11000.json','["江月光於水，高樓思殺人。", "天邊長作客，老去一霑巾。", "玉露團清影，銀河沒半輪。", "誰家挑錦字，滅燭翠眉嚬。"]'),
('dd37d952-4886-47b2-a34e-04a357320163','江上','杜甫','唐','唐诗','tang','','[]','江上日多雨，蕭蕭荆楚秋。',48,'全唐诗/poet.tang.11000.json','["江上日多雨，蕭蕭荆楚秋。", "高風下木葉，永夜攬貂裘。", "勳業頻看鏡，行藏獨倚樓。", "時危思報主，衰謝不能休。"]'),
('608a59d1-b256-4b9a-ad3c-068df67a9caa','中夜','杜甫','唐','唐诗','tang','','[]','中夜江山靜，危樓望北辰。',48,'全唐诗/poet.tang.11000.json','["中夜江山靜，危樓望北辰。", "長爲萬里客，有媿百年身。", "故國風雲氣，高堂戰伐塵。", "胡雛負恩澤，嗟爾太平人。"]'),
('0d699470-bc8e-49d9-85e5-b1987b01c2dd','江漢','杜甫','唐','唐诗','tang','','[]','江漢思歸客，乾坤一腐儒。',48,'全唐诗/poet.tang.11000.json','["江漢思歸客，乾坤一腐儒。", "片雲天共遠，永夜月同孤。", "落日心猶壯，秋風病欲疎。", "古來存老馬，不必取長途。"]'),
('e998ebcb-484e-4633-b2c0-1af1d716695a','白露','杜甫','唐','唐诗','tang','','[]','白露團甘子，清晨散馬蹄。',48,'全唐诗/poet.tang.11000.json','["白露團甘子，清晨散馬蹄。", "圃開連石樹，船渡入江溪。", "憑几看魚樂，迴鞭急鳥棲。", "漸知秋實美，幽徑恐多蹊。"]'),
('5f8937e3-49b1-4ee9-93fe-4ea590143f89','孟氏','杜甫','唐','唐诗','tang','','[]','孟氏好兄弟，養親唯小園。',50,'全唐诗/poet.tang.11000.json','["孟氏好兄弟，養親唯小園。", "承顏胝手足，坐客強盤[飧]。", "負米力葵外，讀書秋樹根。", "卜鄰慚近舍，訓子學誰門。"]'),
('5f7fe6b3-f2ec-49ca-9184-fefb6ac4791c','吾宗','杜甫','唐','唐诗','tang','','[]','吾宗老孫子，質樸古人風。',48,'全唐诗/poet.tang.11000.json','["吾宗老孫子，質樸古人風。", "耕鑿安時論，衣冠與世同。", "在家常早起，憂國願年豐。", "語及君臣際，經書滿腹中。"]'),
('7c325d79-2ab7-4b59-87f7-f02a76cf11f2','有歎','杜甫','唐','唐诗','tang','','[]','壯心久零落，白首寄人間。',48,'全唐诗/poet.tang.11000.json','["壯心久零落，白首寄人間。", "天下兵常鬬，江東客未還。", "窮猨號雨雪，老馬怯關山。", "武德開元際，蒼生豈重攀。"]'),
('1fc0dd82-ef4d-4878-b78a-b57a0563df8c','冬深','杜甫','唐','唐诗','tang','','[]','花葉隨天意，江溪共石根。',48,'全唐诗/poet.tang.11000.json','["花葉隨天意，江溪共石根。", "早霞隨類影，寒水各依痕。", "易下楊朱淚，難招楚客魂。", "風濤暮不穩，舍棹宿誰門。"]'),
('2a0fc134-55af-4890-bfee-97059e2711a8','不寐','杜甫','唐','唐诗','tang','','[]','瞿塘夜水黑，城內改更籌。',48,'全唐诗/poet.tang.11000.json','["瞿塘夜水黑，城內改更籌。", "翳翳月沈霧，輝輝星近樓。", "氣衰甘少寐，心弱恨和愁。", "多壘滿山谷，桃源無處求。"]'),
('06b65f11-2127-42e5-a7a6-2def0df40161','月圓','杜甫','唐','唐诗','tang','','[]','孤月當樓滿，寒江動夜扉。',48,'全唐诗/poet.tang.11000.json','["孤月當樓滿，寒江動夜扉。", "委波金不定，照席綺逾依。", "未缺空山靜，高懸列宿稀。", "故園松桂發，萬里共清輝。"]'),
('59dca3f6-e269-4bf8-8bed-0898f4439b34','中宵','杜甫','唐','唐诗','tang','','[]','西閣百尋餘，中宵步綺疏。',48,'全唐诗/poet.tang.11000.json','["西閣百尋餘，中宵步綺疏。", "飛星過水白，落月動沙虛。", "擇木知幽鳥，潛波想巨魚。", "親朋滿天地，兵甲少來書。"]'),
('262a0118-2fc0-4a10-8d1f-6ada29acc66f','遣愁','杜甫','唐','唐诗','tang','','[]','養拙蓬爲戶，茫茫何所開。',48,'全唐诗/poet.tang.11000.json','["養拙蓬爲戶，茫茫何所開。", "江通神女館，地隔望鄉臺。", "漸惜容顏老，無由弟妹來。", "兵戈與人事，回首一悲哀。"]'),
('47ca52f4-7ef9-4ec2-97b8-37b6818b4854','秋清','杜甫','唐','唐诗','tang','','[]','高秋蘇病氣，白髮自能梳。',48,'全唐诗/poet.tang.11000.json','["高秋蘇病氣，白髮自能梳。", "藥餌憎加減，門庭悶掃除。", "杖藜還客拜，愛竹遣兒書。", "十月江平穩，輕舟進所如。"]'),
('5fb2f973-0b17-49be-83d9-7f9d843b04d3','傷秋','杜甫','唐','唐诗','tang','','[]','林僻來人少，山長去鳥微。',72,'全唐诗/poet.tang.11000.json','["林僻來人少，山長去鳥微。", "高秋收畫扇，久客掩荆扉。", "嬾慢頭時櫛，艱難帶減圍。", "將軍猶汗馬，天子尚戎衣。", "白蔣風飆脆，殷檉曉夜稀。", "何年減豺虎，似有故園歸。"]'),
('85451ae3-79af-4fe6-9cc9-09ebcfbea88a','秋峽','杜甫','唐','唐诗','tang','','[]','江濤萬古峽，肺氣久衰翁。',48,'全唐诗/poet.tang.11000.json','["江濤萬古峽，肺氣久衰翁。", "不寐防巴虎，全生狎楚童。", "衣裳垂素髮，門巷落丹楓。", "常怪商山老，兼存翊贊功。"]'),
('db38a424-b607-4c6e-b95e-8d63c5535249','南極','杜甫','唐','唐诗','tang','','[]','南極青山衆，西江白谷分。',72,'全唐诗/poet.tang.11000.json','["南極青山衆，西江白谷分。", "古城疏落木，荒戍密寒雲。", "歲月虵常見，風飆虎或聞。", "近身皆鳥道，殊俗自人羣。", "睥睨登哀柝，矛弧照夕曛。", "亂離多醉尉，愁殺李將軍。"]'),
('dfab541a-0fbf-44c9-87c2-ce2805282869','搖落','杜甫','唐','唐诗','tang','','[]','搖落巫山暮，寒江東北流。',48,'全唐诗/poet.tang.11000.json','["搖落巫山暮，寒江東北流。", "煙塵多戰鼓，風浪少行舟。", "鵝費義之墨，貂餘季子裘。", "長懷報明主，臥病復高秋。"]'),
('533e2212-7d88-4b6d-9f5f-a8d42f4d3627','耳聾','杜甫','唐','唐诗','tang','','[]','生年鶡冠子，歎世鹿皮翁。',48,'全唐诗/poet.tang.11000.json','["生年鶡冠子，歎世鹿皮翁。", "眼復幾時暗，耳從前月聾。", "猨鳴秋淚缺，雀噪晚愁空。", "黃落驚山樹，呼兒問朔風。"]'),
('9b0081cd-53fe-44ba-89cc-e449a3d4cd58','獨坐二首 一','杜甫','唐','唐诗','tang','','[]','竟日雨冥冥，雙崖洗更青。',48,'全唐诗/poet.tang.11000.json','["竟日雨冥冥，雙崖洗更青。", "水花寒落岸，山鳥暮過庭。", "煖老須燕玉，充飢憶楚萍。", "胡笳在樓上，哀怨不堪聽。"]'),
('1cd1e3f3-1e4f-4777-bf97-af23b1d1eb52','獨坐二首 二','杜甫','唐','唐诗','tang','','[]','白狗斜臨北，黃牛更在東。',48,'全唐诗/poet.tang.11000.json','["白狗斜臨北，黃牛更在東。", "峽雲常照夜，江月會兼風。", "曬藥安垂老，應門試小童。", "亦知行不逮，苦恨耳多聾。"]'),
('c9fe2f3f-ff6e-49b6-b0f8-e715036bb664','遠遊','杜甫','唐','唐诗','tang','','[]','江闊浮高棟，雲長出斷山。',48,'全唐诗/poet.tang.11000.json','["江闊浮高棟，雲長出斷山。", "塵沙連越巂，風雨暗荆蠻。", "雁矯銜蘆內，猨啼失木間。", "弊裘蘇季子，歷國未知還。"]'),
('6c8b99af-73d5-4546-9ff4-8b0380c75105','夜','杜甫','唐','唐诗','tang','','[]','露下天高秋水清，空山獨夜旅魂驚。',64,'全唐诗/poet.tang.11000.json','["露下天高秋水清，空山獨夜旅魂驚。", "疎燈自照孤帆宿，新月猶懸雙杵鳴。", "南菊再逢人臥病，北書不至雁無情。", "步蟾倚杖看牛斗，銀漢遙應接鳳城。"]'),
('6b3d0766-ae3c-4bc2-9ee4-eda61ed67a39','暮春','杜甫','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','臥病擁塞在峽中，瀟湘洞庭虛暎空。',64,'全唐诗/poet.tang.11000.json','["臥病擁塞在峽中，瀟湘洞庭虛暎空。", "楚天不斷四時雨，巫峽常吹千里風。", "沙上草閣柳新闇，城邊野池蓮欲紅。", "暮春鴛鷺立洲渚，挾子翻飛還一叢。"]'),
('1085d5c0-7e80-4469-a4e9-3b462ce3ffed','晴二首 一','杜甫','唐','唐诗','tang','','[]','久雨巫山暗，新晴錦繡文。',48,'全唐诗/poet.tang.11000.json','["久雨巫山暗，新晴錦繡文。", "碧知湖外草，紅見海東雲。", "竟日鶯相和，摩霄鶴數羣。", "野花乾更落，風處急紛紛。"]'),
('9135c693-7ee5-4872-b911-523cb07e9953','晴二首 二','杜甫','唐','唐诗','tang','','[]','啼烏爭引子，鳴鶴不歸林。',48,'全唐诗/poet.tang.11000.json','["啼烏爭引子，鳴鶴不歸林。", "下食遭泥去，高飛恨久陰。", "雨聲衝塞盡，日氣射江深。", "迴首周南客，驅馳魏闕心。"]'),
('6a5b10a8-04af-4ffb-bf0e-53e2b12b3275','雨','杜甫','唐','唐诗','tang','','[]','始賀天休雨，還嗟地出雷。',48,'全唐诗/poet.tang.11000.json','["始賀天休雨，還嗟地出雷。", "驟看浮峽過，密作渡江來。", "牛馬行無色，蛟龍鬬不開。", "干戈盛陰氣，未必自陽臺。"]'),
('d3c23bd8-f03b-419f-aabe-bb56e2d8d5a6','月三首 一','杜甫','唐','唐诗','tang','','[]','斷續巫山雨，天河此夜新。',48,'全唐诗/poet.tang.11000.json','["斷續巫山雨，天河此夜新。", "若無青嶂月，愁殺白頭人。", "魍魎移深樹，蝦蟆動半輪。", "故園當北斗，直指照西秦。"]'),
('690ec16d-1c00-4f82-afe0-98e4dd46ead0','月三首 二','杜甫','唐','唐诗','tang','','[]','併照巫山出，新窺楚水清。',48,'全唐诗/poet.tang.11000.json','["併照巫山出，新窺楚水清。", "羈棲愁裏見，二十四迴明。", "必驗升沈體，如知進退情。", "不違銀漢落，亦伴玉繩橫。"]'),
('1bb36fab-99c2-40f7-9f51-bba8dd59741e','月三首 三','杜甫','唐','唐诗','tang','','[]','萬里瞿塘峽，春來六上弦。',48,'全唐诗/poet.tang.11000.json','["萬里瞿塘峽，春來六上弦。", "時時開暗室，故故滿青天。", "爽合風襟靜，高當淚臉懸。", "南飛有烏鵲，夜久落江邊。"]'),
('10e1135b-1b0b-4b2d-8b21-a42b1291862c','雨','杜甫','唐','唐诗','tang','','[]','萬木雲深隱，連山雨未開。',48,'全唐诗/poet.tang.11000.json','["萬木雲深隱，連山雨未開。", "風扉掩不定，水鳥過仍迴。", "鮫館如鳴杼，樵舟豈伐枚。", "清涼破炎毒，衰意欲登臺。"]'),
('34086aad-f0b7-4bdf-8265-db2a77e6b991','晚晴','杜甫','唐','唐诗','tang','','[]','返照斜初徹，浮雲薄未歸。',48,'全唐诗/poet.tang.11000.json','["返照斜初徹，浮雲薄未歸。", "江虹明遠飲，峽雨落餘飛。", "鳧雁終高去，熊羆覺自肥。", "秋分客尚在，竹露夕微微。"]'),
('4933f2f1-a324-454a-a99a-17b8c57f1e35','夜雨','杜甫','唐','唐诗','tang','','[]','小雨夜復密，迴風吹早秋。',48,'全唐诗/poet.tang.11000.json','["小雨夜復密，迴風吹早秋。", "野涼侵閉戶，江滿帶維舟。", "通籍恨多病，爲郎忝薄遊。", "天寒出巫峽，醉別仲宣樓。"]'),
('413966c1-7c3f-44b8-b036-07e38c724d9f','更題','杜甫','唐','唐诗','tang','','[]','只應踏初雪，騎馬發荆州。',48,'全唐诗/poet.tang.11000.json','["只應踏初雪，騎馬發荆州。", "直怕巫山雨，真傷白帝秋。", "羣公蒼玉珮，天子翠雲裘。", "同舍晨趨侍，胡爲淹此留。"]'),
('15bf3c35-1b72-45e2-bf5b-8e3c7c682d7f','歸','杜甫','唐','唐诗','tang','','[]','束帶還騎馬，東西却渡船。',48,'全唐诗/poet.tang.11000.json','["束帶還騎馬，東西却渡船。", "林中才有地，峽外絕無天。", "虛白高人靜，喧卑俗累牽。", "他鄉悅遲暮，不敢廢詩篇。"]'),
('b1b864f4-8bc3-4611-a3c9-b062e67f196f','返照','杜甫','唐','唐诗','tang','','["\u6292\u60c5", "\u611f\u4f24", "\u5199\u666f", "\u4f24\u6000"]','楚王宮北正黃昏，白帝城西過雨痕。',64,'全唐诗/poet.tang.11000.json','["楚王宮北正黃昏，白帝城西過雨痕。", "返照入江翻石壁，歸雲擁樹失山村。", "衰年肺病唯高枕，絕塞愁時早閉門。", "不可久留豺虎亂，南方實有未招魂。"]'),
('0336e989-ea54-4fdc-80b6-ffd5c6595a35','熱三首 一','杜甫','唐','唐诗','tang','','[]','雷霆空霹靂，雲雨竟虛無。',48,'全唐诗/poet.tang.11000.json','["雷霆空霹靂，雲雨竟虛無。", "炎赫衣流汗，低垂氣不蘇。", "乞爲寒水玉，願作冷秋菰。", "何似兒童歲，風涼出舞雩。"]'),
('d0efe7cc-4876-45cd-a1cc-8c8dc6b2753d','熱三首 二','杜甫','唐','唐诗','tang','','[]','瘴雲終不滅，瀘水復西來。',48,'全唐诗/poet.tang.11000.json','["瘴雲終不滅，瀘水復西來。", "閉戶人高臥，歸林鳥却迴。", "峽中都似火，江上只空雷。", "想見陰宮雪，風門颯踏開。"]'),
('41d24b59-60da-48d1-b004-e5c775f60cf4','熱三首 三','杜甫','唐','唐诗','tang','','[]','朱李沈不冷，彫胡炊屢新。',48,'全唐诗/poet.tang.11000.json','["朱李沈不冷，彫胡炊屢新。", "將衰骨盡痛，被褐味空頻。", "歘翕炎蒸景，飄颻征戍人。", "十年可解甲，爲爾一霑巾。"]'),
('4f4eb47c-2993-49d6-b920-c33ce0533a76','日暮','杜甫','唐','唐诗','tang','','["\u5c71\u6751", "\u601d\u4e61"]','牛羊下來久，各已閉柴門。',48,'全唐诗/poet.tang.11000.json','["牛羊下來久，各已閉柴門。", "風月自清夜，江山非故園。", "石泉流暗壁，草露滴秋根。", "頭白燈明裏，何須花燼繁。"]'),
('e68896e5-b85b-4a0b-abf4-4b732cd230e4','八月十五夜月二首 一','杜甫','唐','唐诗','tang','','[]','滿目飛明鏡，歸心折大刀。',48,'全唐诗/poet.tang.11000.json','["滿目飛明鏡，歸心折大刀。", "轉蓬行地遠，攀桂仰天高。", "水路疑霜雪，林棲見羽毛。", "此時瞻白兔，直欲數秋毫。"]'),
('3e5e2a47-232b-4a3c-bc62-67e808b758fe','八月十五夜月二首 二','杜甫','唐','唐诗','tang','','[]','稍下巫山峽，猶銜白帝城。',48,'全唐诗/poet.tang.11000.json','["稍下巫山峽，猶銜白帝城。", "氣沈全浦暗，輪仄半樓明。", "刁斗皆催曉，蟾蜍且自傾。", "張弓倚殘魄，不獨漢家營。"]'),
('7bca90d8-d192-4088-b5a6-d32afe1f3eed','十六夜翫月','杜甫','唐','唐诗','tang','','[]','舊挹金波爽，皆傳玉露秋。',48,'全唐诗/poet.tang.11000.json','["舊挹金波爽，皆傳玉露秋。", "關山隨地闊，河漢近人流。", "谷口樵歸唱，孤城笛起愁。", "巴童渾不寢，半夜有行舟。"]'),
('874082d6-f3bb-4cb7-aced-c69d916cf87a','十七夜對月','杜甫','唐','唐诗','tang','','[]','秋月仍圓夜，江村獨老身。',48,'全唐诗/poet.tang.11000.json','["秋月仍圓夜，江村獨老身。", "捲簾還照客，倚杖更隨人。", "光射潛虬動，明翻宿鳥頻。", "茅齋依橘柚，清切露華新。"]'),
('013587ae-016b-4a6c-be0c-806ac0bc7a12','村雨','杜甫','唐','唐诗','tang','','[]','雨聲傳兩夜，寒事颯高秋。',48,'全唐诗/poet.tang.11000.json','["雨聲傳兩夜，寒事颯高秋。", "挈帶看朱紱，開箱覩黑裘。", "世情只益睡，盜賊敢忘憂。", "松菊新霑洗，茅齊慰遠遊。"]'),
('3d98c50d-4a8b-4238-af88-3f81b0500982','雨晴','杜甫','唐','唐诗','tang','','[]','雨時山不改，晴罷峽如新。',48,'全唐诗/poet.tang.11000.json','["雨時山不改，晴罷峽如新。", "天路看殊俗，秋江思殺人。", "有猨揮淚盡，無犬附書頻。", "故國愁眉外，長歌欲損神。"]'),
('a352e426-485f-4d00-8ae5-98191e2c5a87','晚晴吳郎見過北舍','杜甫','唐','唐诗','tang','','[]','圃畦新雨潤，媿子廢鉏來。',48,'全唐诗/poet.tang.11000.json','["圃畦新雨潤，媿子廢鉏來。", "竹杖交頭拄，柴扉隔徑開。", "欲棲羣鳥亂，未去小童催。", "明日重陽酒，相迎自醱醅。"]'),
('59e5492a-ef96-4327-8f2d-20c50121a30f','暝','杜甫','唐','唐诗','tang','','[]','日下四山陰，山庭嵐氣侵。',48,'全唐诗/poet.tang.11000.json','["日下四山陰，山庭嵐氣侵。", "牛羊歸徑險，鳥雀聚枝深。", "正枕當星劒，收書動玉琴。", "半扉開燭影，欲掩見清砧。"]'),
('0a70ecbe-cc85-4aba-9a58-227f06152fbe','雲','杜甫','唐','唐诗','tang','','[]','龍似瞿唐會，江依白帝深。',48,'全唐诗/poet.tang.11000.json','["龍似瞿唐會，江依白帝深。", "終年常起峽，每夜必通林。", "收穫辭霜渚，分明在夕岑。", "高齋非一處，秀氣豁煩襟。"]'),
('8e9c72c3-ad63-4979-8226-fceaa3fb581e','月','杜甫','唐','唐诗','tang','','[]','四更山吐月，殘夜水明樓。',48,'全唐诗/poet.tang.11000.json','["四更山吐月，殘夜水明樓。", "塵匣元開鏡，風簾自上鉤。", "兔應疑鶴髮，蟾亦戀貂裘。", "斟酌姮娥寡，天寒耐九秋。"]'),
('3f1da5a7-27cc-4c6a-9ba9-aebded7e7a94','雨四首 一','杜甫','唐','唐诗','tang','','[]','微雨不滑道，斷雲疎復行。',48,'全唐诗/poet.tang.11000.json','["微雨不滑道，斷雲疎復行。", "紫崖奔處黑，白鳥去邊明。", "秋日新霑影，寒江舊落聲。", "柴扉臨野碓，半得搗香秔。"]'),
('85cc5878-f657-4443-b3c2-08c9502a0417','雨四首 二','杜甫','唐','唐诗','tang','','[]','江雨舊無時，天晴忽散絲。',48,'全唐诗/poet.tang.11000.json','["江雨舊無時，天晴忽散絲。", "暮秋霑物冷，今日過雲遲。", "上馬迥休出，看鷗坐不辭。", "高軒當灧澦，潤色靜書帷。"]'),
('9c92bbd7-1c25-4ea2-8854-8db8e6de5284','雨四首 三','杜甫','唐','唐诗','tang','','[]','物色歲將晏，天隅人未歸。',48,'全唐诗/poet.tang.11000.json','["物色歲將晏，天隅人未歸。", "朔風鳴淅淅，寒雨下霏霏。", "多病久加飯，衰容新授衣。", "時危覺凋喪，故舊短書稀。"]'),
('eada6f5e-c3ee-452b-898d-7bac588c7607','雨四首 四','杜甫','唐','唐诗','tang','','[]','楚雨石苔滋，京華消息遲。',48,'全唐诗/poet.tang.11000.json','["楚雨石苔滋，京華消息遲。", "山寒青兕呌，江晚白鷗飢。", "神女花鈿落，鮫人織杼悲。", "繁憂不自整，終日灑如絲。"]'),
('e58d6a53-dec7-4aa2-a3a3-597d8a285a0c','夜','杜甫','唐','唐诗','tang','','[]','絕岸風威動，寒房燭影微。',48,'全唐诗/poet.tang.11000.json','["絕岸風威動，寒房燭影微。", "嶺猨霜外宿，江鳥夜深飛。", "獨坐親雄劒，哀歌嘆短衣。", "煙塵繞閶闔，白首壯心違。"]'),
('7b1b2f93-4583-49ea-88fd-4c73870865bb','晨雨','杜甫','唐','唐诗','tang','','["\u5199\u96e8", "\u96e8"]','小雨晨光內，初來葉上聞。',48,'全唐诗/poet.tang.11000.json','["小雨晨光內，初來葉上聞。", "霧交纔灑地，風逆旋隨雲。", "暫起柴荆色，輕霑鳥獸羣。", "麝香山一半，亭午未全分。"]'),
('4abc2b1d-a598-4326-ad60-01e0f5e03b50','返照','杜甫','唐','唐诗','tang','','[]','返照開巫峽，寒空半有無。',48,'全唐诗/poet.tang.11000.json','["返照開巫峽，寒空半有無。", "已低魚復暗，不盡白鹽孤。", "荻岸如秋水，松門似畫圖。", "牛羊識童僕，既夕應傳呼。"]'),
('5a5adb2b-8b62-4798-864c-a68fb6a42e1d','向夕','杜甫','唐','唐诗','tang','','[]','畎畝孤城外，江村亂水中。',48,'全唐诗/poet.tang.11000.json','["畎畝孤城外，江村亂水中。", "深山催短景，喬木易高風。", "鶴下雲汀近，雞棲草屋同。", "琴書散明燭，長夜始堪終。"]'),
('3dcf8e32-9912-4634-bcf6-82dec4e0f31c','曉望','杜甫','唐','唐诗','tang','','[]','白帝更聲盡，陽臺曙色分。',48,'全唐诗/poet.tang.11000.json','["白帝更聲盡，陽臺曙色分。", "高峯寒上日，疊嶺宿霾雲。", "地坼江帆隱，天清木葉聞。", "荆扉對麋鹿，應共爾爲羣。"]'),
('324ddb41-56fb-48a4-9ae5-2a4cc08bfc74','雷','杜甫','唐','唐诗','tang','','[]','巫峽中宵動，滄江十月雷。',48,'全唐诗/poet.tang.11000.json','["巫峽中宵動，滄江十月雷。", "龍虵不成蟄，天地劃爭迴。", "却碾空山過，深蟠絕壁來。", "何須妒雲雨，霹靂楚王臺。"]'),
('07f75444-32aa-439d-814d-317d7b3ce92c','雨','杜甫','唐','唐诗','tang','','[]','冥冥甲子雨，已度立春時。',48,'全唐诗/poet.tang.11000.json','["冥冥甲子雨，已度立春時。", "輕箑煩相向，纖絺恐自疑。", "煙添纔有色，風引更如絲。", "直覺巫山暮，兼催宋玉悲。"]'),
('9fe91db4-435e-411f-9466-27832046fefa','朝二首 一','杜甫','唐','唐诗','tang','','[]','清旭楚宮南，霜空萬嶺含。',48,'全唐诗/poet.tang.11000.json','["清旭楚宮南，霜空萬嶺含。", "野人時獨往，雲木曉相參。", "俊鶻無聲過，飢烏下食貪。", "病身終不動，搖落任江潭。"]'),
('63ed53e6-3ceb-4ee2-841b-b7b650f6a181','朝二首 二','杜甫','唐','唐诗','tang','','[]','浦帆晨初發，郊扉冷未開。',48,'全唐诗/poet.tang.11000.json','["浦帆晨初發，郊扉冷未開。", "村疎黃葉墜，野靜白鷗來。", "礎潤休全濕，雲晴欲半迴。", "巫山冬可怪，昨夜有奔雷。"]'),
('043ea961-e63c-4290-9855-18f4a557fc99','晚','杜甫','唐','唐诗','tang','','[]','杖藜尋晚巷，炙背近牆暄。',48,'全唐诗/poet.tang.11000.json','["杖藜尋晚巷，炙背近牆暄。", "人見幽居僻，吾知拙養尊。", "朝廷問府主，耕稼學山村。", "歸翼飛棲定，寒燈亦閉門。"]'),
('be5139b5-2036-43ab-8e97-dbe0a073e7ba','夜二首 一','杜甫','唐','唐诗','tang','','[]','白夜月休弦，燈花半委眠。',48,'全唐诗/poet.tang.11000.json','["白夜月休弦，燈花半委眠。", "號山無定鹿，落樹有驚蟬。", "暫憶江東鱠，兼懷雪下船。", "蠻歌犯星起，空覺在天邊。"]'),
('942a3584-0241-43e2-ab41-0d63407f0677','夜二首 二','杜甫','唐','唐诗','tang','','[]','城郭悲笳暮，村墟過翼稀。',48,'全唐诗/poet.tang.11000.json','["城郭悲笳暮，村墟過翼稀。", "甲兵年數久，賦歛夜深歸。", "暗樹依巖落，明河繞塞微。", "斗斜人更望，月細鵲休飛。"]'),
('32e55ae3-1751-4afc-b2f9-00d2ad5b6f99','宗武生日','杜甫','唐','唐诗','tang','','[]','小子何時見，高秋此日生。',72,'全唐诗/poet.tang.11000.json','["小子何時見，高秋此日生。", "自從都邑語，已伴老夫名。", "詩是吾家事，人傳世上情。", "熟精文選理，休覓綵衣輕。", "凋瘵筵初秩，欹斜坐不成。", "流霞分片片，涓滴就徐傾。"]'),
('b096aa9c-b7cd-424f-808e-aef597a16cc8','又示宗武','杜甫','唐','唐诗','tang','','[]','覓句新知律，攤書解滿牀。',72,'全唐诗/poet.tang.11000.json','["覓句新知律，攤書解滿牀。", "試吟青玉案，莫羨紫羅囊。", "假日從時飲，明年共我長。", "應須飽經術，已似愛文章。", "十五男兒志，三千弟子行。", "曾參與游夏，達者得升堂。"]'),
('04bf9a4a-a4fc-4ad0-95f0-ee3c63af195c','熟食日示宗文宗武','杜甫','唐','唐诗','tang','','[]','消渴游江漢，羇棲尚甲兵。',48,'全唐诗/poet.tang.11000.json','["消渴游江漢，羇棲尚甲兵。", "幾年逢熟食，萬里逼清明。", "松柏邛山路，風花白帝城。", "汝曹催我老，回首淚縱橫。"]'),
('c9479b1f-ab0c-445d-bf85-aafafbc341b0','又示兩兒','杜甫','唐','唐诗','tang','','[]','令節成吾老，他時見汝心。',48,'全唐诗/poet.tang.11000.json','["令節成吾老，他時見汝心。", "浮生看物變，爲恨與年深。", "長葛書難得，江州涕不禁。", "團圓思弟妹，行坐白頭吟。"]'),
('64534567-3196-4c84-bc73-077e7014b48b','社日兩篇 一','杜甫','唐','唐诗','tang','','[]','九農成德業，百祀發光輝。',48,'全唐诗/poet.tang.11000.json','["九農成德業，百祀發光輝。", "報効神如在，馨香舊不違。", "南翁巴曲醉，北雁塞聲微。", "尚想東方朔，詼諧割肉歸。"]'),
('9109b067-2471-4810-80e4-36e31f4d3c59','社日兩篇 二','杜甫','唐','唐诗','tang','','[]','陳平亦分肉，太史竟論功。',48,'全唐诗/poet.tang.11000.json','["陳平亦分肉，太史竟論功。", "今日江南老，他時渭北童。", "歡娛看絕塞，涕淚落秋風。", "鴛鷺迴金闕，誰憐病峽中。"]'),
('86f844a6-969b-4af7-be73-b1c12c0cd7fb','九日五首 一','杜甫','唐','唐诗','tang','','["\u601d\u5ff5", "\u996e\u9152", "\u767b\u9ad8", "\u91cd\u9633\u8282"]','重陽獨酌杯中酒，抱病起登江上臺。',64,'全唐诗/poet.tang.11000.json','["重陽獨酌杯中酒，抱病起登江上臺。", "竹葉於人既無分，菊花從此不須開。", "殊方日落玄猨哭，舊國霜前白雁來。", "弟妹蕭條各何往，干戈衰謝兩相催。"]'),
('2e32f511-cc12-47dd-9c32-b3ca629c807f','九日五首 二','杜甫','唐','唐诗','tang','','[]','舊日重陽日，傳杯不放杯。',48,'全唐诗/poet.tang.11000.json','["舊日重陽日，傳杯不放杯。", "即今蓬鬢改，但媿菊花開。", "北闕心長戀，西江首獨回。", "茱萸賜朝士，難得一枝來。"]'),
('5eb68e82-7216-4179-9b85-6f04894890b0','九日五首 三','杜甫','唐','唐诗','tang','','[]','舊與蘇司業，兼隨鄭廣文。',48,'全唐诗/poet.tang.11000.json','["舊與蘇司業，兼隨鄭廣文。", "采花香泛泛，坐客醉紛紛。", "野樹歌還倚，秋砧醒却聞。", "歡娛兩冥漠，西北有孤雲。"]'),
('42c8db32-a5d6-4d73-869d-36bd63632165','九日五首 四','杜甫','唐','唐诗','tang','','[]','故里樊川菊，登高素滻源。',72,'全唐诗/poet.tang.11000.json','["故里樊川菊，登高素滻源。", "他時一笑後，今日幾人存。", "巫峽蟠江路，終南對國門。", "繫舟身萬里，伏枕淚雙痕。", "爲客裁烏帽，從兒具綠尊。", "佳辰對羣盜，愁絕更誰論。"]'),
('99953267-a278-429d-8470-cc30ebcb23d8','九日諸人集於林','杜甫','唐','唐诗','tang','','[]','九日明朝是，相要舊俗非。',48,'全唐诗/poet.tang.11000.json','["九日明朝是，相要舊俗非。", "老翁難早出，賢客幸知歸。", "舊采黃花賸，新梳白髮微。", "漫看年少樂，忍淚已霑衣。"]'),
('acc51055-b8fa-4406-97d0-9a15a278e625','大曆二年九月三十日','杜甫','唐','唐诗','tang','','[]','爲客無時了，悲秋向夕終。',48,'全唐诗/poet.tang.11000.json','["爲客無時了，悲秋向夕終。", "瘴餘夔子國，霜薄楚王宮。", "草敵虛嵐翠，花禁冷葉紅。", "年年小搖落，不與故園同。"]'),
('f359eb2d-3671-4965-b5fe-aff74c5291ae','十月一日','杜甫','唐','唐诗','tang','','[]','有瘴非全歇，爲冬亦不難。',48,'全唐诗/poet.tang.11000.json','["有瘴非全歇，爲冬亦不難。", "夜郎溪日暖，白帝峽風寒。", "蒸裹如千室，焦糟幸一柈。", "茲辰南國重，舊俗自相歡。"]'),
('e2964fb5-3402-47eb-875d-39a3c362aa45','孟冬','杜甫','唐','唐诗','tang','','[]','殊俗還多事，方冬變所爲。',48,'全唐诗/poet.tang.11000.json','["殊俗還多事，方冬變所爲。", "破甘霜落爪，嘗稻雪飜匙。", "巫峽寒都薄，烏蠻瘴遠隨。", "終然減灘瀨，暫喜息蛟螭。"]'),
('61b2f98c-604f-4705-9a4e-0c931115db82','冬至','杜甫','唐','唐诗','tang','','[]','年年至日長爲客，忽忽窮愁泥殺人。',64,'全唐诗/poet.tang.11000.json','["年年至日長爲客，忽忽窮愁泥殺人。", "江上形容吾獨老，天邊風俗自相親。", "杖蓼雪後臨丹壑，鳴玉朝來散紫宸。", "心折此時無一寸，路迷何處見三秦。"]'),
('73fad2cd-27f2-41c4-8a73-609a47cb7ca8','小至','杜甫','唐','唐诗','tang','','[]','天時人事日相催，冬至陽生春又來。',64,'全唐诗/poet.tang.11000.json','["天時人事日相催，冬至陽生春又來。", "刺繡五紋添弱線，吹葭六琯動浮灰。", "岸容待臘將舒柳，山意衝寒欲放梅。", "雲物不殊鄉國異，教兒且覆掌中杯。"]'),
('32118e72-1998-4024-8b55-9748d737ff19','覽物','杜甫','唐','唐诗','tang','','["\u9ec4\u6cb3"]','曾爲掾吏趨三輔，憶在潼關詩興多。',64,'全唐诗/poet.tang.11000.json','["曾爲掾吏趨三輔，憶在潼關詩興多。", "巫峽忽如瞻華岳，蜀江猶似見黃河。", "舟中得病移衾枕，洞口經春長薜蘿。", "形勝有餘風土惡，幾時回首一高歌。"]'),
('5f744f20-8aa2-452d-90d9-0a35661500b8','憶鄭南玭','杜甫','唐','唐诗','tang','','[]','鄭南伏毒寺，瀟灑到江心。',48,'全唐诗/poet.tang.11000.json','["鄭南伏毒寺，瀟灑到江心。", "石影銜珠閣，泉聲帶玉琴。", "風杉曾曙倚，雲嶠憶春臨。", "萬里滄浪外，龍蛇只自深。"]'),
('7f30df76-f2b1-4af1-812d-2141b289a801','懷灞上游','杜甫','唐','唐诗','tang','','[]','悵望東陵道，平生灞上游。',48,'全唐诗/poet.tang.11000.json','["悵望東陵道，平生灞上游。", "春濃停野騎，夜宿敞雲樓。", "離別人誰在，經過老自休。", "眼前今古意，江漢一歸舟。"]'),
('2fcf79dd-3517-459b-8b4c-2d270073d8f9','愁','杜甫','唐','唐诗','tang','','[]','江草日日喚愁生，巫峽泠泠非世情。',64,'全唐诗/poet.tang.11000.json','["江草日日喚愁生，巫峽泠泠非世情。", "盤渦鷺浴底心性，獨樹花發自分明。", "十年戎馬暗萬國，異域賓客老孤城。", "渭水秦山得見否，人經罷病虎縱橫。"]'),
('af29ed64-419d-4eeb-803a-8466d45a7a2b','晝夢','杜甫','唐','唐诗','tang','','["\u6292\u60c5", "\u5fe7\u56fd", "\u6101\u7eea"]','二月饒睡昏昏然，不獨夜短晝分眠。',64,'全唐诗/poet.tang.11000.json','["二月饒睡昏昏然，不獨夜短晝分眠。", "桃花氣暖眼自醉，春渚日落夢相牽。", "故鄉門巷荆棘底，中原君臣豺虎邊。", "安得務農息戰鬬，普天無吏橫索錢。"]'),
('11b3901b-45f3-44c6-a660-8b989e9d795f','覽鏡呈柏中丞','杜甫','唐','唐诗','tang','','[]','渭水流關內，終南在日邊。',48,'全唐诗/poet.tang.11000.json','["渭水流關內，終南在日邊。", "膽銷豺虎窟，淚入犬羊天。", "起晚堪從事，行遲更學仙。", "鏡中衰謝色，萬一故人憐。"]'),
('2d134030-f67d-48b9-b743-bc87db6edbd2','即事','杜甫','唐','唐诗','tang','','["\u6625\u5929", "\u6292\u60c5", "\u60c6\u6005", "\u666f\u8272"]','暮春三月巫峽長，皛皛行雲浮日光。',64,'全唐诗/poet.tang.11000.json','["暮春三月巫峽長，皛皛行雲浮日光。", "雷聲忽送千峰雨，花氣渾如百和香。", "黃鶯過水飜迴去，燕子銜泥濕不妨。", "飛閣卷簾圖畫里，虛無只少對瀟湘。"]'),
('f025f691-f758-4eab-b603-b3a6ea5fd5a2','即事','杜甫','唐','唐诗','tang','','[]','天畔羣山孤草亭，江中風浪雨冥冥。',64,'全唐诗/poet.tang.11000.json','["天畔羣山孤草亭，江中風浪雨冥冥。", "一雙白魚不受釣，三寸黃甘猶自青。", "多病馬卿無日起，窮途阮籍幾時醒。", "未聞細柳散金甲，腸斷秦川流濁涇。"]'),
('47f436f0-773e-4950-955f-02fa11806b60','悶','杜甫','唐','唐诗','tang','','[]','瘴癘浮三蜀，風雲暗百蠻。',48,'全唐诗/poet.tang.11000.json','["瘴癘浮三蜀，風雲暗百蠻。", "卷簾唯白水，隱几亦青山。", "猨捷長難見，鷗輕故不還。", "無錢從滯客，有鏡巧催顏。"]'),
('3f3971c6-08a0-4a9b-9afa-9f9bacedc485','戲作俳諧體遣悶二首 一','杜甫','唐','唐诗','tang','','[]','異俗吁可怪，斯人難竝居。',48,'全唐诗/poet.tang.11000.json','["異俗吁可怪，斯人難竝居。", "家家養烏鬼，頓頓食黃魚。", "舊識能爲態，新知已暗疎。", "治生且耕鑿，只有不關渠。"]'),
('fbe59952-b373-49cb-9578-fe33c09ba5c2','戲作俳諧體遣悶二首 二','杜甫','唐','唐诗','tang','','[]','西歷青羌板，南留白帝城。',48,'全唐诗/poet.tang.11000.json','["西歷青羌板，南留白帝城。", "於菟侵客恨，粔籹作人情。", "瓦卜傳神語，畬田費火聲。", "是非何處定，高枕笑浮生。"]'),
('a80b6c10-6672-4efb-ba89-6ef86beab5bf','得舍弟觀書自中都已達江陵今茲暮春月末行李合到夔州悲喜相兼團圓可待賦詩即事情見乎詞','杜甫','唐','唐诗','tang','','[]','爾到江陵府，何時到峽州？',48,'全唐诗/poet.tang.11000.json','["爾到江陵府，何時到峽州？", "亂難生有別，聚集病應瘳。", "颯颯開啼眼，朝朝上水樓。", "老身須付託，白骨更何憂。"]'),
('cf68f337-d8fc-48a3-b89e-a828d08189a6','喜觀即到復題短篇二首 一','杜甫','唐','唐诗','tang','','[]','巫峽千山暗，終南萬里春。',48,'全唐诗/poet.tang.11000.json','["巫峽千山暗，終南萬里春。", "病中吾見弟，書到汝爲人。", "意荅兒童問，來經戰伐新。", "泊船悲喜後，款款話歸秦。"]'),
('c72f883a-a7ee-4905-8dea-a0315c738a02','喜觀即到復題短篇二首 二','杜甫','唐','唐诗','tang','','[]','待爾嗔烏鵲，拋書示鶺鴒。',48,'全唐诗/poet.tang.11000.json','["待爾嗔烏鵲，拋書示鶺鴒。", "枝間喜不去，原上急曾經。", "江閣嫌津柳，風帆數驛亭。", "應論十年事，愁絕始星星。"]'),
('e3e5281a-acc8-4fed-8465-8bb4571e1772','舍弟觀歸藍田迎新婦送示兩篇 一','杜甫','唐','唐诗','tang','','["\u957f\u6c5f"]','汝去迎妻子，高秋念却迴。',48,'全唐诗/poet.tang.11000.json','["汝去迎妻子，高秋念却迴。", "即今螢已亂，好與雁同來。", "東望西江水，南游北戶開。", "卜居期靜處，會有故人杯。"]'),
('cc21a6b4-7895-4de7-ab76-e68938f6d000','舍弟觀歸藍田迎新婦送示兩篇 二','杜甫','唐','唐诗','tang','','[]','楚塞難爲路，藍田莫滯留。',48,'全唐诗/poet.tang.11000.json','["楚塞難爲路，藍田莫滯留。", "衣裳判白露，鞍馬信清秋。", "滿峽重江水，開帆八月舟。", "此時同一醉，應在仲宣樓。"]'),
('1d14e01f-3e98-434b-8861-c6335b7b8bfa','第五弟豐獨在江左近三四載寂無消息覓使寄此二首 一','杜甫','唐','唐诗','tang','','[]','亂後嗟吾在，羇棲見汝難。',48,'全唐诗/poet.tang.11000.json','["亂後嗟吾在，羇棲見汝難。", "草黃騏驥病，沙晚鶺鴒寒。", "楚設關城險，吳吞水府寬。", "十年朝夕淚，衣袖不曾乾。"]'),
('d62fc4c1-c077-430f-b1e3-6cfab542626d','第五弟豐獨在江左近三四載寂無消息覓使寄此二首 二','杜甫','唐','唐诗','tang','','[]','聞汝依山寺，杭州定越州。',48,'全唐诗/poet.tang.11000.json','["聞汝依山寺，杭州定越州。", "風塵淹別日，江漢失清秋。", "影蓋啼猨樹，魂飄結蜃樓。", "明年下春水，東盡白雲求。"]'),
('b8a248b0-23e9-4a15-b6b2-2e41eff3b430','舍弟觀赴藍田取妻子到江陵喜寄三首 一','杜甫','唐','唐诗','tang','','[]','汝迎妻子達荆州，消息真傳解我憂。',64,'全唐诗/poet.tang.11000.json','["汝迎妻子達荆州，消息真傳解我憂。", "鴻雁影來連峽內，鶺鴒飛急到沙頭。", "嶢關險路今虛遠，禹鑿寒江正穩流。", "朱紱即當隨彩鷁，青春不假報黃牛。"]'),
('066963f7-a2f3-44bf-821c-2a1778987a44','舍弟觀赴藍田取妻子到江陵喜寄三首 二','杜甫','唐','唐诗','tang','','[]','馬度秦關雪正深，北來肌骨苦寒侵。',64,'全唐诗/poet.tang.11000.json','["馬度秦關雪正深，北來肌骨苦寒侵。", "他鄉就我生春色，故國移居見客心。", "賸欲提攜如意舞，喜多行坐白頭吟。", "巡檐索共梅花笑，冷蘂疎枝半不禁。"]'),
('3fb1f819-6534-4a57-ac68-47df60a71dd8','舍弟觀赴藍田取妻子到江陵喜寄三首 三','杜甫','唐','唐诗','tang','','[]','庾信羅含俱有宅，春來秋去作誰家。',64,'全唐诗/poet.tang.11000.json','["庾信羅含俱有宅，春來秋去作誰家。", "短牆若在從殘草，喬木如存可假花。", "卜築應同蔣詡徑，爲園須似邵平瓜。", "比年病酒開涓滴，弟勸兄酬何怨嗟。"]'),
('27325080-ff2f-4215-80b3-5c9e56c319d2','江雨有懷鄭典設','杜甫','唐','唐诗','tang','','[]','春雨闇闇塞峽中，早晚來自楚王宮。',64,'全唐诗/poet.tang.11000.json','["春雨闇闇塞峽中，早晚來自楚王宮。", "亂波分披已打岸，弱雲狼籍不禁風。", "寵光蕙葉與多碧，點注桃花舒小紅。", "谷口子真正憶汝，岸高瀼滑限西東。"]'),
('1b39ff1f-95d3-43b6-ad22-561c8e97f329','王十五前閣會','杜甫','唐','唐诗','tang','','[]','楚岸收新雨，春臺引細風。',48,'全唐诗/poet.tang.11000.json','["楚岸收新雨，春臺引細風。", "情人來石上，鮮膾出江中。", "鄰舍煩書札，肩輿強老翁。", "病身虛俊味，何幸飫兒童。"]'),
('f0f46788-340a-4f53-938d-fc410d36b6a5','寄韋有夏郎中','杜甫','唐','唐诗','tang','','[]','省郎憂病士，書信有柴胡。',72,'全唐诗/poet.tang.11000.json','["省郎憂病士，書信有柴胡。", "飲子頻通汗，懷君想報珠。", "親知天畔少，藥味峽中無。", "歸楫生衣臥，春鷗洗翅呼。", "猶聞上急水，早作取平途。", "萬里皇華使，爲僚記腐儒。"]'),
('11571817-7134-4718-aff3-78fbc55d9261','陪柏中丞觀宴將士二首 一','杜甫','唐','唐诗','tang','','[]','極樂三軍士，誰知百戰場。',48,'全唐诗/poet.tang.11000.json','["極樂三軍士，誰知百戰場。", "無私齊綺饌，久坐密金章。", "醉客霑鸚鵡，佳人指鳳皇。", "幾時來翠節，特地引紅妝。"]'),
('d8a96faa-dbf2-4aee-9c9f-23e1294413dd','陪柏中丞觀宴將士二首 二','杜甫','唐','唐诗','tang','','[]','繡段裝檐額，金花帖鼓腰。',48,'全唐诗/poet.tang.11000.json','["繡段裝檐額，金花帖鼓腰。", "一夫先舞劒，百戰後歌樵。", "江樹城孤遠，雲臺使寂寥。", "漢朝頻選將，應拜霍嫖姚。"]'),
('de2c4fcb-b84a-48a2-aa95-d224db25259a','七月一日題終明府水樓二首 一','杜甫','唐','唐诗','tang','','[]','高棟曾軒已自涼，秋風此日灑衣裳。',64,'全唐诗/poet.tang.11000.json','["高棟曾軒已自涼，秋風此日灑衣裳。", "翛然欲下陰山雪，不去非無漢署香。", "絕辟過雲開錦繡，疎松夾水奏笙簧。", "看君宜著王喬履，真賜還疑出尚方。"]'),
('d87ed489-916b-4f7a-8a7d-fdf3078ef511','七月一日題終明府水樓二首 二','杜甫','唐','唐诗','tang','','[]','宓子彈琴邑宰日，終軍棄繻英妙時。',64,'全唐诗/poet.tang.11000.json','["宓子彈琴邑宰日，終軍棄繻英妙時。", "承家節操尚不泯，爲政風流今在茲。", "可憐賓客盡傾蓋，何處老翁來賦詩。", "楚江巫峽半雲雨，清簟疎簾看弈棊。"]'),
('edfc3534-4103-4c5f-965e-72778db7bc01','季秋蘇五弟纓江樓夜宴崔十三評事韋少府姪三首 一','杜甫','唐','唐诗','tang','','[]','峽險江驚急，樓高月迥明。',48,'全唐诗/poet.tang.11000.json','["峽險江驚急，樓高月迥明。", "一時今夕會，萬里故鄉情。", "星落黃姑渚，秋辭白帝城。", "老人因酒病，堅坐看君傾。"]'),
('fe486143-8dbd-4391-ae7b-2a36a4858d2b','季秋蘇五弟纓江樓夜宴崔十三評事韋少府姪三首 二','杜甫','唐','唐诗','tang','','[]','明月生長好，浮雲薄漸遮。',48,'全唐诗/poet.tang.11000.json','["明月生長好，浮雲薄漸遮。", "悠悠照邊塞，悄悄憶京華。", "清動杯中物，高隨海上查。", "不眠瞻白兔，百過落烏紗。"]'),
('a63d70ba-5ee4-4cce-9062-4cb425497f7f','季秋蘇五弟纓江樓夜宴崔十三評事韋少府姪三首 三','杜甫','唐','唐诗','tang','','[]','對月那無酒，登樓況有江。',48,'全唐诗/poet.tang.11000.json','["對月那無酒，登樓況有江。", "聽歌驚白鬢，笑舞拓秋窗。", "尊蟻添相續，沙鷗竝一雙。", "盡憐君醉倒，更覺片心降。"]'),
('2ab6e7da-29bb-4c2b-8dd5-c23ec5725d97','九月一日過孟十二倉曹十四主簿兄弟','杜甫','唐','唐诗','tang','','[]','藜杖侵寒露，蓬門啓曙煙。',48,'全唐诗/poet.tang.11000.json','["藜杖侵寒露，蓬門啓曙煙。", "力稀經樹歇，老困撥書眠。", "秋覺追隨盡，來因孝友偏。", "清談見滋味，爾輩可忘年。"]'),
('db532d17-1533-4e02-8355-5dd36690106f','過客相尋','杜甫','唐','唐诗','tang','','[]','窮老真無事，江山已定居。',48,'全唐诗/poet.tang.11000.json','["窮老真無事，江山已定居。", "地幽忘盥櫛，客至罷琴書。", "挂壁移筐果，呼兒問煮魚。", "時聞繫舟楫，及此問吾廬。"]'),
('a6db70bd-85c9-4fc5-900d-878c34a96df7','孟倉曹步趾領新酒醬二物滿器見遺老夫','杜甫','唐','唐诗','tang','','[]','楚岸通秋屐，胡牀面夕畦。',48,'全唐诗/poet.tang.11000.json','["楚岸通秋屐，胡牀面夕畦。", "藉糟分汁滓，甕醬落提攜。", "飯糲添香味，朋來有醉泥。", "理生那免俗，方法報山妻。"]'),
('97384a23-7f75-4d43-baee-ac6c4a6c6d14','柳司馬至','杜甫','唐','唐诗','tang','','[]','有使歸三峽，相過問兩京。',72,'全唐诗/poet.tang.11000.json','["有使歸三峽，相過問兩京。", "函關猶出將，渭水更屯兵。", "設備邯鄲道，和親邏些城。", "幽燕唯鳥去，商洛少人行。", "衰謝身何補，蕭條病轉嬰。", "霜天到宮闕，戀主寸心明。"]'),
('db1025d2-bf15-46df-af97-d96aa4b570e8','簡吳郎司法','杜甫','唐','唐诗','tang','','[]','有客乘舸自忠州，遣騎安置瀼西頭。',64,'全唐诗/poet.tang.11000.json','["有客乘舸自忠州，遣騎安置瀼西頭。", "古堂本買藉疎豁，借汝遷居停宴遊。", "雲石熒熒高葉曙，風江颯颯亂帆秋。", "却爲姻婭過逢地，許坐曾軒數散愁。"]'),
('c18b9273-a4d2-493b-8320-5025f2d174f7','又呈吳郎','杜甫','唐','唐诗','tang','','["\u5fe7\u56fd\u5fe7\u6c11"]','堂前撲棗任西鄰，無食無兒一婦人。',64,'全唐诗/poet.tang.11000.json','["堂前撲棗任西鄰，無食無兒一婦人。", "不爲困窮寧有此，祗緣恐懼轉須親。", "即防遠客雖多事，使插疎籬却甚真。", "已訴徵求貧到骨，正思戎馬淚盈巾。"]'),
('db033ee9-5ef8-4acb-8606-c777217f7ae8','覃山人隱居','杜甫','唐','唐诗','tang','','[]','南極老人自有星，北山移文誰勒銘。',64,'全唐诗/poet.tang.11000.json','["南極老人自有星，北山移文誰勒銘。", "徵君已去獨松菊，哀壑無光留戶庭。", "予見亂離不得已，子知出處必須經。", "高車駟馬帶傾覆，悵望秋天虛翠屏。"]'),
('9b51ca3b-92b6-4a73-b382-201a23ac190f','柏學士茅屋','杜甫','唐','唐诗','tang','','["\u8bfb\u4e66"]','碧山學士焚銀魚，白馬却走身巖居。',64,'全唐诗/poet.tang.11000.json','["碧山學士焚銀魚，白馬却走身巖居。", "古人已用三冬足，年少今開萬卷餘。", "晴雲滿戶團傾蓋，秋水浮階溜決渠。", "富貴必從勤苦得，男兒須讀五車書。"]'),
('9cc1af26-0421-4d87-bc86-8a5f069f9618','題柏大兄弟山居屋壁二首 一','杜甫','唐','唐诗','tang','','[]','叔父朱門貴，郎君玉樹高。',48,'全唐诗/poet.tang.11000.json','["叔父朱門貴，郎君玉樹高。", "山居精典籍，文雅涉風騷。", "江漢終吾老，雲林得爾曹。", "哀弦繞白雪，未與俗人操。"]'),
('277fdcd3-6161-402c-a8c7-d7fc6e7b31f3','題柏大兄弟山居屋壁二首 二','杜甫','唐','唐诗','tang','','[]','野屋流寒水，山籬帶薄雲。',48,'全唐诗/poet.tang.11000.json','["野屋流寒水，山籬帶薄雲。", "靜應連虎穴，喧已去人羣。", "筆架霑窗雨，書籤映隙曛。", "蕭蕭千里足，箇箇五花文。"]'),
('86cfbd16-96b4-47c6-9142-6a804159e696','戲寄崔評事表姪蘇五表弟韋大少府諸姪','杜甫','唐','唐诗','tang','','[]','隱豹深愁雨，潛龍故起雲。',48,'全唐诗/poet.tang.11000.json','["隱豹深愁雨，潛龍故起雲。", "泥多仍徑曲，心醉阻賢羣。", "忍待江山麗，還披鮑謝文。", "高樓憶疎豁，秋興坐氛氳。"]'),
('3cf55595-28d2-4205-af87-cc08359db896','秋日寄題鄭監湖上亭三首 一','杜甫','唐','唐诗','tang','','[]','碧草逢春意，沅湘萬里秋。',48,'全唐诗/poet.tang.11000.json','["碧草逢春意，沅湘萬里秋。", "池要山簡馬，月淨庾公樓。", "磨滅餘篇翰，平生一釣舟。", "高唐寒浪減，髣髴識昭丘。"]'),
('8e04fb98-104f-4d84-8037-e1e6797e9039','秋日寄題鄭監湖上亭三首 二','杜甫','唐','唐诗','tang','','[]','新作湖邊宅，還聞賓客過。',48,'全唐诗/poet.tang.11000.json','["新作湖邊宅，還聞賓客過。", "自須開竹逕，誰道避雲蘿。", "官序潘生拙，才名賈傅多。", "舍舟應轉地，鄰接意如何。"]'),
('75313436-93f3-4c30-a0ce-be80991b37bf','秋日寄題鄭監湖上亭三首 三','杜甫','唐','唐诗','tang','','[]','暫阻蓬萊閣，終爲江海人。',48,'全唐诗/poet.tang.11000.json','["暫阻蓬萊閣，終爲江海人。", "揮金應物理，拖玉豈吾身。", "羹煮秋蓴滑，杯迎露菊新。", "賦詩分氣象，佳句莫頻頻。"]'),
('e0fd6680-7e2c-4e1f-88bc-7ddd77c0789c','謁真諦寺禪師','杜甫','唐','唐诗','tang','','[]','蘭若山高處，煙霞嶂幾重。',48,'全唐诗/poet.tang.11000.json','["蘭若山高處，煙霞嶂幾重。", "凍泉依細石，晴雪落長松。", "問法看詩忘，觀身向酒慵。", "未能割妻子，卜宅近前峰。"]'),
('0201eede-b035-4751-a5b5-e2bfbdc6caa2','別崔潩因寄薛據孟雲卿','杜甫','唐','唐诗','tang','','[]','志士惜妄動，知深難固辭。',48,'全唐诗/poet.tang.11000.json','["志士惜妄動，知深難固辭。", "如何久磨礪，但取不磷緇。", "夙夜聽憂主，飛騰急濟時。", "荆州過薛孟，爲報欲論詩。"]'),
('51e0d2da-d7db-4cd4-bdf8-a8f915a4834f','送李八祕書赴杜相公幕','杜甫','唐','唐诗','tang','','[]','青簾白舫益州來，巫峽秋濤天地迴。',64,'全唐诗/poet.tang.11000.json','["青簾白舫益州來，巫峽秋濤天地迴。", "石出倒聽楓葉下，櫓搖背指菊花開。", "貪趨相府今晨發，恐失佳期後命催。", "南極一星朝北斗，五雲多處是三台。"]'),
('0c7375da-6cc8-4663-8397-1f4497397a18','巫峽敝廬奉贈侍御四舅別之澧朗','杜甫','唐','唐诗','tang','','[]','江城秋日落，山鬼閉門中。',48,'全唐诗/poet.tang.11000.json','["江城秋日落，山鬼閉門中。", "行李淹吾舅，誅茅問老翁。", "赤眉猶世亂，青眼只途窮。", "傳語桃源客，人今出處同。"]'),
('151ea59e-59ce-4a29-bdfa-26448921b811','奉送十七舅下邵桂','杜甫','唐','唐诗','tang','','[]','絕域三冬暮，浮生一病身。',48,'全唐诗/poet.tang.11000.json','["絕域三冬暮，浮生一病身。", "感深辭舅氏，別後見何人。", "飄緲蒼梧帝，推遷孟母鄰。", "昏昏阻雲水，側望苦傷神。"]'),
('e8d93d2a-44ab-43e6-9ba9-bbc9842ccd8f','送覃二判官','杜甫','唐','唐诗','tang','','[]','先帝弓劒遠，小臣餘此生。',72,'全唐诗/poet.tang.11000.json','["先帝弓劒遠，小臣餘此生。", "蹉跎病江漢，不復謁承明。", "餞爾白頭日，永懷丹鳳城。", "遲遲戀屈宋，渺渺臥荆衡。", "魂斷航舸失，天寒沙水清。", "肺肝若稍愈，亦上赤霄行。"]'),
('b4ffde4f-9b57-4829-848c-948b12846150','季夏送鄉弟韶陪黃門從叔朝謁','杜甫','唐','唐诗','tang','','[]','令弟尚爲蒼水使，名家莫出杜陵人。',64,'全唐诗/poet.tang.11000.json','["令弟尚爲蒼水使，名家莫出杜陵人。", "比來相國兼安蜀，歸赴朝廷已入秦。", "舍舟策馬論兵地，拖玉腰金報主身。", "莫度清秋吟蟋蟀，早聞黃閣畫麒麟。"]'),
('807194fc-963a-4171-94f7-0b8ade8d98b2','送十五弟侍御使蜀','杜甫','唐','唐诗','tang','','[]','喜弟文章進，添余別興牽。',48,'全唐诗/poet.tang.11000.json','["喜弟文章進，添余別興牽。", "數杯巫峽酒，百丈內江船。", "未息豺狼鬬，空催犬馬年。", "歸朝多便道，搏擊望秋天。"]'),
('c5f9005f-2a05-4f87-918a-155cb2c81221','送田四弟將軍將夔州柏中丞命起居江陵節度陽城郡王衛公幕','杜甫','唐','唐诗','tang','','[]','離筵罷多酒，起地發寒塘。',48,'全唐诗/poet.tang.11000.json','["離筵罷多酒，起地發寒塘。", "回首中丞座，馳牋異姓王。", "燕辭楓樹日，雁度麥城霜。", "空醉山翁酒，遙憐似葛強。"]'),
('0df82a0f-70f4-488f-afbb-8923dbbe29da','送王十六判官','杜甫','唐','唐诗','tang','','[]','客下荆南盡，君今復入舟。',48,'全唐诗/poet.tang.11000.json','["客下荆南盡，君今復入舟。", "買薪猶白帝，鳴櫓少沙頭。", "衡霍生春早，瀟湘共海浮。", "荒林庾信宅，爲仗主人留。"]'),
('334efb9b-c7a8-482a-a971-fd8aa7b0b3c6','奉送卿二翁統節度鎮軍還江陵','杜甫','唐','唐诗','tang','','[]','火旗還錦纜，白馬出江城。',48,'全唐诗/poet.tang.11000.json','["火旗還錦纜，白馬出江城。", "嘹唳吟笳發，簫條別浦清。", "寒空巫峽曙，落日渭陽明。", "留滯嗟衰疾，何時見息兵。"]'),
('bcd11e7d-2617-4fc3-9b26-8a0ff5bc2ed2','送鮮于萬州遷巴州','杜甫','唐','唐诗','tang','','[]','京兆先時傑，琳琅照一門。',48,'全唐诗/poet.tang.11000.json','["京兆先時傑，琳琅照一門。", "朝廷偏注意，接近與名藩。", "祖帳排舟數，寒江觸石喧。", "看君妙爲政，他日有殊恩。"]'),
('586773dd-0a2a-4bef-a704-7d6d647df4c9','寄杜位','杜甫','唐','唐诗','tang','','[]','寒日經檐短，窮猨失木悲。',48,'全唐诗/poet.tang.11000.json','["寒日經檐短，窮猨失木悲。", "峽中爲客恨，江上憶君時。", "天地身何在，風塵病敢辭。", "封書兩行淚，霑灑裛新詩。"]'),
('471d2960-d646-4055-8242-ef298fb6aa7b','奉寄李十五祕書二首 一','杜甫','唐','唐诗','tang','','[]','避暑雲安縣，秋風早下來。',48,'全唐诗/poet.tang.11000.json','["避暑雲安縣，秋風早下來。", "暫留魚復浦，同過楚王臺。", "猨鳥千崖窄，江湖萬里開。", "竹枝歌未好，畫舸莫遲回。"]'),
('ef10e28c-207f-41f0-9345-91d09ef08bf1','奉寄李十五祕書二首 二','杜甫','唐','唐诗','tang','','[]','行李千金贈，衣冠八尺身。',48,'全唐诗/poet.tang.11000.json','["行李千金贈，衣冠八尺身。", "飛騰知有策，意度不無神。", "班秩兼通貴，公侯出異人。", "玄成負文彩，世業豈沈淪。"]'),
('79e0454e-6d35-47fb-80c1-15f9d6632cea','奉送韋中丞之晉赴湖南','杜甫','唐','唐诗','tang','','[]','寵渥徵黃漸，權宜借寇頻。',48,'全唐诗/poet.tang.11000.json','["寵渥徵黃漸，權宜借寇頻。", "湖南安背水，峽內憶行春。", "王室仍多故，蒼生倚大臣。", "還將徐孺子，處處待高人。"]'),
('64528c95-a028-4b37-923d-698bed06ae4c','送李功曹之荆州充鄭侍御判官重贈','杜甫','唐','唐诗','tang','','[]','曾聞宋玉宅，每欲到荆州。',48,'全唐诗/poet.tang.11000.json','["曾聞宋玉宅，每欲到荆州。", "此地生涯晚，遙悲水國秋。", "孤城一柱觀，落日九江流。", "使者雖光彩，青楓遠自愁。"]'),
('c8fcabe4-cdf3-454d-8cbd-b2f78765e6c8','送孟十二倉曹赴東京選','杜甫','唐','唐诗','tang','','[]','君行別老親，此去苦家貧。',48,'全唐诗/poet.tang.11000.json','["君行別老親，此去苦家貧。", "藻鏡留連客，江山顦顇人。", "秋風楚竹冷，夜雪鞏梅春。", "朝夕高堂念，應宜綵服新。"]'),
('c2fc978a-c284-4c06-8f72-eb5041b21e56','憑孟倉曹將書覓土婁舊莊','杜甫','唐','唐诗','tang','','[]','平居喪亂後，不到洛陽岑。',48,'全唐诗/poet.tang.11000.json','["平居喪亂後，不到洛陽岑。", "爲歷雲山問，無辭荆棘深。", "北風黃葉下，南浦白頭吟。", "十載江湖客，茫茫遲暮心。"]'),
('0901271a-f225-4a78-b7cf-bcd2fb3e0d7e','別蘇徯（赴湖南幕）','杜甫','唐','唐诗','tang','','[]','故人有遊子，棄擲傍天隅。',120,'全唐诗/poet.tang.11000.json','["故人有遊子，棄擲傍天隅。", "他日憐才命，居然屈壯圖。", "十年猶塌翼，絕倒爲驚吁。", "消渴今如在，提攜媿老夫。", "豈知臺閣舊，先拂鳳皇雛。", "得實飜蒼竹，棲枝把翠梧。", "北辰當宇宙，南岳據江湖。", "國帶風塵色，兵張虎豹符。", "數論封內事，揮發府中趨。", "贈爾秦人策，莫鞭轅下駒。"]'),
('ecf1ba79-ab9c-4f01-ad7c-0f31bad80f4d','存歿口號二首 一','杜甫','唐','唐诗','tang','','[]','席謙不見近彈棊，畢曜仍傳舊小詩。',32,'全唐诗/poet.tang.11000.json','["席謙不見近彈棊，畢曜仍傳舊小詩。", "玉局他年無限笑，白楊今日幾人悲。"]'),
('b1e5870f-b85d-4297-96cb-8cff7d558433','存歿口號二首 二','杜甫','唐','唐诗','tang','','[]','鄭公粉繪隨長夜，曹霸丹青已白頭。',32,'全唐诗/poet.tang.11000.json','["鄭公粉繪隨長夜，曹霸丹青已白頭。", "天下何曾有山水，人間不解重驊騮。"]'),
('f8055804-4c69-4e9d-b63c-d649c86a6b5f','奉漢中王手札報韋侍御蕭尊師亡','杜甫','唐','唐诗','tang','','[]','秋日蕭韋逝，淮王報峽中。',72,'全唐诗/poet.tang.11000.json','["秋日蕭韋逝，淮王報峽中。", "少年疑柱史，多術怪仙公。", "不但時人惜，祗應吾道窮。", "一哀侵疾病，相識自兒童。", "處處鄰家笛，飄飄客子蓬。", "強吟懷舊賦，已作白頭翁。"]'),
('92d43a33-1a9f-4f37-b216-0b0e2d1de5fb','哭王彭州掄','杜甫','唐','唐诗','tang','','[]','執友驚淪沒，斯人已寂寥。',240,'全唐诗/poet.tang.11000.json','["執友驚淪沒，斯人已寂寥。", "新文生沈謝，異骨降松喬。", "北部初高選，東堂早見招。", "蛟龍纏倚劒，鸞鳳夾吹簫。", "歷職漢庭久，中年胡馬驕。", "兵戈闇兩觀，寵辱事三朝。", "蜀路江干窄，彭門地里遙。", "解龜生碧草，諫獵阻清霄。", "頃壯戎麾出，叨陪幕府要。", "將軍臨氣候，猛士寒風飆。", "井漏泉誰汲，烽疎火不燒。", "前籌自多暇，隱几接終朝。", "翠石俄雙表，寒松竟後凋。", "贈詩焉敢墜，染翰欲無聊。", "再哭經過罷，離魂去住銷。", "之官方玉折，寄葬與萍漂。", "曠望渥洼道，霏微河漢橋。", "夫人先即世，令子各清標。", "巫峽長雲雨，秦城近斗杓。", "馮唐毛髮白，歸興日蕭蕭。"]'),
('9a1a05e7-b53a-431b-ad36-844319dd3a17','見螢火','杜甫','唐','唐诗','tang','','[]','巫山秋夜螢火飛，簾疎巧入坐人衣。',64,'全唐诗/poet.tang.11000.json','["巫山秋夜螢火飛，簾疎巧入坐人衣。", "忽驚屋裏琴書冷，復亂檐邊星宿稀。", "却繞井闌添箇箇，偶經花蘂弄輝輝。", "蒼江白髮愁看汝，來歲如今歸未歸。"]'),
('98db730a-8bb5-4c96-81a9-b8c700e1b628','吹笛','杜甫','唐','唐诗','tang','','[]','吹笛秋山風月清，誰家巧作斷腸聲。',64,'全唐诗/poet.tang.11000.json','["吹笛秋山風月清，誰家巧作斷腸聲。", "風飄律呂相和切，月傍關山幾處明。", "胡騎中宵堪北走，武陵一曲想南征。", "故園楊柳今搖落，何得愁中曲盡生。"]'),
('f6b75eb2-255e-4071-bf01-a5db4d409051','孤雁','杜甫','唐','唐诗','tang','','["\u5b64\u72ec", "\u54c0\u4f24", "\u548f\u7269", "\u5199\u9e1f", "\u548f\u7269\u8bd7", "\u9e1f"]','孤雁不飲啄，飛鳴聲念羣。',48,'全唐诗/poet.tang.11000.json','["孤雁不飲啄，飛鳴聲念羣。", "誰憐一片影，相失萬重雲。", "望盡似猶見，哀多如更聞。", "野鵶無意緒，鳴噪自紛紛。"]'),
('16986240-98d2-47da-a4a9-cf487c2c2f0e','鷗','杜甫','唐','唐诗','tang','','[]','江浦寒鷗戲，無他亦自饒。',48,'全唐诗/poet.tang.11000.json','["江浦寒鷗戲，無他亦自饒。", "却思飜玉羽，隨意點春苗。", "雪暗還須浴，風生一任飄。", "幾羣滄海上，清影日蕭蕭。"]'),
('677b004c-36ac-4456-b584-0b0764d34c79','猨','杜甫','唐','唐诗','tang','','[]','褭褭啼虛壁，蕭蕭挂冷枝。',48,'全唐诗/poet.tang.11000.json','["褭褭啼虛壁，蕭蕭挂冷枝。", "艱難人不見，隱見爾如知。", "慣習元從衆，全生或用奇。", "前林騰每及，父子莫相離。"]'),
('a542e23a-2907-416f-8451-04cbd6779e25','黃魚','杜甫','唐','唐诗','tang','','[]','日見巴東峽，黃魚出浪新。',48,'全唐诗/poet.tang.11000.json','["日見巴東峽，黃魚出浪新。", "脂膏兼飼犬，長大不容身。", "筒桶相沿久，風雷肯爲神。", "泥沙卷涎沫，回首怪龍鱗。"]'),
('998bd0c7-23f3-4c26-b669-9ea415363143','白小','杜甫','唐','唐诗','tang','','[]','白小羣分命，天然二寸魚。',48,'全唐诗/poet.tang.11000.json','["白小羣分命，天然二寸魚。", "細微霑水族，風俗當園蔬。", "入肆銀花亂，傾箱雪片虛。", "生成猶拾卵，盡取義何如。"]'),
('48906931-dcfc-4a6a-a2ea-764bf78f71b5','麂','杜甫','唐','唐诗','tang','','[]','永與清溪別，蒙將玉饌俱。',48,'全唐诗/poet.tang.11000.json','["永與清溪別，蒙將玉饌俱。", "無才逐仙隱，不敢恨庖廚。", "亂世輕全物，微聲及禍樞。", "衣冠兼盜賊，饕餮用斯須。"]'),
('b67d9e71-047a-4304-8b41-b7abb86cbbdb','雞','杜甫','唐','唐诗','tang','','[]','紀德名標五，初鳴度必三。',48,'全唐诗/poet.tang.11000.json','["紀德名標五，初鳴度必三。", "殊方聽有異，失次曉無慙。", "問俗人情似，充庖爾輩堪。", "氣交亭育際，巫峽漏司南。"]'),
('8584c5a1-b204-481e-b6fd-3eb4b70ec209','玉腕騮','杜甫','唐','唐诗','tang','','[]','聞說荆南馬，尚書玉腕騮。',48,'全唐诗/poet.tang.11000.json','["聞說荆南馬，尚書玉腕騮。", "頓驂飄赤汗，踞蹐顧長楸。", "胡虜三年入，乾坤一戰收。", "舉鞭如有問，欲伴習池遊。"]'),
('e359ecda-4561-43e9-aaa0-4a5ab5d1f3fd','見王監兵馬使說近山有白黑二鷹羅者久取竟未能得王以爲毛骨有異他鷹恐臘後春生鶱飛避暖勁翮思秋之甚眇不可見請余賦詩 一','杜甫','唐','唐诗','tang','','[]','雪飛玉立盡清秋，不惜奇毛恣遠遊。',64,'全唐诗/poet.tang.11000.json','["雪飛玉立盡清秋，不惜奇毛恣遠遊。", "在野只教心力破，千人何事網羅求。", "一生自獵知無敵，百中爭能恥下韝。", "鵬礙九天須却避，兔藏三穴莫深憂。"]'),
('59e81bbb-8a37-4a43-882c-884d34a754e9','見王監兵馬使說近山有白黑二鷹羅者久取竟未能得王以爲毛骨有異他鷹恐臘後春生鶱飛避暖勁翮思秋之甚眇不可見請余賦詩 二','杜甫','唐','唐诗','tang','','[]','黑鷹不省人間有，度海疑從北極來。',64,'全唐诗/poet.tang.11000.json','["黑鷹不省人間有，度海疑從北極來。", "正翮摶風超紫塞，立冬幾夜宿陽臺。", "虞羅自各虛施巧，春雁同歸必見猜。", "萬里寒空祗一日，金眸玉爪不凡才。"]'),
('de4dc63c-db19-48ac-84e5-480042f3df86','太歲日','杜甫','唐','唐诗','tang','','[]','楚岸行將老，巫山坐復春。',96,'全唐诗/poet.tang.11000.json','["楚岸行將老，巫山坐復春。", "病多猶是客，謀拙竟何人。", "閶闔開黃道，衣冠拜紫宸。", "榮光懸日月，賜與出金銀。", "愁寂鴛行斷，參差虎穴鄰。", "西江元下蜀，北斗故臨秦。", "散地逾高枕，生涯脫要津。", "天邊梅柳樹，相見幾回新。"]'),
('471d5abe-d0cf-4dd2-a94b-ab5552be07d9','元日示宗武','杜甫','唐','唐诗','tang','','[]','汝啼吾手戰，吾笑汝身長。',72,'全唐诗/poet.tang.11000.json','["汝啼吾手戰，吾笑汝身長。", "處處逢正月，迢迢滯遠方。", "飄零還柏酒，衰病只藜牀。", "訓喻青衿子，名慙白首郎。", "賦詩猶落筆，獻壽更稱觴。", "不見江東弟，高歌淚數行。"]'),
('49255a86-1217-48f7-b480-0f562a4dcf91','遠懷舍弟穎觀等','杜甫','唐','唐诗','tang','','[]','陽翟空知處，荆南近得書。',72,'全唐诗/poet.tang.11000.json','["陽翟空知處，荆南近得書。", "積年仍遠別，多難不安居。", "江漢春風起，冰霜昨夜除。", "雲天猶錯莫，花萼尚蕭疎。", "對酒都疑夢，吟詩正憶渠。", "舊時元日會，鄉黨羨吾廬。"]'),
('c48daf1c-17c9-427b-9614-b54de152e3f9','續得觀書迎就當陽居止正月中旬定出三峽','杜甫','唐','唐诗','tang','','[]','自汝到荆府，書來數喚吾。',96,'全唐诗/poet.tang.11000.json','["自汝到荆府，書來數喚吾。", "頌椒添諷詠，禁火卜歡娛。", "舟楫因人動，形骸用杖扶。", "天旋夔子國，春近岳陽湖。", "發日排南喜，傷神散北吁。", "飛鳴還接翅，行序密銜蘆。", "俗薄江山好，時危草木蘇。", "馮唐雖晚達，終覬在皇都。"]'),
('37ddc488-66be-4acd-b680-049fa13875c5','將別巫峽贈南卿兄瀼西果園四十畝','杜甫','唐','唐诗','tang','','[]','苔竹素所好，萍蓬無定居。',96,'全唐诗/poet.tang.11000.json','["苔竹素所好，萍蓬無定居。", "遠遊長兒子，幾地別林廬。", "雜蘂紅相對，他時錦不如。", "具舟將出峽，巡圃念攜鋤。", "正月喧鶯末，茲辰放鷁初。", "雪籬梅可折，風榭柳微舒。", "託贈卿家有，因歌野興疎。", "殘生逗江漢，何處狎樵漁。"]'),
('60f3c484-4e4f-4612-9f93-e753c7c67c02','送大理封主簿五郎親事不合却赴通州主簿前閬州賢子余與主簿平章鄭氏女子垂欲納鄭氏伯父京書至女子已前許他族親事遂停','杜甫','唐','唐诗','tang','','[]','禁臠去東牀，趨庭赴北堂。',96,'全唐诗/poet.tang.11000.json','["禁臠去東牀，趨庭赴北堂。", "風波空遠涉，琴瑟幾虛張。", "渥水出騏驥，崑山生鳳皇。", "兩家誠款款，中道許蒼蒼。", "頗謂秦晉匹，從來王謝郎。", "青春動才調，白首缺輝光。", "玉潤終孤立，珠明得闇藏。", "餘寒折花卉，恨別滿江鄉。"]'),
('f45104c8-145d-4f09-ac5d-1b9ac85dad65','人日兩篇 一','杜甫','唐','唐诗','tang','','[]','元日到人日，未有不陰時。',48,'全唐诗/poet.tang.11000.json','["元日到人日，未有不陰時。", "冰雪鶯難至，春寒花較遲。", "雲隨白水落，風振紫山悲。", "蓬鬢稀疎久，無勞比素絲。"]'),
('8fe5a657-b087-4fe3-b3f0-d4d5d97da755','人日兩篇 二','杜甫','唐','唐诗','tang','','[]','此日此時人共得，一談一笑俗相看。',64,'全唐诗/poet.tang.11000.json','["此日此時人共得，一談一笑俗相看。", "尊前柏葉休隨酒，勝裏金花巧耐寒。", "佩劒衝星聊暫拔，匣琴流水自須彈。", "早春重引江湖興，直道無憂行路難。"]'),
('26a4d4f1-b9bb-42c4-8201-8b84b88c5531','江梅','杜甫','唐','唐诗','tang','','[]','梅蘂臘前破，梅花年後多。',48,'全唐诗/poet.tang.11000.json','["梅蘂臘前破，梅花年後多。", "絕知春意好，最奈客愁何。", "雪樹元同色，江風亦自波。", "故園不可見，巫岫鬱嵯峨。"]'),
('2b47ba92-18b5-4dc4-8dc6-fd74a117c242','庭草','杜甫','唐','唐诗','tang','','[]','楚草經寒碧，逢春入眼濃。',48,'全唐诗/poet.tang.11000.json','["楚草經寒碧，逢春入眼濃。", "舊低收葉舉，新掩卷牙重。", "步履宜輕過，開筵得屢供。", "看花隨節序，不敢強爲容。"]'),
('ef36b0a2-6327-47a2-b777-ccf669af3ebb','大曆三年春白帝城放船出瞿塘峽久居夔府將適江陵漂泊有詩凡四十韻','杜甫','唐','唐诗','tang','','[]','老向巴人裏，今辭楚塞隅。',288,'全唐诗/poet.tang.11000.json','["老向巴人裏，今辭楚塞隅。", "入舟飜不樂，解纜獨長吁。", "窄轉深啼狖，虛隨亂浴鳧。", "石苔凌几杖，空翠撲肌膚。", "疊壁排霜劒，奔泉濺水珠。", "杳冥藤上下，濃澹樹榮枯。", "神女峰娟妙，昭君宅有無。", "曲留明怨惜，夢盡失歡娛。", "擺闔盤渦沸，欹斜激浪輸。", "風雷纏地脈，冰雪耀天衢。", "鹿角真走險，狼頭如跋胡。", "惡灘寧變色，高臥負微軀。", "書史全傾撓，裝囊半壓濡。", "生涯臨臬兀，死地脫斯須。", "不有平川決，焉知衆壑趨。", "乾坤霾漲海，雨露洗春蕪。", "歐鳥牽絲颺，驪龍濯錦紆。", "落霞沈綠綺，殘月壞金樞。", "泥筍苞初荻，沙茸出小蒲。", "雁兒爭水馬，燕子逐檣烏。", "絕島容煙霧，環洲納曉晡。", "前聞辨陶牧，轉眄拂宜都。", "縣郭南畿好，津亭北望孤。", "勞心依憩息，朗詠劃昭蘇。"]'),
('80d30278-2a20-4eac-a99e-4c31c476146a','巫山縣汾州唐使君十八弟宴別兼諸公攜酒樂相送率題小詩留於屋壁，','杜甫','唐','唐诗','tang','','[]','臥病巴東久，今年強作歸。',48,'全唐诗/poet.tang.11000.json','["臥病巴東久，今年強作歸。", "故人猶遠謫，茲日倍多違。", "接宴身兼杖，聽歌淚滿衣。", "諸公不相棄，擁別惜光輝。"]'),
('ee06ff18-c97c-41bf-8839-3e628f84df56','春夜峽州田侍御長史津亭留宴','杜甫','唐','唐诗','tang','','[]','北斗三更席，西江萬里船。',48,'全唐诗/poet.tang.11000.json','["北斗三更席，西江萬里船。", "杖藜登水榭，揮翰宿春天。", "白髮煩多酒，明星惜此筵。", "始知雲雨峽，忽盡下牢邊。"]'),
('83b6f8c7-9df6-4a6d-975b-15b582055495','泊松滋江亭','杜甫','唐','唐诗','tang','','[]','沙帽隨鷗鳥，扁舟繫此亭。',48,'全唐诗/poet.tang.11000.json','["沙帽隨鷗鳥，扁舟繫此亭。", "江湖深更白，松竹遠微青。", "一柱全應近，高唐莫再經。", "今宵南極外，甘作老人星。"]'),
('60416453-6d7f-42e7-932c-493495a224e1','行次古城店泛江作不揆鄙拙奉呈江陵幕府諸公','杜甫','唐','唐诗','tang','','[]','老年常道路，遲日復山川。',72,'全唐诗/poet.tang.11000.json','["老年常道路，遲日復山川。", "白屋花開裏，孤城麥秀邊。", "濟江元自闊，下水不勞牽。", "風蝶勤依漿，春鷗嬾避船。", "王門高德業，幕府盛才賢。", "行色兼多病，蒼茫泛愛前。"]'),
('e326a87d-30e8-4981-8278-d38ecaf8b213','乘雨入行軍六弟宅','杜甫','唐','唐诗','tang','','[]','曙角凌雲罷，春城帶雨長。',48,'全唐诗/poet.tang.11000.json','["曙角凌雲罷，春城帶雨長。", "水花分塹弱，巢燕得泥忙。", "令弟雄軍佐，凡才污省郎。", "萍漂忍流涕，衰颯近中堂。"]'),
('69df3f32-fc62-40b8-9cd2-1f98cc3e3076','宴胡侍御書堂','杜甫','唐','唐诗','tang','','[]','江湖春欲暮，牆宇日猶微。',48,'全唐诗/poet.tang.11000.json','["江湖春欲暮，牆宇日猶微。", "闇闇春籍滿，輕輕花絮飛。", "翰林名有素，墨客興無違。", "今夜文星動，吾儕醉不歸。"]'),
('ea32b290-7412-4a01-b660-42821f8730d0','書堂飲既夜復邀李尚書下馬月下賦絕句','杜甫','唐','唐诗','tang','','[]','湖水林風相與清，殘尊下馬復同傾。',32,'全唐诗/poet.tang.11000.json','["湖水林風相與清，殘尊下馬復同傾。", "久判野鶴如霜鬢，遮莫鄰雞下五更。"]'),
('d2161c1d-c64e-46dd-bf17-9e3bb5a9be47','上巳日徐司錄林園宴集','杜甫','唐','唐诗','tang','','[]','鬢毛垂領白，花蘂亞枝紅。',48,'全唐诗/poet.tang.11000.json','["鬢毛垂領白，花蘂亞枝紅。", "欹倒衰年廢，招尋令節同。", "薄衣臨積水，吹面受和風。", "有喜留攀桂，無勞問轉蓬。"]'),
('17454a63-af1d-4f71-97c9-55eba184d068','奉送蘇州李二十五長史丈之任','杜甫','唐','唐诗','tang','','[]','星坼台衡地，曾爲人所憐。',72,'全唐诗/poet.tang.11000.json','["星坼台衡地，曾爲人所憐。", "公侯終必復，經術昔相傳。", "食德見從事，克家何妙年。", "一毛生鳳穴，三尺獻龍泉。", "赤壁浮春暮，姑蘇落海邊。", "客間頭最白，惆悵此離筵。"]'),
('1fd0c2d9-0382-4b51-a19f-8361be58a31d','暮春江陵送馬大卿公恩命追赴闕下','杜甫','唐','唐诗','tang','','[]','自古求忠孝，名家信有之。',120,'全唐诗/poet.tang.11000.json','["自古求忠孝，名家信有之。", "吾賢富才術，此道未磷緇。", "玉府標孤映，霜蹄去不疑。", "激揚音韻徹，籍甚衆多推。", "潘陸應同調，孫吳亦異時。", "北辰徵事業，南紀赴恩私。", "卿月升金掌，王春度玉墀。", "熏風行應律，湛露即歌詩。", "天意高難問，人情老易悲。", "尊前江漢闊，後會且深期。"]'),
('ac88cc63-7c2c-472f-b65e-3c357334b0fd','暮春陪李尚書李中丞過鄭監湖亭泛舟','杜甫','唐','唐诗','tang','','[]','海內文章伯，湖邊意緒多。',48,'全唐诗/poet.tang.11000.json','["海內文章伯，湖邊意緒多。", "玉尊移晚興，桂楫帶酣歌。", "春日繁魚鳥，江天足芰荷。", "鄭莊賓客地，衰白遠來過。"]'),
('921df201-3eb0-44bb-b6b8-2d001fa71074','奉送蜀州柏二別駕將中丞命赴江陵起居衛尚書太夫人因示從弟行軍司馬佐','杜甫','唐','唐诗','tang','','[]','中丞問俗畫熊頻，愛弟傳書彩鷁新。',64,'全唐诗/poet.tang.11000.json','["中丞問俗畫熊頻，愛弟傳書彩鷁新。", "遷轉五州防禦使，起居八座太夫人。", "楚宮臘送荆門水，白帝雲偷碧海春。", "報與惠連詩不惜，知吾斑鬢總如銀。"]'),
('ab0c8118-d665-4dc1-be2b-901ae13395ed','夏日楊長寧宅送崔侍御常正字入京','杜甫','唐','唐诗','tang','','[]','醉酒揚雄宅，升堂子賤琴。',48,'全唐诗/poet.tang.11000.json','["醉酒揚雄宅，升堂子賤琴。", "不堪垂老鬢，還對欲分襟。", "天地西江遠，星辰北斗深。", "烏臺俯麟閣，長夏白頭吟。"]'),
('c7a83aed-b9e5-42f9-bd70-ac220655820d','和江陵宋大少府暮春雨後同諸公及舍弟宴書齋','杜甫','唐','唐诗','tang','','[]','渥洼汗血種，天上麒麟兒。',48,'全唐诗/poet.tang.11000.json','["渥洼汗血種，天上麒麟兒。", "才士得神秀，書齋聞爾爲。", "棣華晴雨好，綵服暮春宜。", "朋酒日歡會，老夫今始知。"]'),
('29e9f169-b4de-493a-b6f1-9b63d1f8f32a','宇文晁尚書之甥崔彧司業之孫尚書之子重泛鄭監前湖','杜甫','唐','唐诗','tang','','[]','郊扉俗遠長幽寂，野水春來更接連。',64,'全唐诗/poet.tang.11000.json','["郊扉俗遠長幽寂，野水春來更接連。", "錦席淹留還出浦，葛巾欹側未迴船。", "尊當霞綺輕初散，櫂拂荷珠碎却圓。", "不但習池歸酩酊，君看鄭谷去夤緣。"]'),
('b443f8f6-d94d-4399-bbe4-6816d1ae0126','多病執熱奉懷李尚書','杜甫','唐','唐诗','tang','','[]','衰年正苦病侵凌，首夏何須氣鬱蒸。',63,'全唐诗/poet.tang.11000.json','["衰年正苦病侵凌，首夏何須氣鬱蒸。", "大水淼茫炎海接，奇峰硉兀火雲升。", "思霑道暍黃梅雨，敢望宮恩玉井冰。", "不是尚書期不顧山陰野雪興難乘。"]'),
('47177306-ac64-4cba-a655-5e4fdf44bee6','水宿遣興奉呈羣公','杜甫','唐','唐诗','tang','','[]','魯鈍仍多病，逢迎遠復迷。',240,'全唐诗/poet.tang.11000.json','["魯鈍仍多病，逢迎遠復迷。", "耳聾須畫字，髮短不勝蓖。", "澤國雖勤雨，炎天竟淺泥。", "小江還積浪，弱纜且長堤。", "歸路非關北，行舟却向西。", "暮年漂泊恨，今夕亂離啼。", "童稚頻書札，盤餐詎糝藜。", "我行何到此，物理直難齊。", "高枕飜星月，嚴城疊鼓鞞。", "風號聞虎豹，水宿伴鳧鷖。", "異縣驚虛往，同人惜解攜。", "蹉跎長泛鷁，展轉屢鳴雞。", "嶷嶷瑚璉器，陰陰桃李蹊。", "餘波期救涸，費日苦輕齎。", "支策門闌邃，肩輿羽翮低。", "自傷甘賤役，誰愍強幽棲。", "巨海能無釣，浮雲亦有梯。", "勳庸思樹立，語默可端倪。", "贈粟囷應指，登橋柱必題。", "丹心老未折，時訪武陵溪。"]'),
('2c08a55b-3506-4770-a3fb-66b0d021835e','奉賀陽城郡王太夫人恩命加鄧國太夫人','杜甫','唐','唐诗','tang','','[]','衛幕銜恩重，潘輿送喜頻。',120,'全唐诗/poet.tang.11000.json','["衛幕銜恩重，潘輿送喜頻。", "濟時瞻上將，錫號戴慈親。", "富貴當如此，尊榮邁等倫。", "郡依封土舊，國與大名新。", "紫誥鸞迴紙，清朝燕賀人。", "遠傳冬筍味，更覺綵衣春。", "奕葉班姑史，芬芳孟母鄰。", "義方兼有訓，詞翰兩如神。", "委曲承顏體，騫飛報主身。", "可憐忠與孝，雙美畫騏麟。"]'),
('383ea645-4277-41c8-af4e-8d03d1497a87','江陵望幸','杜甫','唐','唐诗','tang','','[]','雄都元壯麗，望幸歘威神。',72,'全唐诗/poet.tang.11000.json','["雄都元壯麗，望幸歘威神。", "地利西通蜀，天文北照秦。", "風煙含越鳥，舟楫控吳人。", "未枉周王駕，終期漢武巡。", "甲兵分聖旨，居守付宗臣。", "早發雲臺杖，恩波起涸鱗。"]'),
('683085c0-248c-4545-998b-a04be7b8fd48','江邊星月二首 一','杜甫','唐','唐诗','tang','','[]','驟雨清秋夜，金波耿玉繩。',48,'全唐诗/poet.tang.11000.json','["驟雨清秋夜，金波耿玉繩。", "天河元自白，江浦向來澄。", "映物連珠斷，緣空一鏡升。", "餘光隱更漏，況乃露華凝。"]'),
('1130a58d-d738-46e6-8052-1252a540540d','江邊星月二首 二','杜甫','唐','唐诗','tang','','[]','江月辭風纜，江星別霧船。',48,'全唐诗/poet.tang.11000.json','["江月辭風纜，江星別霧船。", "雞鳴還曙色，鷺浴自清川。", "歷歷竟誰種，悠悠何處圓。", "客愁殊未已，他夕始相鮮。"]'),
('6ac2ae13-b8bc-45ad-9657-e34cbc3906c5','舟月對驛近寺','杜甫','唐','唐诗','tang','','[]','更深不假燭，月朗自明船。',48,'全唐诗/poet.tang.11000.json','["更深不假燭，月朗自明船。", "金剎清楓外，朱樓白水邊。", "城烏啼眇眇，野鷺宿娟娟。", "皓首江湖客，鉤簾獨未眠。"]'),
('9929c7fe-f4ad-449c-85f4-a0aebd0f4de8','舟中','杜甫','唐','唐诗','tang','','[]','風餐江柳下，雨臥驛樓邊。',48,'全唐诗/poet.tang.11000.json','["風餐江柳下，雨臥驛樓邊。", "結纜排魚網，連檣竝米船。", "今朝雲細薄，昨夜月清圓。", "飄泊南庭老，祗應學水仙。"]'),
('ca2fc78d-b575-49ac-abbc-e548d9fe1457','遣悶','杜甫','唐','唐诗','tang','','[]','地闊平沙岸，舟虛小洞房。',144,'全唐诗/poet.tang.11000.json','["地闊平沙岸，舟虛小洞房。", "使塵來驛道，城日避烏檣。", "暑雨留蒸濕，江風借夕涼。", "行雲星隱見，疊浪月光芒。", "螢鑒緣帷徹，蛛絲罥鬢長。", "哀箏猶凭几，鳴笛竟霑裳。", "倚著如秦贅，過逢類楚狂。", "氣衝看劒匣，穎脫撫錐囊。", "妖孽關東臭，兵戈隴右創。", "時清疑武略，世亂跼文場。", "餘力浮於海，端憂問彼蒼。", "百年從萬事，故國耿難忘。"]'),
('0db42110-bda6-490a-b3e0-61a5dfffad79','江陵節度陽城郡王新樓成王請嚴侍御判官賦七字句同作','杜甫','唐','唐诗','tang','','[]','樓上炎天冰雪生，高飛燕雀賀新成。',64,'全唐诗/poet.tang.11000.json','["樓上炎天冰雪生，高飛燕雀賀新成。", "碧窗宿霧濛濛濕，朱栱浮雲細細輕。", "杖鉞褰帷瞻具美，投壺散帙有餘清。", "自公多暇延參佐，江漢風流萬古情。"]'),
('7ee24af9-5477-4a56-b579-4ccdf8150bd5','又作此奉衛公','杜甫','唐','唐诗','tang','','[]','西北樓成雄楚都，遠開山岳散江湖。',64,'全唐诗/poet.tang.11000.json','["西北樓成雄楚都，遠開山岳散江湖。", "二儀清濁還高下，三伏炎蒸定有無。", "推轂幾年唯鎮靜，曳裾終日盛文儒。", "白頭授簡焉能賦，媿似相如爲大夫。"]'),
('72dc154a-f628-4c7c-9a53-71891cdcdba4','舟出江陵南浦奉寄鄭少尹','杜甫','唐','唐诗','tang','','[]','更欲投何處，飄然去此都。',144,'全唐诗/poet.tang.11000.json','["更欲投何處，飄然去此都。", "形骸元土木，舟檝復江湖。", "社稷纏妖氣，干戈送老儒。", "百年同棄物，萬國盡窮途。", "雨洗平沙靜，天銜闊岸紆。", "鳴螿隨泛梗，別燕赴秋菰。", "棲託難高臥，飢寒迫向隅。", "寂寥相喣沫，浩蕩報恩珠。", "溟漲鯨波動，衡陽雁影徂。", "南征問懸榻，東逝想乘桴。", "濫竊商歌聽，時憂卞泣誅。", "經過憶鄭驛，斟酌旅情孤。"]'),
('ae5b1a15-0b5c-4578-8f31-1b60030633a4','江南逢李龜年','杜甫','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u521d\u4e2d\u53e4\u8bd7", "\u4e03\u8a00\u7edd\u53e5", "\u6000\u5ff5", "\u611f\u4f24", "\u4e03\u5e74\u7ea7\u4e0b\u518c(\u8bfe\u5916)"]','歧王宅裏尋常見，崔九堂前幾度聞。',32,'全唐诗/poet.tang.11000.json','["歧王宅裏尋常見，崔九堂前幾度聞。", "正是江南好風景，落花時節又逢君。"]'),
('a0e3340b-44e1-40fb-8566-bc8338573e7b','官亭夕坐戲簡顏十少府','杜甫','唐','唐诗','tang','','[]','南國調寒杵，西江浸日車。',48,'全唐诗/poet.tang.11000.json','["南國調寒杵，西江浸日車。", "客愁連蟋蟀，亭古帶蒹葭。", "不返青絲鞚，虛燒夜燭花。", "老翁須地主，細細酌流霞。"]'),
('1168c377-42c2-4c1f-a283-1ba089165dab','秋日荆南述懷三十韻','杜甫','唐','唐诗','tang','','[]','昔承推獎分，媿匪挺生材。',288,'全唐诗/poet.tang.11000.json','["昔承推獎分，媿匪挺生材。", "遲暮宮臣忝，艱危衮職陪。", "揚鑣隨日馭，折檻出雲臺。", "罪戾寬猶活，干戈塞未開。", "星霜玄鳥變，身世白駒催。", "伏枕因超忽，扁舟任往來。", "九鑽巴噀火，三蟄楚祠雷。", "望帝傳應實，昭王問不迴。", "蛟螭深作橫，豺虎亂雄猜。", "素業行已矣，浮名安在哉？", "琴烏曲怨憤，庭鶴舞摧頹。", "秋雨漫湘水，陰風過嶺梅。", "苦搖求食尾，常曝報恩顋。", "結舌防讒柄，探腸有禍胎。", "蒼茫步兵哭，展轉仲宣哀。", "飢籍家家米，愁徵處處杯。", "休爲貧士歎，任受衆人咍。", "得喪初難識，榮枯劃易該。", "差池分組冕，合沓起蒿萊。", "不必伊周地，皆知屈宋才。", "漢庭和異域，晉史坼中台。", "霸業尋常體，忠臣忌諱災。", "羣公紛戮力，聖慮窅裴回。", "數見銘鍾鼎，真宜法斗魁。"]'),
('f0d0412b-b79c-4643-a730-f980bf7e088a','秋日荆南送石首薛明府辭滿告別奉寄薛尚書頌德敍懷斐然之作三十韻','杜甫','唐','唐诗','tang','','[]','南征爲客久，西候別君初。',288,'全唐诗/poet.tang.11000.json','["南征爲客久，西候別君初。", "歲滿歸鳧舄，秋來把雁書。", "荆門留美化，姜被就離居。", "聞道和親人，垂名報國餘。", "連枝不日竝，八座幾時除。", "往者胡星孛，恭惟漢網疎。", "風塵相澒洞，天地一丘墟。", "殿瓦鴛鴦坼，宮簾翡翠虛。", "鉤陳摧徼道，槍櫐失儲胥。", "文物陪巡守，親賢病拮据。", "公時呵䝟貐，首唱却鯨魚。", "勢愜宗蕭相，材非一范雎。", "屍填太行道，血走浚儀渠。", "滏口師仍會，函關憤已攄。", "紫微臨大角，皇極正乘輿。", "賞從頻峨冕，殊私再直廬。", "豈惟高衛霍，曾是接應徐。", "降集飜翔鳳，追攀絕衆狙。", "侍臣雙宋玉，戰策兩穰苴。", "鑒澈勞懸鏡，荒蕪已荷鋤。", "嚮來披述作，重此憶吹噓。", "白髮甘凋喪，青雲亦卷舒。", "經綸功不朽，跋涉體何如。", "應訝耽湖橘，常餐占野蔬。"]'),
('95c62445-9249-4c6b-8628-0058dfda0dd5','哭李尚書','杜甫','唐','唐诗','tang','','[]','漳濱與蒿里，逝水竟同年。',120,'全唐诗/poet.tang.11000.json','["漳濱與蒿里，逝水竟同年。", "欲挂留徐劒，猶迴憶戴船。", "相知成白首，此別間黃泉。", "風雨嗟何及，江湖涕泫然。", "修文將管輅，奉使失張騫。", "史閣行人在，詩家秀句傳。", "客亭鞍馬絕，旅櫬網蟲懸。", "復魄昭丘遠，歸魂素滻偏。", "樵蘇封葬地，喉舌罷朝天。", "秋色凋春草，王孫若箇邊。"]'),
('511b0ab5-253f-4f98-b82e-6029d875abcf','重題','杜甫','唐','唐诗','tang','','[]','涕泗不能收，哭君余白頭。',48,'全唐诗/poet.tang.11000.json','["涕泗不能收，哭君余白頭。", "兒童相識盡，宇宙此生浮。", "江雨銘旌濕，湖風井徑秋。", "還瞻魏太子，賓客減應劉。"]'),
('96dbd7f8-f385-4e71-aea2-f8e4f743418f','獨坐','杜甫','唐','唐诗','tang','','[]','悲愁回白首，倚杖背孤城。',48,'全唐诗/poet.tang.11000.json','["悲愁回白首，倚杖背孤城。", "江斂洲渚出，天虛風物清。", "滄溟服衰謝，朱紱負平生。", "仰羨黃昏鳥，投林羽翮輕。"]'),
('d8b37acd-dfd9-45b0-b28a-425c5f453a35','暮歸','杜甫','唐','唐诗','tang','','["\u60b2\u4f24", "\u6292\u60c5", "\u7f81\u65c5", "\u5199\u666f"]','霜黃碧梧白鶴樓，城上擊拆復烏啼。',64,'全唐诗/poet.tang.11000.json','["霜黃碧梧白鶴樓，城上擊拆復烏啼。", "客子入門月皎皎，誰家擣練風淒淒。", "南渡桂水關舟檝，北歸秦川多鼓鞞。", "年過半百不稱意，明日看雲還杖藜。"]'),
('bc16aa10-9068-4f48-8f38-fd4ee1872954','移居公安敬贈衛大郎','杜甫','唐','唐诗','tang','','[]','衛侯不易得，余病汝知之。',120,'全唐诗/poet.tang.11000.json','["衛侯不易得，余病汝知之。", "雅量涵高遠，清襟照等夷。", "平生感意氣，少小愛文辭。", "河海由來合，風雲若有期。", "形容勞宇宙，質樸謝軒墀。", "自古幽人泣，留年壯士悲。", "水煙通徑草，秋露接園葵。", "入邑豺狼鬬，傷弓鳥雀飢。", "白頭供宴語，烏几伴棲遲。", "交態遭輕薄，今朝豁所思。"]'),
('2d283f99-14dc-476d-97f3-8a0245bb1ce4','公安送韋二少府匡贊','杜甫','唐','唐诗','tang','','["\u4e0d\u820d", "\u6292\u60c5", "\u9001\u522b"]','逍遙公後世多賢，送爾維舟惜此筵。',64,'全唐诗/poet.tang.11000.json','["逍遙公後世多賢，送爾維舟惜此筵。", "念我能書數字至，將詩不必萬人傳。", "時危兵甲黃塵裏，日短江湖白髮前。", "古往今來皆涕淚，斷腸分手各風煙。"]'),
('2a94b5e1-665b-4d40-a9a4-66703d0b9f09','贈虞十五司馬','杜甫','唐','唐诗','tang','','[]','遠師虞祕監，今喜識玄孫。',120,'全唐诗/poet.tang.11000.json','["遠師虞祕監，今喜識玄孫。", "形像丹青逼，家聲器宇存。", "淒涼憐筆勢，浩蕩問詞源。", "爽氣金天豁，清談玉露繁。", "佇鳴南岳鳳，欲化北溟鯤。", "交態知浮俗，儒流不異門。", "過逢聯客位，日夜倒芳尊。", "沙岸風吹葉，雲江月上軒。", "百年嗟已半，四座敢辭喧。", "書籍終相與，青山隔故園。"]'),
('08b0af5b-c537-4546-aadd-07e0b35d86ea','公安縣懷古','杜甫','唐','唐诗','tang','','[]','野曠呂蒙營，江深劉備城。',48,'全唐诗/poet.tang.11000.json','["野曠呂蒙營，江深劉備城。", "寒天催日短，風浪與雲平。", "灑落君臣契，飛騰戰伐名。", "維舟倚前浦，長嘯一含情。"]'),
('6cd30e4e-275a-4d8e-afa0-b0e03200f8ef','公安送李二十九弟晉肅入蜀余下沔鄂','杜甫','唐','唐诗','tang','','[]','正解柴桑纜，仍看蜀道行。',48,'全唐诗/poet.tang.11000.json','["正解柴桑纜，仍看蜀道行。", "檣烏相背發，塞雁一行鳴。", "南紀連銅柱，西江接錦城。", "憑將百錢卜，飄泊問君平。"]'),
('bdc426bc-334e-4fd8-bc4c-3ba0e3fcbe4e','宴王使君宅題二首 一','杜甫','唐','唐诗','tang','','[]','漢主追韓信，蒼生起謝安。',48,'全唐诗/poet.tang.11000.json','["漢主追韓信，蒼生起謝安。", "吾徒自漂泊，世事各艱難。", "逆旅招邀近，他鄉思緒寬。", "不材甘朽質，高臥豈泥蟠。"]'),
('4874778c-f3c9-456b-a64d-4cfe107b40c4','宴王使君宅題二首 二','杜甫','唐','唐诗','tang','','[]','泛愛容霜髮，留歡卜夜閒。',48,'全唐诗/poet.tang.11000.json','["泛愛容霜髮，留歡卜夜閒。", "自吟詩送老，相勸酒開顏。", "戎馬今何地，鄉園獨舊山。", "江湖墮清月，酩酊任扶還。"]'),
('4b70cf4d-91c2-4f35-88b6-27719132e234','留別公安太易沙門','杜甫','唐','唐诗','tang','','["\u5e90\u5c71"]','隱居欲就廬山遠，麗藻初逢休上人。',64,'全唐诗/poet.tang.11000.json','["隱居欲就廬山遠，麗藻初逢休上人。", "數問舟航留製作，長開篋笥擬心神。", "沙村白雪仍含凍，江縣紅梅已放春。", "先蹋爐峰置蘭若，徐飛錫杖出風塵。"]'),
('a62a3f41-1b77-4897-823e-c6f080f4b488','曉發公安','杜甫','唐','唐诗','tang','','[]','北城擊柝復欲罷，東方明星亦不遲。',64,'全唐诗/poet.tang.11000.json','["北城擊柝復欲罷，東方明星亦不遲。", "鄰雞野哭如昨日，物色生態能幾時。", "舟檝眇然自此去，江湖遠適無前期。", "出門轉眄已陳迹，藥餌扶吾隨所之。"]'),
('aa01fa86-99b8-4f58-b591-1007b5d3b010','泊岳陽城下','杜甫','唐','唐诗','tang','','["\u5fe7\u56fd\u5fe7\u6c11"]','江國踰千里，山城僅百層。',48,'全唐诗/poet.tang.11000.json','["江國踰千里，山城僅百層。", "岸風飜夕浪，舟雪灑寒燈。", "留滯才難盡，艱危氣益增。", "圖南未可料，變化有鯤鵬。"]'),
('4d16ccaa-a7a3-45e6-b0d9-6e94e3e1d99d','纜船苦風戲題四韻奉簡鄭十三判官','杜甫','唐','唐诗','tang','','[]','楚岸朔風疾，天寒鶬鴰呼。',48,'全唐诗/poet.tang.11000.json','["楚岸朔風疾，天寒鶬鴰呼。", "漲沙霾草樹，舞雪渡江湖。", "吹帽時時落，維舟日日孤。", "因聲置驛外，爲覓酒家壚。"]'),
('5d05fef6-e4aa-48e5-917d-c29d0e6d6b33','登岳陽樓','杜甫','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u6d1e\u5ead\u6e56", "\u5cb3\u9633\u697c", "\u62b1\u8d1f", "\u4e94\u8a00\u5f8b\u8bd7", "\u5c71\u6c34"]','昔聞洞庭水，今上岳陽樓。',48,'全唐诗/poet.tang.11000.json','["昔聞洞庭水，今上岳陽樓。", "吳楚東南坼，乾坤日夜浮。", "親朋無一字，老病有孤舟。", "戎馬關山北，憑軒涕泗流。"]'),
('e70bf788-5565-441d-a424-8a6d0580dc8b','陪裴使君登岳陽樓','杜甫','唐','唐诗','tang','','["\u5cb3\u9633\u697c", "\u5e26\u6709\u5730\u540d", "\u613f\u671b", "\u8d5e\u7f8e", "\u5730\u540d"]','湖闊兼雲霧，樓孤屬晚晴。',48,'全唐诗/poet.tang.11000.json','["湖闊兼雲霧，樓孤屬晚晴。", "禮加徐孺子，詩接謝宣城。", "雪岸叢梅發，春泥百草生。", "敢違漁父問，從此更南征。"]'),
('4c5525bf-6b4c-4bfc-ac1d-ecef40a745f2','過南岳入洞庭湖','杜甫','唐','唐诗','tang','','["\u8861\u5c71", "\u6d1e\u5ead\u6e56"]','洪波忽爭道，岸轉異江湖。',144,'全唐诗/poet.tang.11000.json','["洪波忽爭道，岸轉異江湖。", "鄂渚分雲樹，衡山引舳艫。", "翠牙穿裛槳，碧節上寒蒲。", "病渴身何去，春生力更無。", "壤童犂雨雪，漁屋架泥塗。", "欹側風帆滿，微冥水驛孤。", "悠悠迴赤壁，浩浩略蒼梧。", "帝子留遺恨，曹公屈壯圖。", "聖朝光御極，殘孽駐艱虞。", "才淑隨廝養，名賢隱鍛鑪。", "邵平元入漢，張翰後歸吳。", "莫怪啼痕數，危檣逐夜烏。"]'),
('0599e6cd-e57a-4b90-ac98-f65a23cebae0','宿青草湖','杜甫','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','洞庭猶在目，青草續爲名。',48,'全唐诗/poet.tang.11000.json','["洞庭猶在目，青草續爲名。", "宿槳依農事，郵籤報水程。", "寒冰爭倚薄，雲月遞微明。", "湖雁雙雙起，人來故北征。"]'),
('ca5a763f-80a5-4af8-93c0-083856a6aeb6','宿白沙驛','杜甫','唐','唐诗','tang','','[]','水宿仍餘照，人煙復此亭。',48,'全唐诗/poet.tang.11000.json','["水宿仍餘照，人煙復此亭。", "驛邊沙舊白，湖外草新青。", "萬象皆春氣，孤槎自客星。", "隨波無限月，的的近南溟。"]'),
('20dd694b-d037-4c84-bcde-26b98a9c689a','湘夫人祠','杜甫','唐','唐诗','tang','','[]','肅肅湘妃廟，空牆碧水春。',48,'全唐诗/poet.tang.11000.json','["肅肅湘妃廟，空牆碧水春。", "蟲書玉佩蘚，燕舞翠帷塵。", "晚泊登汀樹，微馨借渚蘋。", "蒼梧恨不盡，染淚在叢筠。"]'),
('ad112c4f-ec1f-410d-9e8a-9784c3a8a355','祠南夕望','杜甫','唐','唐诗','tang','','[]','百丈牽江色，孤舟泛日斜。',48,'全唐诗/poet.tang.11000.json','["百丈牽江色，孤舟泛日斜。", "興來猶杖屨，目斷更雲沙。", "山鬼迷春竹，湘娥倚暮花。", "湖南清絕地，萬古一長嗟。"]'),
('7f2ba157-9d10-4c65-8da8-9b277d0ebeb3','登白馬潭','杜甫','唐','唐诗','tang','','[]','水生春纜沒，日出野船開。',48,'全唐诗/poet.tang.11000.json','["水生春纜沒，日出野船開。", "宿鳥行猶去，叢花笑不來。", "人人傷白首，處處接金杯。", "莫道新知要，南征且未回。"]'),
('ad7a0111-98f9-43e5-bad4-9c73c5336389','歸雁','杜甫','唐','唐诗','tang','','[]','聞道今春雁，南歸自廣州。',48,'全唐诗/poet.tang.11000.json','["聞道今春雁，南歸自廣州。", "見花辭漲海，避雪到羅浮。", "是物關兵氣，何時免客愁。", "年年霜露隔，不過五湖秋。"]'),
('b11ed6db-b3a6-46f9-b51e-94a0d8606406','野望','杜甫','唐','唐诗','tang','','[]','納納乾坤大，行行郡國遙。',48,'全唐诗/poet.tang.11000.json','["納納乾坤大，行行郡國遙。", "雲山兼五嶺，風壤帶三苗。", "野樹侵江闊，春蒲長雪消。", "扁舟空老去，無補聖明朝。"]'),
('f334fa1b-6b29-4a14-a769-828fa8fd2ec9','入喬口','杜甫','唐','唐诗','tang','','[]','漠漠舊京遠，遲遲歸路賒。',48,'全唐诗/poet.tang.11000.json','["漠漠舊京遠，遲遲歸路賒。", "殘年傍水國，落日對春華。", "樹蜜早蠭亂，江泥輕燕斜。", "賈生骨已朽，悽惻近長沙。"]'),
('272095aa-4f8c-4674-b704-e626118c81db','銅官渚守風','杜甫','唐','唐诗','tang','','[]','不夜楚帆落，避風湘渚間。',48,'全唐诗/poet.tang.11000.json','["不夜楚帆落，避風湘渚間。", "水耕先浸草，春火更燒山。", "早泊雲物晦，逆行波浪慳。", "飛來雙白鶴，過去杳難攀。"]'),
('43f8bb74-5673-41a8-96ac-6a5e3a906382','北風','杜甫','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','春生南國瘴，氣待北風蘇。',120,'全唐诗/poet.tang.11000.json','["春生南國瘴，氣待北風蘇。", "向晚霾殘日，初宵鼓大鑪。", "爽攜卑濕地，聲拔洞庭湖。", "萬里魚龍伏，三更鳥獸呼。", "滌除貪破浪，愁絕付摧枯。", "執熱沈沈在，凌寒往往須。", "且知寬疾胏，不敢恨危途。", "再宿煩舟子，衰容問僕夫。", "今晨非盛怒，便道即長驅。", "隱几看帆席，雲州湧坐隅。"]'),
('767a621a-7b99-49c1-813f-1537932d9297','雙楓浦','杜甫','唐','唐诗','tang','','[]','輟櫂青楓浦，雙楓舊已摧。',48,'全唐诗/poet.tang.11000.json','["輟櫂青楓浦，雙楓舊已摧。", "自驚衰謝力，不道棟梁材。", "浪足浮紗帽，皮須截錦苔。", "江邊地有主，暫借上天迴。"]'),
('78368c3c-4a50-4662-9fe2-261dcb331ab3','奉送王信州崟北歸','杜甫','唐','唐诗','tang','','[]','朝廷防盜賊，供給愍誅求。',216,'全唐诗/poet.tang.11000.json','["朝廷防盜賊，供給愍誅求。", "下詔選郎署，傳聲能典州。", "蒼生今日困，天子嚮時憂。", "井屋有煙起，瘡痍無血流。", "壤歌唯海甸，畫角自山樓。", "白髮寐常早，荒榛農復秋。", "解龜踰臥轍，遣騎覓扁舟。", "徐榻不知倦，潁川何以酬。", "塵生彤管筆，寒膩黑貂裘。", "高義終焉在，斯文去矣休。", "別離同雨散，行止各雲浮。", "林熱鳥開口，江渾魚掉頭。", "尉佗雖北拜，太史尚南留。", "軍旅應都息，寰區要盡收。", "九重思諫諍，八極念懷柔。", "徙倚瞻王室，從容仰廟謀。", "故人持雅論，絕塞豁窮愁。", "復見陶唐理，甘爲汗漫遊。"]'),
('6e3f5313-7c69-4bfb-9be8-4cf31afd0f12','江閣臥病走筆寄呈崔盧兩侍御','杜甫','唐','唐诗','tang','','[]','客子庖廚薄，江樓枕席清。',48,'全唐诗/poet.tang.11000.json','["客子庖廚薄，江樓枕席清。", "衰年病祗瘦，長夏想爲情。", "滑憶彫胡飯，香聞錦帶羹。", "溜匙兼暖腹，誰欲致杯甖。"]'),
('3a50da07-221c-4d47-848f-5bc81a0644b8','潭州送韋員外牧韶州','杜甫','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','炎海韶州牧，風流漢署郎。',48,'全唐诗/poet.tang.11000.json','["炎海韶州牧，風流漢署郎。", "分符先令望，同舍有輝光。", "白首多年疾，秋天昨夜涼。", "洞庭無過雁，書疏莫相忘。"]'),
('4661e4b6-82bb-4897-a21c-559468a25ca7','江閣對雨有懷行營裴二端公','杜甫','唐','唐诗','tang','','[]','南紀風濤壯，陰晴屢不分。',48,'全唐诗/poet.tang.11000.json','["南紀風濤壯，陰晴屢不分。", "野流行地日，江入度山雲。", "層閣憑雷殷，長空水面文。", "雨來銅柱北，應洗伏波軍。"]'),
('06503227-08cb-4d3e-aa95-9471d4f5b22f','酬韋韶州見寄','杜甫','唐','唐诗','tang','','[]','養拙江湖外，朝廷記憶疎。',48,'全唐诗/poet.tang.11000.json','["養拙江湖外，朝廷記憶疎。", "深慙長者轍，重得故人書。", "白髮絲難理，新詩錦不如。", "雖無南去雁，看取北來魚。"]'),
('e72f4403-6f48-473d-96d4-730900a4eb10','千秋節有感二首 一','杜甫','唐','唐诗','tang','','[]','自罷千秋節，頻傷八月來。',72,'全唐诗/poet.tang.11000.json','["自罷千秋節，頻傷八月來。", "先朝常宴會，壯觀已塵埃。", "鳳紀編生日，龍池塹劫灰。", "湘川新涕淚，秦樹遠樓臺。", "寶鏡羣臣得，金吾萬國迴。", "衢尊不重飲，白首獨餘哀。"]'),
('f77e5692-4182-472f-8b19-6fa83cc74e5b','千秋節有感二首 二','杜甫','唐','唐诗','tang','','[]','御氣雲樓敞，含風綵仗高。',72,'全唐诗/poet.tang.11000.json','["御氣雲樓敞，含風綵仗高。", "仙人張內樂，王母獻宮桃。", "羅襪紅蕖豔，金羈白雪毛。", "舞階銜壽酒，走索背秋毫。", "聖主他年貴，邊心此日勞。", "桂江流向北，滿眼送波濤。"]'),
('3ca9f283-25e2-4e86-a080-3f2ab565154d','晚秋長沙蔡五侍御飲筵送殷六參軍歸澧州覲省','杜甫','唐','唐诗','tang','','[]','佳士欣相識，慈顏望遠遊。',48,'全唐诗/poet.tang.11000.json','["佳士欣相識，慈顏望遠遊。", "甘從投轄飲，肯作置書郵。", "高鳥黃雲暮，寒蟬碧樹秋。", "湖南冬不雪，吾病得淹留。"]'),
('5728a2f1-e337-4f6d-95b1-ff5e51693d44','湖中送敬十使君適廣陵','杜甫','唐','唐诗','tang','','[]','相見各頭白，其如離別何。',96,'全唐诗/poet.tang.11000.json','["相見各頭白，其如離別何。", "幾年一會面，今日復悲歌。", "少壯樂難得，歲寒心匪他。", "氣纏霜匣滿，冰置玉壺多。", "遭亂實漂泊，濟時曾琢磨。", "形容吾校老，膽力爾誰過。", "秋晚岳增翠，風高湖湧波。", "騫騰訪知己，淮海莫磋跎。"]'),
('0d16ff1c-ae92-41ad-9278-195c506463fc','長沙送李十一','杜甫','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','與子避地西康州，洞庭相逢十二秋。',64,'全唐诗/poet.tang.11000.json','["與子避地西康州，洞庭相逢十二秋。", "遠媿尚方曾賜履，竟非吾土倦登樓。", "久存膠漆應難竝，一辱泥塗遂晚收。", "李杜齊名真忝竊，朔雲寒菊倍離憂。"]'),
('8b3aa647-68e8-4ab9-8a5c-eabf83671ad8','重送劉十弟判官','杜甫','唐','唐诗','tang','','[]','分源豕韋派，別浦雁賓秋。',72,'全唐诗/poet.tang.11000.json','["分源豕韋派，別浦雁賓秋。", "年事推兄忝，人才覺弟優。", "經過辨豐劒，意氣逐吳鉤。", "垂翅徒衰老，先鞭不滯留。", "本枝凌歲晚，高義豁窮愁。", "他日臨江待，長沙舊驛樓。"]'),
('03835a84-cf65-4775-8f22-fd98bf907b5e','奉贈盧五丈參謀','杜甫','唐','唐诗','tang','','[]','恭惟同自出，妙選異高標。',192,'全唐诗/poet.tang.11000.json','["恭惟同自出，妙選異高標。", "入幕知孫楚，披襟得鄭僑。", "丈人藉才地，門閥冠雲霄。", "老矣逢迎拙，相於契託饒。", "賜錢傾府待，爭米駐船遙。", "鄰好艱難薄，氓心杼軸焦。", "客星空伴使，寒水不成潮。", "素髮乾垂領，銀章破在腰。", "說詩能累夜，醉酒或連朝。", "藻翰惟牽率，湖山合動搖。", "時清非造次，興盡却蕭條。", "天子多恩澤，蒼生轉寂寥。", "休傳鹿是馬，莫信鵩如鴞。", "未解依依袂，還斟泛泛瓢。", "流年疲蟋蟀，體物幸鷦鷯。", "辜負滄州願，誰云晚見招。"]'),
('232e1f32-4d09-4689-b3ba-6d434f6aacf7','登舟將適漢陽','杜甫','唐','唐诗','tang','','[]','春宅棄汝去，秋帆催客歸。',72,'全唐诗/poet.tang.11000.json','["春宅棄汝去，秋帆催客歸。", "庭蔬尚在眼，浦浪已吹衣。", "生理飄蕩拙，有心遲暮歸。", "中原戎馬盛，遠道素書稀。", "塞雁與時集，檣烏終歲飛。", "鹿門自此往，永息漢陰機。"]'),
('2b424b44-0b51-483b-9936-1a92c6a23993','暮秋將歸秦留別湖南幕府親友','杜甫','唐','唐诗','tang','','[]','水闊蒼梧野，天高白帝秋。',48,'全唐诗/poet.tang.11000.json','["水闊蒼梧野，天高白帝秋。", "途窮那免哭，身老不禁愁。", "大府才能會，諸公德業優。", "北歸衝雨雪，誰憫敝貂裘。"]'),
('01524421-e3e5-49f3-a237-ae1c44d720b9','送盧十四弟侍御護韋尚書靈櫬歸上都二十韻','杜甫','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','素幕渡江遠，朱幡登陸微。',240,'全唐诗/poet.tang.11000.json','["素幕渡江遠，朱幡登陸微。", "悲鳴駟馬顧，失涕萬人揮。", "參佐哭辭畢，門闌誰送歸。", "從公伏事久，之子俊才稀。", "長路更執紼，此心猶倒衣。", "感恩義不小，懷舊禮無違。", "墓待龍驤詔，臺迎獬豸威。", "深衷見士則，雅論在兵機。", "戎狄乘妖氣，塵沙落禁闈。", "往年朝謁斷，他日埽除非。", "但促銅壺箭，休添玉帳旂。", "動詢黃閣老，肯慮白登圍。", "萬姓瘡痍合，羣凶嗜慾肥。", "刺規多諫諍，端拱自光輝。", "儉約前王體，風流後代希。", "對敭期特達，衰朽再芳菲。", "空裏愁書字，山中疾采薇。", "撥杯要忽罷，抱被宿何依。", "眼冷看征蓋，兒扶立釣磯。", "清霜洞庭葉，故就別時飛。"]'),
('135919ac-449e-4c24-b088-c71de153f199','哭李常侍嶧二首 一','杜甫','唐','唐诗','tang','','[]','一代風流盡，修文地下深。',48,'全唐诗/poet.tang.11000.json','["一代風流盡，修文地下深。", "斯人不重見，將老失知音。", "短日行梅嶺，寒山落桂林。", "長安若箇畔，猶想映貂金。"]'),
('f6f418e9-b030-4998-bd2f-d1f21ade4e5a','哭李常侍嶧二首 二','杜甫','唐','唐诗','tang','','[]','青瑣陪雙入，銅梁阻一辭。',48,'全唐诗/poet.tang.11000.json','["青瑣陪雙入，銅梁阻一辭。", "風塵逢我地，江漢哭君時。", "次第尋書札，呼兒檢贈詩。", "發揮王子表，不媿史臣詞。"]'),
('73d1a893-b647-4f14-a083-ae4b9a99edbb','哭韋大夫之晉','杜甫','唐','唐诗','tang','','[]','悽愴郇瑕色，差池弱冠年。',216,'全唐诗/poet.tang.11000.json','["悽愴郇瑕色，差池弱冠年。", "丈人叨禮數，文律早周旋。", "臺閣黃圖裏，簪裾紫蓋邊。", "尊榮真不忝，端雅獨翛然。", "貢喜音容間，馮招病疾纏。", "南過駭倉卒，北思悄聯緜。", "鵩鳥長沙諱，犀牛蜀郡憐。", "素車猶慟哭，寶劒欲高懸。", "漢道中興盛，韋經亞相傳。", "沖融標世業，磊落映時賢。", "城府深朱夏，江湖眇霽天。", "綺樓關樹頂，飛旐汎堂前。", "帟幕疑風燕，笳簫急暮蟬。", "興殘虛白室，跡斷孝廉船。", "童孺交遊盡，喧卑俗事牽。", "老來多涕淚，情在強詩篇。", "誰寄方隅理，朝難將帥權。", "春秋褒貶例，名器重雙全。"]'),
('15a3131f-aaa2-4557-9233-aeceb9edbb63','舟中夜雪有懷盧十四侍御弟','杜甫','唐','唐诗','tang','','[]','朔風吹桂水，朔雪夜紛紛。',48,'全唐诗/poet.tang.11000.json','["朔風吹桂水，朔雪夜紛紛。", "暗度南樓月，寒深北渚雲。", "燭斜初近見，舟重竟無聞。", "不識山陰道，聽雞更憶君。"]'),
('fe6b1d10-773b-41cc-ba18-6cf545884231','對雪','杜甫','唐','唐诗','tang','','[]','北雪犯長沙，胡雲冷萬家。',48,'全唐诗/poet.tang.11000.json','["北雪犯長沙，胡雲冷萬家。", "隨風且間葉，帶雨不成花。", "金錯囊從罄，銀壺酒易賒。", "無人竭浮蟻，有待至昏鴉。"]'),
('580369cf-1eb5-4463-8e49-579462e0cc2a','樓上','杜甫','唐','唐诗','tang','','[]','天地空搔首，頻抽白玉簪。',48,'全唐诗/poet.tang.11000.json','["天地空搔首，頻抽白玉簪。", "皇輿三極北，身事五湖南。", "戀闕勞肝肺，論材媿杞柟。", "亂離難自救，終是老湘潭。"]'),
('a13d98fa-8cde-4b47-8bb7-ffdafb0de067','冬晚送長孫漸舍人歸州','杜甫','唐','唐诗','tang','','[]','參卿休坐幄，蕩子不還鄉。',72,'全唐诗/poet.tang.11000.json','["參卿休坐幄，蕩子不還鄉。", "南客瀟湘外，西戎鄠杜旁。", "衰年傾蓋晚，費日繫舟長。", "會面思來札，銷魂逐去檣。", "雲晴鷗更舞，風逆雁無行。", "匣裏雌雄劒，吹毛任選將。"]'),
('159f0579-ff84-4cca-a001-9b5709cbf122','暮冬送蘇四郎徯兵曹適桂州','杜甫','唐','唐诗','tang','','[]','飄飄蘇季子，六印佩何遲。',72,'全唐诗/poet.tang.11000.json','["飄飄蘇季子，六印佩何遲。", "早作諸侯客，兼工古體詩。", "爾賢埋照久，余病長年悲。", "盧綰須征日，樓蘭要斬時。", "歲陽初盛動，王化久磷緇。", "爲人蒼梧廟，看雲哭九疑。"]'),
('a1a8cc9a-28f6-44d0-8195-d44de3bd0a8b','風疾舟中伏枕書懷三十六韻奉呈湖南親友','杜甫','唐','唐诗','tang','','["\u5fe7\u56fd\u5fe7\u6c11"]','軒轅休製律，虞舜罷彈琴。',288,'全唐诗/poet.tang.11000.json','["軒轅休製律，虞舜罷彈琴。", "尚錯雄鳴管，猶傷半死心。", "聖賢名古邈，羇旅病年侵。", "舟泊常依震，湖平早見參。", "如聞馬融笛，若倚仲宣襟。", "故國悲寒望，羣雲慘歲陰。", "水鄉霾白屋，楓岸疊青岑。", "鬱鬱冬炎瘴，濛濛雨滯淫。", "鼓迎非祭鬼，彈落似鴞禽。", "興盡纔無悶，愁來遽不禁。", "生涯相汩沒，時物自蕭森。", "疑惑尊中弩，淹留冠上簪。", "牽裾驚魏帝，投閣爲劉歆。", "狂走終奚適，微才謝所欽。", "吾安藜不糝，汝貴玉爲琛。", "烏几重重縛，鶉衣寸寸鍼。", "哀傷同庾信，述作異陳琳。", "十暑岷山葛，三霜楚戶砧。", "叨陪錦帳座，久放白頭吟。", "反樸時難遇，忘機陸易沈。", "應過數粒食，得近四知金。", "春草封歸恨，源花費獨尋。", "轉蓬憂悄悄，行藥病涔涔。", "瘞夭追潘岳，持危覓鄧林。"]'),
('b54ccce5-156f-4067-8408-a1d8a0d4c180','奉贈蕭二十使君','杜甫','唐','唐诗','tang','','[]','惜在嚴公幕，俱爲蜀使臣。',216,'全唐诗/poet.tang.11000.json','["惜在嚴公幕，俱爲蜀使臣。", "艱危參大府，前後間清塵。", "起草鳴先路，乘槎動要津。", "王鳧聊暫出，蕭雉只相馴。", "終始任安義，荒蕪孟母鄰。", "聯翩匍匐禮，意氣死生親。", "張老存家事，嵇康有故人。", "食恩慙鹵莽，鏤骨抱酸辛。", "巢許山林志，夔龍廊廟珍。", "鵬圖乃矯翼，熊軾且移輪。", "磊落衣冠地，蒼茫土木身。", "塤篪鳴自合，金石瑩逾新。", "重憶羅江外，同遊錦水濱。", "結歡隨過隙，懷舊益霑巾。", "曠絕含香舍，稽留伏枕辰。", "停驂雙闕早，迴雁五湖春。", "不達長卿病，從來原憲貧。", "監河受貸粟，一起轍中鱗。"]'),
('ee733580-5e11-44be-9e68-4b42a85d8f8e','奉送二十三舅錄事之攝郴州','杜甫','唐','唐诗','tang','','[]','賢良歸盛族，吾舅盡知名。',120,'全唐诗/poet.tang.11000.json','["賢良歸盛族，吾舅盡知名。", "徐庶高交友，劉牢出外甥。", "泥塗豈珠玉，環堵但柴荆。", "衰老悲人世，驅馳厭甲兵。", "氣春江上別，淚血渭陽情。", "舟鷁排風影，林烏反哺聲。", "永嘉多北至，句漏且南征。", "必見公侯復，終聞盜賊平。", "郴州頗涼冷，橘井尚淒清。", "從役何蠻貊，居官志在行。"]'),
('b45a58ee-882c-4e39-bebc-3792c8e2e5de','送魏二十四司直充嶺南掌選崔郎中判官兼寄韋韶州','杜甫','唐','唐诗','tang','','[]','選曹分五嶺，使者歷三湘。',72,'全唐诗/poet.tang.11000.json','["選曹分五嶺，使者歷三湘。", "才美膺推薦，君行佐紀綱。", "佳聲斯共遠，雅節在周防。", "明白山濤鑒，嫌疑陸賈裝。", "故人湖外少，春日嶺南長。", "憑報韶州牧，新詩昨寄將。"]'),
('1371127c-6ab6-4316-ba07-ef52b37e5b27','送趙十七明府之縣','杜甫','唐','唐诗','tang','','[]','連城爲寶重，茂宰得才新。',48,'全唐诗/poet.tang.11000.json','["連城爲寶重，茂宰得才新。", "山雉迎舟楫，江花報邑人。", "論交飜恨晚，臥病却愁春。", "惠愛南翁悅，餘波及老身。"]'),
('c9e8cd22-8ed0-407b-a20a-8c4650f1fa2e','燕子來舟中作','杜甫','唐','唐诗','tang','','["\u5b64\u72ec", "\u6292\u60c5", "\u5199\u9e1f", "\u9e1f"]','湖南爲客動經春，燕子銜泥兩度新。',64,'全唐诗/poet.tang.11000.json','["湖南爲客動經春，燕子銜泥兩度新。", "舊入故園常識主，如今社日遠看人。", "可憐處處巢君室，何異飄飄託此身。", "暫語船檣還起去，穿花落水益霑巾。"]'),
('edd75f98-26ab-4171-91bc-3aa9e979bae2','同豆盧峰知字韻','杜甫','唐','唐诗','tang','','[]','煉金歐冶子，噴玉大宛兒。',72,'全唐诗/poet.tang.11000.json','["煉金歐冶子，噴玉大宛兒。", "符彩高無敵，聰明達所爲。", "夢蘭他日應，折桂早年知。", "爛漫通經術，光芒刷羽儀。", "謝庭瞻不遠，潘省會於斯。", "倡和將雛曲，田翁號鹿皮。"]'),
('c3c45810-1845-4140-ac61-bb875c8a6488','歸雁二首 一','杜甫','唐','唐诗','tang','','[]','萬里衡陽雁，今年又北歸。',48,'全唐诗/poet.tang.11000.json','["萬里衡陽雁，今年又北歸。", "雙雙瞻客上，一一背人飛。", "雲裏相呼疾，沙邊自宿稀。", "繫書元浪語，愁寂故山薇。"]'),
('bba246a1-13b5-432c-a91b-d3b963150a9f','歸雁二首 二','杜甫','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','欲雪違胡地，先花別楚雲。',48,'全唐诗/poet.tang.11000.json','["欲雪違胡地，先花別楚雲。", "却過清渭影，高起洞庭羣。", "塞北春陰暮，江南日色曛。", "傷弓流落羽，行斷不堪聞。"]'),
('b6be3e45-97f6-4b6e-a61a-860fb324b6a1','小寒食舟中作','杜甫','唐','唐诗','tang','','["\u5fe7\u56fd\u5fe7\u6c11", "\u5bd2\u98df\u8282", "\u5199\u666f"]','佳辰強飯食猶寒，隱几蕭條帶鶡冠。',64,'全唐诗/poet.tang.11000.json','["佳辰強飯食猶寒，隱几蕭條帶鶡冠。", "春水船如天上坐，老年花似霧中看。", "娟娟戲蝶過閑幔，片片輕鷗下急湍。", "雲白山清萬餘里，愁看直北是長安。"]'),
('f69f9c09-d812-4d6a-9650-bbbbcad29caa','清明二首 一','杜甫','唐','唐诗','tang','','[]','朝來新火起新煙，湖色春光淨客船。',96,'全唐诗/poet.tang.11000.json','["朝來新火起新煙，湖色春光淨客船。", "繡羽銜花他自得，紅顏騎竹我無緣。", "胡童結束還難有，楚女腰肢亦可憐。", "不見定王城舊處，長懷賈傅井依然。", "虛霑焦舉爲寒食，實藉嚴君賣卜錢。", "鐘鼎山林各天性，濁醪粗飯任吾年。"]'),
('00a2e26b-5799-453b-bdc1-16b870e092be','清明二首 二','杜甫','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','此身飄泊苦西東，右臂偏枯半耳聾。',96,'全唐诗/poet.tang.11000.json','["此身飄泊苦西東，右臂偏枯半耳聾。", "寂寂繫舟雙下淚，悠悠伏枕左書空。", "十年蹴鞠將雛遠，萬里鞦韆習俗同。", "旅雁上雲歸紫塞，家人鑽火用青楓。", "秦城樓閣煙花裏，漢主山河錦繡中。", "風水春來洞庭闊，白蘋愁殺白頭翁。"]'),
('1a3ceb31-3ce5-4708-850f-842ed8edd31d','發潭州','杜甫','唐','唐诗','tang','','[]','夜醉長沙酒，曉行湘水春。',48,'全唐诗/poet.tang.11000.json','["夜醉長沙酒，曉行湘水春。", "岸花飛送客，檣燕語留人。", "賈傅才未有，褚公書絕倫。", "高名前後事，回首一傷神。"]'),
('0ba35e31-8786-4ebb-889d-f33293bbaf67','迴櫂','杜甫','唐','唐诗','tang','','[]','宿昔試安命，自私猶畏天。',168,'全唐诗/poet.tang.11000.json','["宿昔試安命，自私猶畏天。", "勞生繫一物，爲客費多年。", "衡岳江湖大，蒸池疫癘偏。", "散才嬰薄俗，有跡負前賢。", "巾拂那關眼，缾罍易滿船。", "火雲滋垢膩，凍雨裛沈緜。", "強飯蓴添滑，端居茗續煎。", "清思漢水上，涼憶峴山巔。", "順浪飜堪倚，迴帆又省牽。", "吾家碑不昧，王氏井依然。", "几杖將衰齒，茅茨寄短椽。", "灌園曾取適，遊寺可終焉。", "遂性同漁父，成名異魯連。", "篙師煩爾送，朱夏及寒泉。"]'),
('896165e9-c6f3-47f5-ad08-591f4c291630','贈韋七贊善','杜甫','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','鄉里衣冠不乏賢，杜陵韋曲未央前。',64,'全唐诗/poet.tang.11000.json','["鄉里衣冠不乏賢，杜陵韋曲未央前。", "爾家最近魁三象，時論同歸尺五天。", "北走關山開雨雪，南遊花柳塞雲煙。", "洞庭春色悲公子，鰕菜忘歸范蠡船。"]'),
('ce32eb67-b007-4a04-a668-49445c5b2fd3','奉酬寇十侍御錫見寄四韻復寄寇','杜甫','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','往別郇瑕地，於今四十年。',48,'全唐诗/poet.tang.11000.json','["往別郇瑕地，於今四十年。", "來簪御府筆，故泊洞庭船。", "詩憶傷心處，春深把臂前。", "南瞻按百越，黃帽待君偏。"]'),
('f5a23a71-eaa5-4494-9c16-f3fd44546508','酬郭十五受判官','杜甫','唐','唐诗','tang','','[]','才微歲老尚虛名，臥病江湖春復生。',64,'全唐诗/poet.tang.11000.json','["才微歲老尚虛名，臥病江湖春復生。", "藥裹關心詩總廢，花枝照眼句還成。", "只同燕石能星隕，自得隋珠覺夜明。", "喬口橘洲風浪促，繫帆何惜片時程。"]'),
('5f52da7a-9e85-4077-8b9f-88f1abdaf274','衡州送李大夫七丈勉赴廣州','杜甫','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','斧鉞下青冥，樓船過洞庭。',48,'全唐诗/poet.tang.11000.json','["斧鉞下青冥，樓船過洞庭。", "北風隨爽氣，南斗避文星。", "日月籠中鳥，乾坤水上萍。", "王孫丈人行，垂老見飄零。"]'),
('b73268d2-ab46-4887-9379-915c053146fc','哭長孫侍御','杜甫','唐','唐诗','tang','','[]','道爲謀書重，名因賦頌雄。',48,'全唐诗/poet.tang.11000.json','["道爲謀書重，名因賦頌雄。", "禮闈曾擢桂，憲府舊乘驄。", "流水生涯盡，浮雲世事空。", "唯餘舊臺柏，蕭瑟九原中。"]'),
('15180235-db35-499b-8fd5-b8d9fa92f5f2','虢國夫人','杜甫','唐','唐诗','tang','','["\u5199\u4eba", "\u4e03\u8a00\u7edd\u53e5", "\u5510\u8bd7\u4e09\u767e\u9996", "\u8bbd\u523a"]','虢國夫人承主恩，平明上馬入宮門。',32,'全唐诗/poet.tang.11000.json','["虢國夫人承主恩，平明上馬入宮門。", "却嫌脂粉涴顏色，澹埽蛾眉朝至尊。"]'),
('fa4a274a-df2c-4bab-b123-7d210259b37c','軍中醉飲寄沈八劉叟','杜甫','唐','唐诗','tang','','[]','酒渴愛江清，餘甘漱晚汀。',48,'全唐诗/poet.tang.11000.json','["酒渴愛江清，餘甘漱晚汀。", "輭沙欹坐穩，冷石醉眠醒。", "野膳隨行帳，華音發從伶。", "數杯君不見，醉已遣沈冥。"]'),
('f5a8d640-d4a1-4c79-ae07-b67a36e5761c','杜鵑行','杜甫','唐','唐诗','tang','','[]','古時杜宇稱望帝，魂作杜鵑何微細。',168,'全唐诗/poet.tang.11000.json','["古時杜宇稱望帝，魂作杜鵑何微細。", "跳枝竄葉樹木中，搶佯瞥捩雌隨雄。", "毛衣慘黑貌顦顇，衆鳥安肯相尊崇。", "隳形不敢棲華屋，短翮唯願巢深叢。", "穿皮啄朽觜欲禿，苦飢始得食一蟲。", "誰言養雛不自哺，此語亦足爲愚蒙。", "聲音咽咽如有謂，號啼略與嬰兒同。", "口乾垂血轉迫促，似欲上訴於蒼穹。", "蜀人聞之皆起立，至今斅學傳遺風。", "迺知變化不可窮，豈知昔日居深宮，嬪嬙左右如花紅。"]'),
('1d096967-8741-47e1-99f9-41e41c03f829','聞惠二過東溪特一送','杜甫','唐','唐诗','tang','','[]','惠子白駒瘦，歸溪唯病身。',48,'全唐诗/poet.tang.11000.json','["惠子白駒瘦，歸溪唯病身。", "皇天無老眼，空谷滯斯人。", "崖蜜松花熟，山杯竹葉新。", "柴門了無事，黃綺未稱臣。"]'),
('643603e3-ff0c-43b7-942b-e2348da428ab','舟泛洞庭','杜甫','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','蛟室圍青草，龍堆擁白沙。',48,'全唐诗/poet.tang.11000.json','["蛟室圍青草，龍堆擁白沙。", "護江盤古木，迎櫂舞神鵶。", "破浪南風正，收颿畏日斜。", "雲山千萬疊，底處上仙槎。"]'),
('8f666ee1-3c05-4695-9cfd-8b4d02d4c418','李鹽鐵二首','杜甫','唐','唐诗','tang','','[]','落葉春風起，高城煙霧開。',48,'全唐诗/poet.tang.11000.json','["落葉春風起，高城煙霧開。", "雜花分戶映，嬌燕入檐回。", "一見能傾產，虛懷只愛才。", "鹽官雖絆驥，名是漢庭來。"]'),
('da4aba0f-2770-4a59-9050-7e2688d8f1fa','長吟','杜甫','唐','唐诗','tang','','[]','江渚飜鷗戲，官橋帶柳陰。',48,'全唐诗/poet.tang.11000.json','["江渚飜鷗戲，官橋帶柳陰。", "江飛兢渡日，草見蹋春心。", "已撥形骸累，真爲爛漫深。", "賦詩歌句穩，不免自長吟。"]'),
('9ffa5316-14cd-4eb2-b4ea-075621799298','絕句九首 七','杜甫','唐','唐诗','tang','','[]','聞道巴山裏，春船正好行。',24,'全唐诗/poet.tang.11000.json','["聞道巴山裏，春船正好行。", "都將百年興，一望九江城。"]'),
('9113337c-c93a-497c-ac46-39ad99d6b908','絕句九首 八','杜甫','唐','唐诗','tang','','[]','水檻溫江口，茅堂石筍西。',24,'全唐诗/poet.tang.11000.json','["水檻溫江口，茅堂石筍西。", "移船先主廟，洗藥淙沙溪。"]'),
('09c772f5-e6c7-4b3c-9902-1a0af8e8255c','絕句九首 九','杜甫','唐','唐诗','tang','','[]','設道春來好，狂風大放顛。',24,'全唐诗/poet.tang.11000.json','["設道春來好，狂風大放顛。", "吹花隨水去，飜却釣魚船。"]'),
('ab1fc7f2-defc-46cc-b791-647abb1f381c','瞿唐懷古','杜甫','唐','唐诗','tang','','[]','西南萬壑注，勍敵兩崖[開]。',50,'全唐诗/poet.tang.11000.json','["西南萬壑注，勍敵兩崖[開]。", "地與山根裂，江從月窟來。", "削成當白帝，空曲隱陽臺。", "疏鑿功雖美，陶鈞力大哉。"]'),
('aeeb99c7-6fe4-4535-af24-9581d92aa264','送司馬入京','杜甫','唐','唐诗','tang','','[]','羣盜至今日，先朝忝從臣。',48,'全唐诗/poet.tang.11000.json','["羣盜至今日，先朝忝從臣。", "歎君能戀主，久客羨歸秦。", "黃閣長司諫，丹墀有故人。", "向來論社稷，爲話涕霑巾。"]'),
('184965e8-dd83-4699-afb1-eac6f8211dab','惜別行送劉僕射判官','杜甫','唐','唐诗','tang','','[]','聞道南行市駿馬，不限匹數軍中須。',257,'全唐诗/poet.tang.11000.json','["聞道南行市駿馬，不限匹數軍中須。", "襄陽幕府天下異，主將儉省憂艱虞。", "祗收壯健勝鐵甲，豈因格鬬求龍駒。", "而今西北自反胡，騏驎蕩盡一匹無。", "龍媒真種在帝都，子孫永落西南隅。", "向非戎事備征伐，君肯辛苦越江湖。", "江湖凡馬多顦顇，衣冠往往乘蹇驢。", "梁公富貴於身疎，號令明白人安居。", "俸錢時散士子盡，府庫不爲驕豪虛。", "以茲報主寸心赤，氣却西戎迴北狄。", "羅網羣馬籍馬多，氣在驅馳出金帛。", "劉侯奉使光推擇，滔滔才略滄溟窄。", "杜陵老翁秋繫船，扶病相識長沙驛。", "強梳白髮提胡盧，手把菊花路旁摘。", "九州兵革浩茫茫，三歎聚散臨重陽。", "當杯對客忍流涕，君不覺老夫神內傷。"]'),
('d5aac1dd-2ab0-4f0e-a47b-279c683b6c52','呀鶻行','杜甫','唐','唐诗','tang','','[]','病鶻孤飛俗眼醜，每夜江邊宿衰柳。',96,'全唐诗/poet.tang.11000.json','["病鶻孤飛俗眼醜，每夜江邊宿衰柳。", "清秋落日已側身，過雁歸鵶錯回首。", "緊腦雄姿迷所向，疎翮稀毛不可狀。", "強神迷復皁雕前，俊才早在蒼鷹上。", "風濤颯颯寒山陰，熊羆欲蟄龍蛇深。", "念爾此時有一擲，失聲濺血非其心。"]'),
('21009cf8-00ea-4825-a9a4-87bccedba515','狂歌行贈四兄','杜甫','唐','唐诗','tang','','[]','與兄行年校一歲，賢者是兄愚者弟。',176,'全唐诗/poet.tang.11000.json','["與兄行年校一歲，賢者是兄愚者弟。", "兄將富貴等浮雲，弟切功名好權勢。", "長安秋雨十日泥，我曹鞴馬聽晨雞。", "公卿朱門未開鎖，我曹已到肩相齊。", "吾兄睡穩方舒膝，不襪不巾蹋曉日。", "男啼女哭莫我知，身上須繒腹中實。", "今年思我來嘉州，嘉州酒重花繞樓。", "樓頭喫酒樓下臥，長歌短詠還相酬。", "四時八節還拘禮，女拜弟妻男拜弟。", "幅巾鞶帶不挂身，頭脂足垢何曾洗。", "吾兄吾兄巢許倫，一生喜怒長任真。"]'),
('e39196f1-babc-4cb4-9bad-92f4006f6d36','逃難','杜甫','唐','唐诗','tang','','[]','五十頭白翁，南北逃世難。',84,'全唐诗/poet.tang.11000.json','["五十頭白翁，南北逃世難。", "疎布纏枯骨，奔走苦不暖。", "已衰病方入，四海一塗炭。", "乾坤萬里內，莫見容身畔。", "妻孥復隨我，回首共悲歡。", "故國莽丘墟，鄰里各分散。", "歸路從此迷，涕盡湘江岸。"]'),
('936e5e7b-7a5d-4e5c-b021-cd3079c05b6a','寄高適','杜甫','唐','唐诗','tang','','[]','楚隔乾坤遠，難招病客魂。',48,'全唐诗/poet.tang.11000.json','["楚隔乾坤遠，難招病客魂。", "詩名惟我共，世事與誰論。", "北闕更新主，南星落故園。", "定知相見日，爛漫倒芳尊。"]'),
('5f2de4bc-ee96-4ec0-bed4-16541c2dd2c0','送靈州李判官','杜甫','唐','唐诗','tang','','[]','犬戎腥四海，回首一茫茫。',48,'全唐诗/poet.tang.11000.json','["犬戎腥四海，回首一茫茫。", "血戰乾坤赤，氛迷日月黃。", "將軍專策略，幕府盛材良。", "近賀中興主，神兵動朔方。"]'),
('ee3a2178-4382-4532-9f74-3c8fc5a8e629','與嚴二郎奉禮別','杜甫','唐','唐诗','tang','','[]','別君誰暖眼，將老病纏身。',72,'全唐诗/poet.tang.11000.json','["別君誰暖眼，將老病纏身。", "出涕同斜日，臨風看去塵。", "商歌還入夜，巴俗自爲鄰。", "尚媿微軀在，遙聞盛禮新。", "山東羣盜散，闕下受降頻。", "諸將歸應盡，題書報旅人。"]'),
('a318610a-56a2-4c5c-a4f3-337085962bd4','巴西驛亭觀江漲呈竇使君二首 一','杜甫','唐','唐诗','tang','','[]','轉驚波作怒，即恐岸隨流。',48,'全唐诗/poet.tang.11000.json','["轉驚波作怒，即恐岸隨流。", "賴有杯中物，還同海上鷗。", "關心小剡縣，傍眼見揚州。", "爲接情人飲，朝來減半愁。"]'),
('4d955a6e-82ab-4336-848e-80d4d0c52227','巴西驛亭觀江漲呈竇使君二首 二','杜甫','唐','唐诗','tang','','[]','向晚波微綠，連空岸脚青。',48,'全唐诗/poet.tang.11000.json','["向晚波微綠，連空岸脚青。", "日兼春有暮，愁與醉無醒。", "漂泊猶杯酒，躊躇此驛亭。", "相看萬里外，同是一浮萍。"]'),
('9d6fc326-de20-4ee9-a355-a79c523d55d1','遣憂','杜甫','唐','唐诗','tang','','[]','亂離知又甚，消息苦難真。',48,'全唐诗/poet.tang.11000.json','["亂離知又甚，消息苦難真。", "受諫無今日，臨危憶古人。", "紛紛乘白馬，攘攘著黃巾。", "隋氏留宮室，焚燒何太頻。"]'),
('388bec3c-e7e4-44f2-99f2-f8dfe5a2daba','早花','杜甫','唐','唐诗','tang','','[]','西京安穩未，不見一人來。',48,'全唐诗/poet.tang.11000.json','["西京安穩未，不見一人來。", "臘日巴江曲，山花已自開。", "盈盈當雪杏，豔豔待春梅。", "直苦風塵暗，誰憂容鬢催。"]'),
('0b969e7b-3472-43b2-a137-dbe434043411','巴山','杜甫','唐','唐诗','tang','','[]','巴山遇中使，云自峽城來。',36,'全唐诗/poet.tang.11000.json','["巴山遇中使，云自峽城來。", "盜賊還奔突，乘輿恐未回。", "天寒邵伯樹，地闊望仙臺。"]'),
('68b787e3-af74-4a3b-961b-7b01295dc800','收京','杜甫','唐','唐诗','tang','','[]','復道收京邑，兼聞殺犬戎。',48,'全唐诗/poet.tang.11000.json','["復道收京邑，兼聞殺犬戎。", "衣冠却扈從，車架已還宮。", "克復成如此，安危在數公。", "莫令回首地，慟哭起悲風。"]');
